struct MeaningfulTokenLinks {
    prev: Vec<Option<usize>>,
    next: Vec<Option<usize>>,
}

#[derive(Clone)]
struct FormatResultCacheEntry {
    preferred_db_type: Option<DatabaseType>,
    append_missing_terminator: bool,
    input: String,
    output: String,
}

const FORMAT_RESULT_CACHE_CAPACITY: usize = 8;
static FORMAT_RESULT_CACHE: OnceLock<Mutex<VecDeque<FormatResultCacheEntry>>> = OnceLock::new();

impl MeaningfulTokenLinks {
    fn build(tokens: &[SqlToken]) -> Self {
        let mut prev = vec![None; tokens.len()];
        let mut next = vec![None; tokens.len()];

        let mut previous_meaningful = None;
        for (idx, token) in tokens.iter().enumerate() {
            prev[idx] = previous_meaningful;
            if !matches!(token, SqlToken::Comment(_)) {
                previous_meaningful = Some(idx);
            }
        }

        let mut next_meaningful = None;
        for (idx, token) in tokens.iter().enumerate().rev() {
            next[idx] = next_meaningful;
            if !matches!(token, SqlToken::Comment(_)) {
                next_meaningful = Some(idx);
            }
        }

        Self { prev, next }
    }

    fn prev_index(&self, idx: usize) -> Option<usize> {
        self.prev.get(idx).copied().flatten()
    }

    fn next_index(&self, idx: usize) -> Option<usize> {
        self.next.get(idx).copied().flatten()
    }
}

fn format_result_cache() -> &'static Mutex<VecDeque<FormatResultCacheEntry>> {
    FORMAT_RESULT_CACHE
        .get_or_init(|| Mutex::new(VecDeque::with_capacity(FORMAT_RESULT_CACHE_CAPACITY)))
}

fn format_result_cache_guard() -> MutexGuard<'static, VecDeque<FormatResultCacheEntry>> {
    match format_result_cache().lock() {
        Ok(guard) => guard,
        Err(poisoned) => poisoned.into_inner(),
    }
}

struct StatementWordLinks {
    prev_word_in_statement: Vec<Option<usize>>,
}

impl StatementWordLinks {
    fn build(tokens: &[SqlToken]) -> Self {
        let mut prev_word_in_statement = vec![None; tokens.len()];
        let mut previous_word_idx = None;

        for (idx, token) in tokens.iter().enumerate() {
            prev_word_in_statement[idx] = previous_word_idx;
            match token {
                SqlToken::Symbol(symbol) if symbol == ";" => {
                    previous_word_idx = None;
                }
                SqlToken::Word(_) => {
                    previous_word_idx = Some(idx);
                }
                _ => {}
            }
        }

        Self {
            prev_word_in_statement,
        }
    }

    fn prev_word_index(&self, idx: usize) -> Option<usize> {
        self.prev_word_in_statement.get(idx).copied().flatten()
    }
}

fn current_rendered_line(out: &str) -> &str {
    out.rsplit('\n').next().unwrap_or(out)
}

fn active_query_owner_line(out: &str, opener_starts_new_line: bool) -> &str {
    if !opener_starts_new_line {
        return current_rendered_line(out);
    }

    let trimmed = out.trim_end_matches('\n');
    trimmed.rsplit('\n').next().unwrap_or(trimmed)
}

fn rendered_line_indent(line: &str) -> usize {
    SqlEditorWidget::safe_indent_div(line.chars().take_while(|ch| *ch == ' ').count())
}

#[derive(Clone, Copy, Default)]
struct FormatBlockDepthFrame {
    owner_depth: usize,
    previous_indent_level: usize,
}

fn push_format_block(
    block_stack: &mut Vec<String>,
    block_indent_stack: &mut Vec<FormatBlockDepthFrame>,
    kind: &str,
    previous_indent_level: usize,
    owner_depth: usize,
) {
    block_stack.push(kind.to_string());
    block_indent_stack.push(FormatBlockDepthFrame {
        owner_depth,
        previous_indent_level,
    });
}

fn pop_format_block(
    block_stack: &mut Vec<String>,
    block_indent_stack: &mut Vec<FormatBlockDepthFrame>,
) -> Option<(String, FormatBlockDepthFrame)> {
    let kind = block_stack.pop()?;
    let depth_frame = block_indent_stack.pop().unwrap_or_default();
    Some((kind, depth_frame))
}

struct FormatterTokenCache {
    meaningful_links: MeaningfulTokenLinks,
    statement_word_links: StatementWordLinks,
    next_word_indices: Vec<Option<usize>>,
    second_next_word_indices: Vec<Option<usize>>,
    matching_paren_close_indices: Vec<Option<usize>>,
    open_paren_multiline_child_head_prefix_counts: Vec<usize>,
    upper_words: Vec<Option<String>>,
}

impl FormatterTokenCache {
    fn build(tokens: &[SqlToken]) -> Self {
        let meaningful_links = MeaningfulTokenLinks::build(tokens);
        let statement_word_links = StatementWordLinks::build(tokens);
        let mut next_word_indices = vec![None; tokens.len()];
        let mut second_next_word_indices = vec![None; tokens.len()];
        let matching_paren_close_indices = Self::build_matching_paren_close_indices(tokens);
        let mut upper_words = vec![None; tokens.len()];

        let mut next_word_idx = None;
        let mut second_next_word_idx = None;
        for (idx, token) in tokens.iter().enumerate().rev() {
            next_word_indices[idx] = next_word_idx;
            second_next_word_indices[idx] = second_next_word_idx;
            if let SqlToken::Word(word) = token {
                upper_words[idx] = Some(word.to_ascii_uppercase());
                second_next_word_idx = next_word_idx;
                next_word_idx = Some(idx);
            }
        }
        let open_paren_multiline_child_head_prefix_counts =
            Self::build_open_paren_multiline_child_head_prefix_counts(
                tokens,
                &meaningful_links,
                &statement_word_links,
            );

        Self {
            meaningful_links,
            statement_word_links,
            next_word_indices,
            second_next_word_indices,
            matching_paren_close_indices,
            open_paren_multiline_child_head_prefix_counts,
            upper_words,
        }
    }

    fn build_matching_paren_close_indices(tokens: &[SqlToken]) -> Vec<Option<usize>> {
        let mut closes = vec![None; tokens.len()];
        let mut open_stack: Vec<usize> = Vec::new();

        for (idx, token) in tokens.iter().enumerate() {
            match token {
                SqlToken::Symbol(symbol) if symbol == "(" => open_stack.push(idx),
                SqlToken::Symbol(symbol) if symbol == ")" => {
                    if let Some(open_idx) = open_stack.pop() {
                        closes[open_idx] = Some(idx);
                    }
                }
                _ => {}
            }
        }

        closes
    }

    fn build_open_paren_multiline_child_head_prefix_counts(
        tokens: &[SqlToken],
        meaningful_links: &MeaningfulTokenLinks,
        statement_word_links: &StatementWordLinks,
    ) -> Vec<usize> {
        let mut prefix_counts = vec![0usize; tokens.len().saturating_add(1)];

        for idx in 0..tokens.len() {
            let previous = prefix_counts[idx];
            let Some(slot) = prefix_counts.get_mut(idx.saturating_add(1)) else {
                continue;
            };
            *slot = previous;

            if !matches!(tokens.get(idx), Some(SqlToken::Symbol(sym)) if sym == "(") {
                continue;
            }

            let next_non_comment = meaningful_links
                .next_index(idx)
                .and_then(|token_idx| tokens.get(token_idx));
            let opens_query_like_child = matches!(
                next_non_comment,
                Some(SqlToken::Word(word)) if crate::sql_text::is_subquery_head_keyword(word)
            );
            let opens_wrapped_layout_child = SqlEditorWidget::paren_starts_wrapped_layout_head(
                tokens,
                idx,
                Some(meaningful_links),
            );
            let opens_owner_relative_child = SqlEditorWidget::paren_multiline_clause_owner_kind(
                tokens,
                idx,
                Some(statement_word_links),
            )
            .is_some();
            let opens_column_list_child = statement_word_links
                .prev_word_index(idx)
                .and_then(|token_idx| tokens.get(token_idx))
                .is_some_and(|token| {
                    matches!(token, SqlToken::Word(word) if word.eq_ignore_ascii_case("COLUMNS"))
                });

            if opens_query_like_child
                || opens_wrapped_layout_child
                || opens_owner_relative_child
                || opens_column_list_child
            {
                *slot = slot.saturating_add(1);
            }
        }

        prefix_counts
    }

    fn meaningful_links(&self) -> &MeaningfulTokenLinks {
        &self.meaningful_links
    }

    fn statement_word_links(&self) -> &StatementWordLinks {
        &self.statement_word_links
    }

    fn matching_paren_close_indices(&self) -> &[Option<usize>] {
        self.matching_paren_close_indices.as_slice()
    }

    fn open_paren_multiline_child_head_prefix_counts(&self) -> &[usize] {
        self.open_paren_multiline_child_head_prefix_counts
            .as_slice()
    }

    fn next_non_comment<'a>(&self, tokens: &'a [SqlToken], idx: usize) -> Option<&'a SqlToken> {
        self.meaningful_links
            .next_index(idx)
            .and_then(|next_idx| tokens.get(next_idx))
    }

    fn next_word<'a>(&self, tokens: &'a [SqlToken], idx: usize) -> Option<&'a str> {
        self.next_word_indices
            .get(idx)
            .copied()
            .flatten()
            .and_then(|word_idx| match tokens.get(word_idx) {
                Some(SqlToken::Word(word)) => Some(word.as_str()),
                _ => None,
            })
    }

    fn second_next_word<'a>(&self, tokens: &'a [SqlToken], idx: usize) -> Option<&'a str> {
        self.second_next_word_indices
            .get(idx)
            .copied()
            .flatten()
            .and_then(|word_idx| match tokens.get(word_idx) {
                Some(SqlToken::Word(word)) => Some(word.as_str()),
                _ => None,
            })
    }

    fn upper_word(&self, idx: usize) -> Option<&str> {
        self.upper_words.get(idx).and_then(|word| word.as_deref())
    }
}

struct CommentPrefixCache {
    prefix_text: String,
    prefix_len_before_token: Vec<usize>,
    previous_non_comment_token: Vec<Option<usize>>,
    second_previous_non_comment_token: Vec<Option<usize>>,
    has_string_token_before: Vec<bool>,
}

impl CommentPrefixCache {
    fn build(tokens: &[SqlToken]) -> Self {
        let mut prefix_text = String::new();
        let mut prefix_len_before_token = vec![0usize; tokens.len()];
        let mut previous_non_comment_token = vec![None; tokens.len()];
        let mut second_previous_non_comment_token = vec![None; tokens.len()];
        let mut has_string_token_before = vec![false; tokens.len()];
        let mut prev_non_comment = None;
        let mut prev_prev_non_comment = None;
        let mut saw_string_token = false;

        for (idx, token) in tokens.iter().enumerate() {
            prefix_len_before_token[idx] = prefix_text.len();
            previous_non_comment_token[idx] = prev_non_comment;
            second_previous_non_comment_token[idx] = prev_prev_non_comment;
            has_string_token_before[idx] = saw_string_token;

            if matches!(token, SqlToken::Comment(_)) {
                continue;
            }

            if !prefix_text.is_empty() {
                prefix_text.push(' ');
            }
            match token {
                SqlToken::Word(word) => prefix_text.push_str(word),
                SqlToken::String(literal) => {
                    prefix_text.push_str(literal);
                    saw_string_token = true;
                }
                SqlToken::Symbol(symbol) => prefix_text.push_str(symbol),
                SqlToken::Comment(_) => {}
            }
            prev_prev_non_comment = prev_non_comment;
            prev_non_comment = Some(idx);
        }

        Self {
            prefix_text,
            prefix_len_before_token,
            previous_non_comment_token,
            second_previous_non_comment_token,
            has_string_token_before,
        }
    }

    fn prefix_before(&self, idx: usize) -> &str {
        let prefix_len = self
            .prefix_len_before_token
            .get(idx)
            .copied()
            .unwrap_or(self.prefix_text.len());
        self.prefix_text.get(..prefix_len).unwrap_or("")
    }

    fn previous_non_comment_token_index(&self, idx: usize) -> Option<usize> {
        self.previous_non_comment_token.get(idx).copied().flatten()
    }

    fn second_previous_non_comment_token_index(&self, idx: usize) -> Option<usize> {
        self.second_previous_non_comment_token
            .get(idx)
            .copied()
            .flatten()
    }

    fn has_string_token_before(&self, idx: usize) -> bool {
        self.has_string_token_before
            .get(idx)
            .copied()
            .unwrap_or(false)
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum ParenFormatFrameKind {
    Compact,
    WrappedLayout,
    ColumnList,
    QueryLike,
}

impl ParenFormatFrameKind {
    fn is_query_like(self) -> bool {
        matches!(self, Self::QueryLike)
    }

    fn is_column_list(self) -> bool {
        matches!(self, Self::ColumnList)
    }

    fn opens_indented(self) -> bool {
        matches!(
            self,
            Self::WrappedLayout | Self::ColumnList | Self::QueryLike
        )
    }

    fn closes_indented(self) -> bool {
        matches!(
            self,
            Self::WrappedLayout | Self::ColumnList | Self::QueryLike
        )
    }

    fn counts_for_paren_extra(self) -> bool {
        !matches!(self, Self::ColumnList | Self::QueryLike)
    }

    fn suppresses_comma_breaks(self) -> bool {
        matches!(self, Self::Compact)
    }

    fn indent_level_delta(self) -> usize {
        if self.is_query_like() {
            2
        } else if self.opens_indented() {
            1
        } else {
            0
        }
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
struct ParenFormatFrame {
    kind: ParenFormatFrameKind,
    open_line_indent: usize,
    opened_at_line_start: bool,
    indent_level_delta: usize,
    close_indent_override: Option<usize>,
    body_indent: Option<usize>,
    pending_multiline_child_continuation: bool,
    post_multiline_child_tail_token_count: u8,
}

impl ParenFormatFrame {
    fn new(
        kind: ParenFormatFrameKind,
        open_line_indent: usize,
        opened_at_line_start: bool,
        indent_level_delta: usize,
        close_indent_override: Option<usize>,
    ) -> Self {
        Self {
            kind,
            open_line_indent,
            opened_at_line_start,
            indent_level_delta,
            close_indent_override,
            body_indent: None,
            pending_multiline_child_continuation: false,
            post_multiline_child_tail_token_count: 0,
        }
    }

    fn is_query_like(self) -> bool {
        self.kind.is_query_like()
    }

    fn is_column_list(self) -> bool {
        self.kind.is_column_list()
    }

    fn opens_indented(self) -> bool {
        self.kind.opens_indented()
    }

    fn closes_indented(self) -> bool {
        self.kind.closes_indented()
    }

    fn counts_for_paren_extra(self) -> bool {
        self.kind.counts_for_paren_extra()
    }

    fn suppresses_comma_breaks(self) -> bool {
        self.kind.suppresses_comma_breaks()
    }

    fn indent_level_delta(self) -> usize {
        self.indent_level_delta
    }

    fn close_indent(self) -> usize {
        if self.closes_indented() {
            self.close_indent_override.unwrap_or(self.open_line_indent)
        } else {
            0
        }
    }

    fn compact_multiline_close_indent(self) -> usize {
        self.open_line_indent
    }

    fn mark_multiline_child_closed(&mut self) {
        self.pending_multiline_child_continuation = true;
        self.post_multiline_child_tail_token_count = 0;
    }

    fn note_continuation_token(&mut self) {
        if self.pending_multiline_child_continuation {
            self.pending_multiline_child_continuation = false;
        }
        self.post_multiline_child_tail_token_count = self
            .post_multiline_child_tail_token_count
            .saturating_add(1)
            .min(2);
    }

    fn has_pending_multiline_child_continuation(self) -> bool {
        self.pending_multiline_child_continuation
    }

    fn sibling_body_indent(self) -> Option<usize> {
        (!self.is_query_like() && !self.is_column_list()).then_some(
            self.body_indent
                .unwrap_or_else(|| self.open_line_indent.saturating_add(1)),
        )
    }

    fn record_body_indent(&mut self, indent: usize) {
        if self.is_query_like() || self.is_column_list() || indent <= self.open_line_indent {
            return;
        }

        self.body_indent = Some(
            self.body_indent
                .map(|current| current.min(indent))
                .unwrap_or(indent),
        );
    }

    fn has_simple_multiline_child_tail(self) -> bool {
        self.post_multiline_child_tail_token_count == 1
    }

    fn contributes_multiline_close(self) -> bool {
        self.opens_indented()
            || self.pending_multiline_child_continuation
            || self.has_simple_multiline_child_tail()
    }
}

