#[derive(Clone, Copy)]
enum PendingSplitEndSuffixKind {
    SingleWord,
    TimingSuffix {
        consumed_timing_keyword: bool,
        consumed_each: bool,
    },
}

impl PendingSplitEndSuffixKind {
    fn from_first_suffix_word(word_upper: &str) -> Self {
        if matches!(word_upper, "BEFORE" | "AFTER") {
            Self::TimingSuffix {
                consumed_timing_keyword: false,
                consumed_each: false,
            }
        } else {
            Self::SingleWord
        }
    }

    fn advance(self, word_upper: &str) -> Option<Self> {
        match self {
            Self::SingleWord => None,
            Self::TimingSuffix {
                consumed_timing_keyword: false,
                consumed_each: false,
            } => {
                if matches!(word_upper, "BEFORE" | "AFTER") {
                    Some(Self::TimingSuffix {
                        consumed_timing_keyword: true,
                        consumed_each: false,
                    })
                } else {
                    None
                }
            }
            Self::TimingSuffix {
                consumed_timing_keyword: true,
                consumed_each: false,
            } => {
                if word_upper == "EACH" {
                    Some(Self::TimingSuffix {
                        consumed_timing_keyword: true,
                        consumed_each: true,
                    })
                } else {
                    None
                }
            }
            Self::TimingSuffix {
                consumed_timing_keyword: true,
                consumed_each: true,
            } => None,
            Self::TimingSuffix {
                consumed_timing_keyword: false,
                consumed_each: true,
            } => None,
        }
    }
}

#[derive(Clone, Copy, Default, PartialEq, Eq)]
struct FormatScope {
    paren_depth: usize,
    block_depth: usize,
}

impl FormatScope {
    fn new(paren_depth: usize, block_depth: usize) -> Self {
        Self {
            paren_depth,
            block_depth,
        }
    }

    fn contains(self, other: Self) -> bool {
        self.paren_depth <= other.paren_depth && self.block_depth <= other.block_depth
    }
}

#[derive(Default)]
struct ScopedFlag {
    scopes: Vec<FormatScope>,
}

impl ScopedFlag {
    fn activate(&mut self, scope: FormatScope) {
        if self
            .scopes
            .last()
            .is_some_and(|active_scope| *active_scope == scope)
        {
            return;
        }
        self.scopes.push(scope);
    }

    fn deactivate(&mut self) {
        let _ = self.scopes.pop();
    }

    fn deactivate_at_or_above_paren_depth(&mut self, paren_depth: usize) {
        while self
            .scopes
            .last()
            .is_some_and(|scope| scope.paren_depth >= paren_depth)
        {
            self.scopes.pop();
        }
    }

    fn clear(&mut self) {
        self.scopes.clear();
    }

    fn is_active(&self) -> bool {
        !self.scopes.is_empty()
    }

    fn is_active_at_paren_depth(&self, paren_depth: usize) -> bool {
        self.scopes
            .last()
            .is_some_and(|scope| scope.paren_depth == paren_depth)
    }

    fn sync_scope(&mut self, current_scope: FormatScope) {
        while self
            .scopes
            .last()
            .is_some_and(|scope| !scope.contains(current_scope))
        {
            self.scopes.pop();
        }
    }
}

struct ScopedValueFrame<T> {
    scope: FormatScope,
    value: T,
}

#[derive(Default)]
struct ScopedValue<T> {
    frames: Vec<ScopedValueFrame<T>>,
}

impl<T> ScopedValue<T> {
    fn replace(&mut self, scope: FormatScope, value: T) {
        if let Some(frame) = self.frames.last_mut() {
            if frame.scope == scope {
                frame.value = value;
                return;
            }
        }

        self.frames.push(ScopedValueFrame { scope, value });
    }

    fn clear(&mut self) {
        self.frames.clear();
    }

    fn is_some(&self) -> bool {
        !self.frames.is_empty()
    }

    fn sync_scope(&mut self, current_scope: FormatScope) {
        while self
            .frames
            .last()
            .is_some_and(|frame| !frame.scope.contains(current_scope))
        {
            self.frames.pop();
        }
    }
}

impl ScopedValue<String> {
    fn as_deref(&self) -> Option<&str> {
        self.frames.last().map(|frame| frame.value.as_str())
    }
}

// For huge buffers, avoid an additional full/prefix reformat pass when remapping cursor position.
const CURSOR_MAPPING_FULL_REFORMAT_THRESHOLD_BYTES: usize = 2 * 1024 * 1024;

/// SQL 구문별 포맷팅 상태를 캡슐화한 구조체.
/// 각 SQL 구문(CREATE, MERGE, GRANT 등)이 활성 상태인지 추적하며,
/// 절(clause) 키워드의 줄바꿈 억제 여부를 한 곳에서 판단합니다.
#[derive(Default)]
struct ConstructState {
    create_pending: ScopedFlag,
    create_object: ScopedValue<String>,
    routine_decl_pending: ScopedFlag,
    create_table_paren_expected: ScopedFlag,
    create_index_pending: ScopedFlag,
    create_sequence_active: ScopedFlag,
    create_synonym_active: ScopedFlag,
    grant_revoke_active: ScopedFlag,
    comment_on_active: ScopedFlag,
    model_active: ScopedFlag,
    model_reference_pending: ScopedFlag,
    merge_active: ScopedFlag,
    merge_when_branch_active: ScopedFlag,
    returning_active: ScopedFlag,
    search_cycle_clause_active: ScopedFlag,
    match_recognize_paren_depths: Vec<usize>,
    analytic_over_paren_depths: Vec<usize>,
    window_clause_paren_depths: Vec<usize>,
    keep_paren_depths: Vec<usize>,
    fetch_active: ScopedFlag,
    bulk_collect_active: ScopedFlag,
    insert_all_active: ScopedFlag,
    referential_action_pending: ScopedFlag,
    referential_on_active: ScopedFlag,
    execute_immediate_active: ScopedFlag,
    cursor_decl_pending: ScopedFlag,
    cursor_sql_active: ScopedFlag,
    forall_pending: ScopedFlag,
    forall_body_active: ScopedFlag,
}

impl ConstructState {
    fn sync_scope(&mut self, current_scope: FormatScope) {
        self.create_pending.sync_scope(current_scope);
        self.create_object.sync_scope(current_scope);
        self.routine_decl_pending.sync_scope(current_scope);
        self.create_table_paren_expected.sync_scope(current_scope);
        self.create_index_pending.sync_scope(current_scope);
        self.create_sequence_active.sync_scope(current_scope);
        self.create_synonym_active.sync_scope(current_scope);
        self.grant_revoke_active.sync_scope(current_scope);
        self.comment_on_active.sync_scope(current_scope);
        self.model_active.sync_scope(current_scope);
        self.model_reference_pending.sync_scope(current_scope);
        self.merge_active.sync_scope(current_scope);
        self.merge_when_branch_active.sync_scope(current_scope);
        self.returning_active.sync_scope(current_scope);
        self.search_cycle_clause_active.sync_scope(current_scope);
        self.fetch_active.sync_scope(current_scope);
        self.bulk_collect_active.sync_scope(current_scope);
        self.insert_all_active.sync_scope(current_scope);
        self.referential_action_pending.sync_scope(current_scope);
        self.referential_on_active.sync_scope(current_scope);
        self.execute_immediate_active.sync_scope(current_scope);
        self.cursor_decl_pending.sync_scope(current_scope);
        self.cursor_sql_active.sync_scope(current_scope);
        self.forall_pending.sync_scope(current_scope);
        self.forall_body_active.sync_scope(current_scope);
    }

    fn in_match_recognize_paren(&self, paren_depth: usize) -> bool {
        self.match_recognize_paren_depths
            .last()
            .is_some_and(|depth| paren_depth >= *depth)
    }

    fn in_analytic_over_paren(&self, paren_depth: usize) -> bool {
        self.analytic_over_paren_depths
            .last()
            .is_some_and(|depth| paren_depth >= *depth)
    }

    fn in_window_paren(&self, paren_depth: usize) -> bool {
        self.window_clause_paren_depths
            .last()
            .is_some_and(|depth| paren_depth >= *depth)
    }

    fn in_keep_paren(&self, paren_depth: usize) -> bool {
        self.keep_paren_depths
            .last()
            .is_some_and(|depth| paren_depth >= *depth)
    }

    fn pop_closed_paren_scopes(&mut self, paren_depth: usize) {
        while self
            .match_recognize_paren_depths
            .last()
            .is_some_and(|depth| paren_depth < *depth)
        {
            self.match_recognize_paren_depths.pop();
        }

        while self
            .analytic_over_paren_depths
            .last()
            .is_some_and(|depth| paren_depth < *depth)
        {
            self.analytic_over_paren_depths.pop();
        }

        while self
            .window_clause_paren_depths
            .last()
            .is_some_and(|depth| paren_depth < *depth)
        {
            self.window_clause_paren_depths.pop();
        }

        while self
            .keep_paren_depths
            .last()
            .is_some_and(|depth| paren_depth < *depth)
        {
            self.keep_paren_depths.pop();
        }
    }

    /// clause 키워드(SELECT, FROM, WHERE 등)의 줄바꿈을 억제해야 하는지 판단합니다.
    /// 새 SQL 구문을 추가할 때는 이 메서드에만 규칙을 추가하면 됩니다.
    fn suppresses_clause_break(
        &self,
        tokens: &[SqlToken],
        idx: usize,
        keyword: &str,
        prev_word_upper: Option<&str>,
        in_plsql_block: bool,
        suppress_comma_break_depth: usize,
        has_subquery_in_paren_stack: bool,
        inside_function_local_non_query_paren: bool,
        current_scope: FormatScope,
        trigger_header_state: &TriggerHeaderState,
        is_analytic_within_group: bool,
        is_fetch_into_single_target: bool,
        in_analytic_over_paren: bool,
        in_keep_paren: bool,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        // Inside analytic OVER(): clause keywords are handled by the
        // analytic_over_paren_depths branch instead.
        if in_analytic_over_paren {
            return true;
        }
        if in_keep_paren && keyword == "ORDER" {
            return true;
        }
        if SqlEditorWidget::is_inline_clause_phrase(
            tokens,
            idx,
            keyword,
            prev_word_upper,
            current_scope,
            self,
            statement_word_links,
        ) {
            return true;
        }
        // INSERT INTO stays on same line
        if keyword == "INTO" && matches!(prev_word_upper, Some("INSERT")) {
            return true;
        }
        // MERGE INTO stays on same line
        if keyword == "INTO" && matches!(prev_word_upper, Some("MERGE")) {
            return true;
        }
        // DELETE FROM stays on same line
        if keyword == "FROM" && matches!(prev_word_upper, Some("DELETE")) {
            return true;
        }
        // START WITH stays on same line
        if keyword == "WITH" && matches!(prev_word_upper, Some("START")) {
            return true;
        }
        // FETCH FIRST n ROW[S] WITH TIES stays on same line
        if keyword == "WITH" && matches!(prev_word_upper, Some("ROW" | "ROWS")) {
            return true;
        }
        // ORDER BY after SEQUENTIAL/AUTOMATIC suppressed
        if keyword == "ORDER"
            && (suppress_comma_break_depth > 0
                || matches!(prev_word_upper, Some("SEQUENTIAL" | "AUTOMATIC")))
        {
            return true;
        }
        // Trigger event keywords (INSERT/UPDATE/DELETE in trigger header)
        if trigger_header_state.is_active() && matches!(keyword, "INSERT" | "UPDATE" | "DELETE") {
            return true;
        }
        // FOR UPDATE (SQL, not PL/SQL)
        if keyword == "UPDATE" && matches!(prev_word_upper, Some("FOR")) && !in_plsql_block {
            return true;
        }
        // RETURNING INTO
        if self.returning_active.is_active() && keyword == "INTO" {
            return true;
        }
        // FETCH INTO (single target)
        if self.fetch_active.is_active() && keyword == "INTO" && is_fetch_into_single_target {
            return true;
        }
        // BULK COLLECT INTO
        if self.bulk_collect_active.is_active() && keyword == "INTO" {
            return true;
        }
        // GRANT/REVOKE privilege keywords
        if self.grant_revoke_active.is_active()
            && matches!(
                keyword,
                "SELECT"
                    | "INSERT"
                    | "UPDATE"
                    | "DELETE"
                    | "EXECUTE"
                    | "ALTER"
                    | "DROP"
                    | "CREATE"
                    | "INDEX"
                    | "REFERENCES"
                    | "ALL"
                    | "PRIVILEGES"
                    | "MERGE"
            )
        {
            return true;
        }
        // GRANT/REVOKE ON
        if self.grant_revoke_active.is_active() && keyword == "ON" {
            return true;
        }
        // CREATE SEQUENCE: suppress START/CONNECT
        if self.create_sequence_active.is_active() && matches!(keyword, "START" | "CONNECT") {
            return true;
        }
        // FETCH: suppress LIMIT/BULK
        if self.fetch_active.is_active() && matches!(keyword, "LIMIT" | "BULK") {
            return true;
        }
        // EXECUTE IMMEDIATE: suppress INTO/USING
        if self.execute_immediate_active.is_active() && matches!(keyword, "INTO" | "USING") {
            return true;
        }
        // MERGE WHEN ... THEN UPDATE/INSERT: suppress SET/VALUES/INTO
        if self.merge_when_branch_active.is_active() && matches!(keyword, "SET" | "VALUES" | "INTO")
        {
            return true;
        }
        // Referential action: suppress DELETE/UPDATE/SET after ON DELETE/UPDATE
        if self.referential_on_active.is_active() && matches!(keyword, "DELETE" | "UPDATE" | "SET")
        {
            return true;
        }
        // Non-subquery paren context: suppress function-local clause starters.
        // `FROM` stays local to the formatter because the active paren stack
        // tells us when EXTRACT-style bodies are safe to keep inline without
        // hiding real query `FROM` clauses from the analyzer.
        if suppress_comma_break_depth > 0
            && ((inside_function_local_non_query_paren && matches!(keyword, "FROM" | "WITH"))
                || (!has_subquery_in_paren_stack
                    && (keyword == "FROM"
                        || sql_text::is_non_subquery_paren_suppressed_clause_start(keyword))))
        {
            return true;
        }
        // SEARCH/CYCLE ... SET
        if self
            .search_cycle_clause_active
            .is_active_at_paren_depth(current_scope.paren_depth)
            && keyword == "SET"
        {
            return true;
        }
        // Analytic WITHIN GROUP
        if is_analytic_within_group {
            return true;
        }
        // CHARACTER SET stays inline (MySQL-specific syntax)
        if keyword == "SET" && matches!(prev_word_upper, Some("CHARACTER")) {
            return true;
        }
        // SIGNAL/RESIGNAL ... SET MESSAGE_TEXT: SET is a sub-clause continuation,
        // not an independent clause break (MySQL-specific syntax)
        if keyword == "SET"
            && SqlEditorWidget::is_mysql_signal_set_clause(tokens, idx, statement_word_links)
        {
            return true;
        }
        // ON DUPLICATE KEY UPDATE: UPDATE stays inline with KEY (MySQL-specific syntax)
        if keyword == "UPDATE"
            && SqlEditorWidget::is_mysql_on_duplicate_key_update(tokens, idx, statement_word_links)
        {
            return true;
        }
        false
    }

    fn has_compact_non_query_frame_since_last_query(paren_stack: &[ParenFormatFrame]) -> bool {
        let start_idx = paren_stack
            .iter()
            .rposition(|frame| frame.is_query_like())
            .map_or(0, |idx| idx.saturating_add(1));

        paren_stack[start_idx..]
            .iter()
            .filter(|frame| frame.suppresses_comma_breaks())
            .count()
            > 0
    }

    /// condition 키워드(ON, AND, OR, WHEN)의 줄바꿈을 억제해야 하는지 판단합니다.
    fn suppresses_condition_break(
        &self,
        keyword: &str,
        prev_word_upper: Option<&str>,
        trigger_header_state: &TriggerHeaderState,
    ) -> bool {
        // OR in CREATE OR REPLACE
        if keyword == "OR" && matches!(prev_word_upper, Some("CREATE")) {
            return true;
        }
        // Trigger: keep event chains inline (`INSERT OR UPDATE`), but let
        // `ON <table>` break onto its own trigger-header line.
        if trigger_header_state.is_active() && keyword == "OR" {
            return true;
        }
        // CREATE INDEX ON
        if keyword == "ON" && self.create_index_pending.is_active() {
            return true;
        }
        // COMMENT ON
        if keyword == "ON" && self.comment_on_active.is_active() {
            return true;
        }
        // MODEL REFERENCE name ON
        if keyword == "ON" && self.model_reference_pending.is_active() {
            return true;
        }
        // GRANT/REVOKE ON
        if self.grant_revoke_active.is_active() && keyword == "ON" {
            return true;
        }
        // ON after REFERENCES (referential constraint)
        if keyword == "ON"
            && (matches!(prev_word_upper, Some("REFERENCES"))
                || self.referential_action_pending.is_active())
        {
            return true;
        }
        false
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum OpenCursorFormatState {
    None,
    AwaitingFor,
    InSelect {
        anchor_indent: usize,
        select_paren_depth: Option<usize>,
    },
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum SelectListBreakState {
    None,
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum SelectListLayoutState {
    Inactive,
    Pending {
        anchor: usize,
        indent: usize,
    },
    Multiline {
        indent: usize,
        hanging_indent_spaces: Option<usize>,
    },
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum InlineCommentContinuationState {
    None,
    Operand { indent: usize },
}

impl SelectListLayoutState {
    fn activate(&mut self, anchor: usize, indent: usize) {
        *self = Self::Pending { anchor, indent };
    }

    fn clear(&mut self) {
        *self = Self::Inactive;
    }

    fn is_multiline(self) -> bool {
        matches!(self, Self::Multiline { .. })
    }

    fn has_active_indent(self) -> bool {
        matches!(self, Self::Pending { .. } | Self::Multiline { .. })
    }

    fn indentation_or(self, fallback: usize) -> usize {
        match self {
            Self::Pending { indent, .. } | Self::Multiline { indent, .. } => indent,
            Self::Inactive => fallback,
        }
    }

    fn hanging_indent_spaces(self, out: &str, fallback_indent: usize) -> usize {
        match self {
            Self::Pending { anchor, indent } => {
                if anchor < out.len() && out.as_bytes().get(anchor) == Some(&b' ') {
                    let line_start = out[..anchor].rfind('\n').map(|idx| idx + 1).unwrap_or(0);
                    anchor
                        .saturating_sub(line_start)
                        .saturating_add(1)
                        .max(indent * 4)
                } else {
                    indent.max(fallback_indent) * 4
                }
            }
            Self::Multiline {
                indent,
                hanging_indent_spaces,
            } => hanging_indent_spaces.unwrap_or_else(|| indent.max(fallback_indent) * 4),
            Self::Inactive => fallback_indent * 4,
        }
    }

    fn force_newline_if_possible(self, out: &mut String) -> Self {
        match self {
            Self::Pending { anchor, indent } => {
                if anchor < out.len() && out.as_bytes().get(anchor) == Some(&b' ') {
                    let indentation = " ".repeat(indent * 4);
                    out.replace_range(anchor..anchor + 1, &format!("\n{indentation}"));
                    Self::Multiline {
                        indent,
                        hanging_indent_spaces: None,
                    }
                } else {
                    self
                }
            }
            _ => self,
        }
    }
}

impl SelectListBreakState {
    fn clear(&mut self) {
        *self = Self::None;
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum ExitConditionState {
    None,
    AwaitingWhen,
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum MySqlHandlerFormatState {
    None,
    AwaitingConditionStart,
    AwaitingNotFoundTail,
    AwaitingSqlstateValueOrLiteral,
    AwaitingSqlstateLiteral,
    AwaitingNextConditionOrBody,
}

impl MySqlHandlerFormatState {
    fn start(&mut self) {
        *self = Self::AwaitingConditionStart;
    }

    fn clear(&mut self) {
        *self = Self::None;
    }

    fn body_line_pending(self) -> bool {
        matches!(self, Self::AwaitingNextConditionOrBody)
    }

    fn consume_word(&mut self, word_upper: &str) -> bool {
        match *self {
            Self::None => false,
            Self::AwaitingConditionStart => {
                *self = match word_upper {
                    "NOT" => Self::AwaitingNotFoundTail,
                    "SQLSTATE" => Self::AwaitingSqlstateValueOrLiteral,
                    _ => Self::AwaitingNextConditionOrBody,
                };
                true
            }
            Self::AwaitingNotFoundTail => {
                if word_upper == "FOUND" {
                    *self = Self::AwaitingNextConditionOrBody;
                    true
                } else {
                    *self = Self::None;
                    false
                }
            }
            Self::AwaitingSqlstateValueOrLiteral => {
                if word_upper == "VALUE" {
                    *self = Self::AwaitingSqlstateLiteral;
                    true
                } else {
                    *self = Self::None;
                    false
                }
            }
            Self::AwaitingSqlstateLiteral => {
                *self = Self::None;
                false
            }
            Self::AwaitingNextConditionOrBody => {
                *self = Self::None;
                false
            }
        }
    }

    fn consume_string(&mut self) -> bool {
        match *self {
            Self::AwaitingConditionStart => {
                *self = Self::AwaitingNextConditionOrBody;
                true
            }
            Self::AwaitingSqlstateValueOrLiteral | Self::AwaitingSqlstateLiteral => {
                *self = Self::AwaitingNextConditionOrBody;
                true
            }
            Self::AwaitingNotFoundTail | Self::AwaitingNextConditionOrBody => {
                *self = Self::None;
                false
            }
            Self::None => false,
        }
    }

    fn on_symbol(&mut self, symbol: &str) {
        match (*self, symbol) {
            (Self::AwaitingNextConditionOrBody, ",") => {
                *self = Self::AwaitingConditionStart;
            }
            (_, ";") => {
                *self = Self::None;
            }
            _ => {}
        }
    }
}

impl ExitConditionState {
    fn on_keyword(&mut self, keyword: &str) {
        match (keyword, *self) {
            ("EXIT" | "CONTINUE", _) => {
                *self = Self::AwaitingWhen;
            }
            ("WHEN", Self::AwaitingWhen) => {
                *self = Self::None;
            }
            _ => {}
        }
    }

    fn is_exit_when(self, keyword: &str) -> bool {
        keyword == "WHEN" && matches!(self, Self::AwaitingWhen)
    }

    fn clear(&mut self) {
        *self = Self::None;
    }
}

#[derive(Clone, PartialEq, Eq)]
struct WithCteFrame {
    paren_depth: usize,
    owner_depth: Option<usize>,
    plsql_state: WithPlsqlFormatState,
}

#[derive(Default)]
struct WithCteFormatState {
    frames: Vec<WithCteFrame>,
}

#[derive(Clone, Copy, PartialEq, Eq)]
struct WithPlsqlPendingDeclaration {
    starts_body: bool,
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum WithPlsqlBodyFrameKind {
    Routine,
    Block,
    Case,
    If,
    Loop,
}

#[derive(Clone, Copy, PartialEq, Eq)]
struct WithPlsqlBodyFrame {
    kind: WithPlsqlBodyFrameKind,
    awaiting_begin: bool,
}

impl WithPlsqlBodyFrame {
    fn routine() -> Self {
        Self {
            kind: WithPlsqlBodyFrameKind::Routine,
            awaiting_begin: true,
        }
    }

    fn nested(kind: WithPlsqlBodyFrameKind) -> Self {
        Self {
            kind,
            awaiting_begin: false,
        }
    }
}

#[derive(Clone, PartialEq, Eq)]
enum WithPlsqlFormatState {
    None,
    Collecting {
        active_body_frames: Vec<WithPlsqlBodyFrame>,
        pending_routine_declaration: Option<WithPlsqlPendingDeclaration>,
        pending_end: bool,
    },
    AwaitingMainQuery,
}

#[derive(Default)]
struct TriggerHeaderState {
    scopes: Vec<FormatScope>,
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum CompoundTriggerPhase {
    AwaitingOuterBodyStart,
    InOuterBody,
    AwaitingTimingPointBodyStart,
}

struct CompoundTriggerFrame {
    scope: FormatScope,
    phase: CompoundTriggerPhase,
}

#[derive(Default)]
struct CompoundTriggerState {
    frames: Vec<CompoundTriggerFrame>,
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum CommentAttachment {
    Previous,
    Next,
    Block,
    FileHeader,
}

#[derive(Clone, Copy)]
struct QueryApplyFrame {
    start_paren_depth: usize,
    started_inside_paren: bool,
    has_apply: bool,
    in_apply_clause: bool,
}

impl TriggerHeaderState {
    fn sync_scope(&mut self, current_scope: FormatScope) {
        while self
            .scopes
            .last()
            .is_some_and(|scope| !scope.contains(current_scope))
        {
            self.scopes.pop();
        }
    }

    fn is_active(&self) -> bool {
        !self.scopes.is_empty()
    }

    fn start(&mut self, scope: FormatScope) {
        self.scopes.push(scope);
    }

    fn clear(&mut self) {
        self.scopes.clear();
    }
}

impl CompoundTriggerState {
    fn sync_scope(&mut self, current_scope: FormatScope) {
        while self
            .frames
            .last()
            .is_some_and(|frame| !frame.scope.contains(current_scope))
        {
            self.frames.pop();
        }
    }

    fn awaiting_outer_body_start(&self) -> bool {
        self.frames.last().is_some_and(|frame| {
            matches!(frame.phase, CompoundTriggerPhase::AwaitingOuterBodyStart)
        })
    }

    fn mark_compound_header(&mut self, scope: FormatScope) {
        self.frames.push(CompoundTriggerFrame {
            scope,
            phase: CompoundTriggerPhase::AwaitingOuterBodyStart,
        });
    }

    fn enter_outer_body(&mut self) {
        if let Some(frame) = self.frames.last_mut() {
            frame.phase = CompoundTriggerPhase::InOuterBody;
        }
    }

    fn is_in_outer_body(&self) -> bool {
        self.frames.last().is_some_and(|frame| {
            matches!(
                frame.phase,
                CompoundTriggerPhase::InOuterBody
                    | CompoundTriggerPhase::AwaitingTimingPointBodyStart
            )
        })
    }

    fn start_timing_point(&mut self) {
        if let Some(frame) = self.frames.last_mut() {
            frame.phase = CompoundTriggerPhase::AwaitingTimingPointBodyStart;
        }
    }

    fn begin_timing_point_body(&mut self) {
        if let Some(frame) = self.frames.last_mut() {
            if matches!(
                frame.phase,
                CompoundTriggerPhase::AwaitingTimingPointBodyStart
            ) {
                frame.phase = CompoundTriggerPhase::InOuterBody;
            }
        }
    }

    fn clear(&mut self) {
        self.frames.clear();
    }
}

impl WithCteFormatState {
    fn pop_with_plsql_body_frame(
        active_body_frames: &mut Vec<WithPlsqlBodyFrame>,
        expected_kind: Option<WithPlsqlBodyFrameKind>,
    ) {
        if let Some(expected_kind) = expected_kind {
            if active_body_frames
                .last()
                .is_some_and(|frame| frame.kind == expected_kind)
            {
                let _ = active_body_frames.pop();
                return;
            }

            if let Some(frame_idx) = active_body_frames
                .iter()
                .rposition(|frame| frame.kind == expected_kind)
            {
                active_body_frames.remove(frame_idx);
                return;
            }
        }

        let _ = active_body_frames.pop();
    }

    fn on_word(&mut self, keyword: &str, prev_word_upper: Option<&str>) {
        let upper = keyword.to_ascii_uppercase();
        let mut close_current_frame = false;

        if let Some(frame) = self.frames.last_mut() {
            match &mut frame.plsql_state {
                WithPlsqlFormatState::None | WithPlsqlFormatState::AwaitingMainQuery => {
                    if frame.paren_depth == 0
                        && sql_text::is_with_plsql_declaration_keyword(upper.as_str())
                    {
                        frame.plsql_state = WithPlsqlFormatState::Collecting {
                            active_body_frames: Vec::new(),
                            pending_routine_declaration: Some(WithPlsqlPendingDeclaration {
                                starts_body: sql_text::with_plsql_declaration_starts_routine_body(
                                    upper.as_str(),
                                ),
                            }),
                            pending_end: false,
                        };
                    } else if frame.paren_depth == 0
                        && matches!(
                            upper.as_str(),
                            "SELECT" | "UPDATE" | "DELETE" | "INSERT" | "MERGE"
                        )
                    {
                        close_current_frame = true;
                    }
                }
                WithPlsqlFormatState::Collecting {
                    active_body_frames,
                    pending_routine_declaration,
                    pending_end,
                } => {
                    let mut consumed_end_qualifier = false;
                    if *pending_end {
                        match upper.as_str() {
                            "CASE" => {
                                Self::pop_with_plsql_body_frame(
                                    active_body_frames,
                                    Some(WithPlsqlBodyFrameKind::Case),
                                );
                                consumed_end_qualifier = true;
                            }
                            "IF" => {
                                Self::pop_with_plsql_body_frame(
                                    active_body_frames,
                                    Some(WithPlsqlBodyFrameKind::If),
                                );
                                consumed_end_qualifier = true;
                            }
                            "LOOP" => {
                                Self::pop_with_plsql_body_frame(
                                    active_body_frames,
                                    Some(WithPlsqlBodyFrameKind::Loop),
                                );
                                consumed_end_qualifier = true;
                            }
                            _ => {
                                Self::pop_with_plsql_body_frame(active_body_frames, None);
                            }
                        }
                        *pending_end = false;
                    }

                    if !consumed_end_qualifier {
                        if frame.paren_depth == 0
                            && sql_text::is_with_plsql_declaration_keyword(upper.as_str())
                        {
                            *pending_routine_declaration = Some(WithPlsqlPendingDeclaration {
                                starts_body: sql_text::with_plsql_declaration_starts_routine_body(
                                    upper.as_str(),
                                ),
                            });
                        } else if matches!(upper.as_str(), "AS" | "IS")
                            && pending_routine_declaration
                                .is_some_and(|declaration| declaration.starts_body)
                        {
                            active_body_frames.push(WithPlsqlBodyFrame::routine());
                            *pending_routine_declaration = None;
                        } else if upper == "BEGIN" {
                            if let Some(frame) = active_body_frames.last_mut() {
                                if frame.kind == WithPlsqlBodyFrameKind::Routine
                                    && frame.awaiting_begin
                                {
                                    frame.awaiting_begin = false;
                                } else {
                                    active_body_frames.push(WithPlsqlBodyFrame::nested(
                                        WithPlsqlBodyFrameKind::Block,
                                    ));
                                }
                            }
                        } else if upper == "DECLARE" {
                            if !active_body_frames.is_empty() {
                                active_body_frames.push(WithPlsqlBodyFrame::nested(
                                    WithPlsqlBodyFrameKind::Block,
                                ));
                            }
                        } else if upper == "CASE" {
                            if !active_body_frames.is_empty() {
                                active_body_frames
                                    .push(WithPlsqlBodyFrame::nested(WithPlsqlBodyFrameKind::Case));
                            }
                        } else if upper == "IF" {
                            if !active_body_frames.is_empty() {
                                active_body_frames
                                    .push(WithPlsqlBodyFrame::nested(WithPlsqlBodyFrameKind::If));
                            }
                        } else if upper == "LOOP" {
                            if !active_body_frames.is_empty() {
                                active_body_frames
                                    .push(WithPlsqlBodyFrame::nested(WithPlsqlBodyFrameKind::Loop));
                            }
                        } else if upper == "END" && !active_body_frames.is_empty() {
                            *pending_end = true;
                        }
                    }
                }
            }
        }

        if close_current_frame {
            let _ = self.frames.pop();
        }

        let starts_cte_definitions =
            upper == "WITH" && !matches!(prev_word_upper, Some("START" | "ROW" | "ROWS"));
        if starts_cte_definitions {
            self.frames.push(WithCteFrame {
                paren_depth: 0,
                owner_depth: None,
                plsql_state: WithPlsqlFormatState::None,
            });
        }
    }

    fn record_with_owner_depth(&mut self, owner_depth: usize) {
        if let Some(frame) = self.frames.last_mut() {
            if frame.paren_depth == 0
                && matches!(
                    frame.plsql_state,
                    WithPlsqlFormatState::None | WithPlsqlFormatState::AwaitingMainQuery
                )
            {
                frame.owner_depth = Some(owner_depth);
            }
        }
    }

    fn separator_indent(&self, fallback: usize) -> usize {
        self.frames
            .last()
            .and_then(|frame| frame.owner_depth)
            .unwrap_or(fallback)
    }

    fn on_open_paren(&mut self) {
        for frame in &mut self.frames {
            frame.paren_depth = frame.paren_depth.saturating_add(1);
        }
    }

    fn on_close_paren(&mut self) {
        for frame in &mut self.frames {
            frame.paren_depth = frame.paren_depth.saturating_sub(1);
        }
    }

    fn on_separator(&mut self) {
        if let Some(frame) = self.frames.last_mut() {
            if let WithPlsqlFormatState::Collecting {
                active_body_frames,
                pending_routine_declaration,
                pending_end,
            } = &mut frame.plsql_state
            {
                if *pending_end {
                    Self::pop_with_plsql_body_frame(active_body_frames, None);
                    *pending_end = false;
                }
                if frame.paren_depth > 0 {
                    return;
                }
                *pending_routine_declaration = None;

                if active_body_frames.is_empty() {
                    frame.plsql_state = WithPlsqlFormatState::AwaitingMainQuery;
                }
            }
        }
    }

    fn can_close_on_select(&self) -> bool {
        self.frames.last().is_some_and(|frame| {
            frame.paren_depth == 0
                && matches!(
                    frame.plsql_state,
                    WithPlsqlFormatState::None | WithPlsqlFormatState::AwaitingMainQuery
                )
        })
    }

    fn collecting_routine_declaration_body_start(&self) -> bool {
        self.frames.last().is_some_and(|frame| {
            matches!(
                frame.plsql_state,
                WithPlsqlFormatState::Collecting {
                    pending_routine_declaration: Some(WithPlsqlPendingDeclaration {
                        starts_body: true
                    }),
                    ..
                }
            )
        })
    }

    fn collecting_plsql_declaration_header(&self) -> bool {
        self.frames.last().is_some_and(|frame| {
            matches!(
                frame.plsql_state,
                WithPlsqlFormatState::Collecting {
                    pending_routine_declaration: Some(_),
                    ..
                }
            )
        })
    }

    fn keeps_top_level_semicolon_inside_with_definitions(&self) -> bool {
        self.frames.last().is_some_and(|frame| {
            matches!(frame.plsql_state, WithPlsqlFormatState::AwaitingMainQuery)
        })
    }

    fn in_definitions(&self) -> bool {
        !self.frames.is_empty()
    }
}

impl OpenCursorFormatState {
    fn base_indent(self, indent_level: usize) -> usize {
        match self {
            Self::InSelect { anchor_indent, .. } => indent_level.max(anchor_indent),
            _ => indent_level,
        }
    }

    fn in_select(self) -> bool {
        matches!(self, Self::InSelect { .. })
    }

    fn set_select_depth(&mut self, depth: usize) {
        if let Self::InSelect {
            select_paren_depth, ..
        } = self
        {
            if select_paren_depth.is_none() {
                *select_paren_depth = Some(depth);
            }
        }
    }

    fn select_depth(self) -> Option<usize> {
        match self {
            Self::InSelect {
                select_paren_depth, ..
            } => select_paren_depth,
            _ => None,
        }
    }
}

impl SqlEditorWidget {
    const INDENT_TAB_WIDTH: usize = 4;

    fn normalized_indent_tab_width() -> usize {
        Self::INDENT_TAB_WIDTH.max(1)
    }

    fn safe_indent_div(value: usize) -> usize {
        value
            .checked_div(Self::normalized_indent_tab_width())
            .unwrap_or(0)
    }

    fn mysql_formatter_profile_enabled() -> bool {
        std::env::var_os("SPACE_PROFILE_MYSQL_FORMATTER").is_some()
    }

    fn profile_mysql_formatter_stage<F>(
        stage: &str,
        input_len: usize,
        enabled: bool,
        f: F,
    ) -> String
    where
        F: FnOnce() -> String,
    {
        if !enabled {
            return f();
        }

        let started_at = std::time::Instant::now();
        let output = f();
        eprintln!(
            "[mysql-formatter] stage={stage} input_bytes={input_len} output_bytes={} elapsed_ms={:.3}",
            output.len(),
            started_at.elapsed().as_secs_f64() * 1000.0
        );
        output
    }

    fn previous_word_upper(tokens: &[SqlToken], start_idx: usize) -> Option<(String, usize)> {
        let mut idx = start_idx;
        while idx > 0 {
            idx = idx.saturating_sub(1);
            match tokens.get(idx) {
                Some(SqlToken::Comment(_)) => continue,
                Some(SqlToken::Word(word)) => return Some((word.to_ascii_uppercase(), idx)),
                _ => return None,
            }
        }

        None
    }

    fn next_meaningful_word<'a>(tokens: &'a [SqlToken], cursor: &mut usize) -> Option<&'a str> {
        while let Some(token) = tokens.get(*cursor) {
            *cursor = cursor.saturating_add(1);
            if let SqlToken::Word(word) = token {
                return Some(word.as_str());
            }
        }
        None
    }

    fn statement_starts_with_package_body_header(tokens: &[SqlToken]) -> bool {
        let mut cursor = 0usize;
        let Some(first) = Self::next_meaningful_word(tokens, &mut cursor) else {
            return false;
        };
        if !first.eq_ignore_ascii_case("CREATE") {
            return false;
        }

        let Some(mut current) = Self::next_meaningful_word(tokens, &mut cursor) else {
            return false;
        };

        if current.eq_ignore_ascii_case("OR") {
            let Some(replace) = Self::next_meaningful_word(tokens, &mut cursor) else {
                return false;
            };
            if !replace.eq_ignore_ascii_case("REPLACE") {
                return false;
            }
            let Some(after_replace) = Self::next_meaningful_word(tokens, &mut cursor) else {
                return false;
            };
            current = after_replace;
        }

        while current.eq_ignore_ascii_case("EDITIONABLE")
            || current.eq_ignore_ascii_case("NONEDITIONABLE")
        {
            let Some(next) = Self::next_meaningful_word(tokens, &mut cursor) else {
                return false;
            };
            current = next;
        }

        if !current.eq_ignore_ascii_case("PACKAGE") {
            return false;
        }

        Self::next_meaningful_word(tokens, &mut cursor)
            .is_some_and(|word| word.eq_ignore_ascii_case("BODY"))
    }

    fn statement_contains_keyword(tokens: &[SqlToken], keyword: &str) -> bool {
        tokens.iter().any(
            |token| matches!(token, SqlToken::Word(word) if word.eq_ignore_ascii_case(keyword)),
        )
    }

    fn query_like_paren_layout(
        owner_line: &str,
        owner_depth: usize,
        current_query_base: Option<usize>,
        standalone_opener: bool,
    ) -> QueryLikeParenLayout {
        if standalone_opener {
            let close_depth = if owner_line.trim_end().ends_with('(') {
                owner_depth.saturating_add(1)
            } else {
                owner_depth
            };
            let child_head_depth = close_depth.saturating_add(1);
            return QueryLikeParenLayout {
                child_head_depth,
                close_depth,
            };
        }

        let mut owner_with_open_paren = String::with_capacity(owner_line.len().saturating_add(2));
        owner_with_open_paren.push_str(owner_line.trim_end());
        if !owner_with_open_paren.is_empty() && !owner_with_open_paren.ends_with(' ') {
            owner_with_open_paren.push(' ');
        }
        owner_with_open_paren.push('(');

        if sql_text::line_is_format_cte_definition_header(&owner_with_open_paren)
            || sql_text::line_is_create_query_body_header(&owner_with_open_paren)
        {
            let child_head_depth = owner_depth.saturating_add(1);
            return QueryLikeParenLayout {
                child_head_depth,
                close_depth: owner_depth,
            };
        }

        if sql_text::line_ends_with_identifier_sequence_before_inline_comment(
            owner_line,
            &["VALUE"],
        ) {
            let child_head_depth = owner_depth.saturating_add(1);
            return QueryLikeParenLayout {
                child_head_depth,
                close_depth: child_head_depth,
            };
        }

        if sql_text::line_ends_with_identifier_sequence_before_inline_comment(owner_line, &["JOIN"])
            || sql_text::line_ends_with_identifier_sequence_before_inline_comment(
                owner_line,
                &["APPLY"],
            )
        {
            let child_head_depth = owner_depth.saturating_add(1);
            return QueryLikeParenLayout {
                child_head_depth,
                close_depth: owner_depth,
            };
        }

        let child_head_depth =
            sql_text::contextual_format_query_owner_kind(&owner_with_open_paren, true)
                .map(|kind| kind.formatter_child_query_head_depth(owner_depth, current_query_base))
                .unwrap_or_else(|| owner_depth.saturating_add(1));

        QueryLikeParenLayout {
            child_head_depth,
            close_depth: child_head_depth.saturating_sub(1),
        }
    }

    fn is_log_errors_into_clause(
        tokens: &[SqlToken],
        into_idx: usize,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let prev_word_idx = statement_word_links
            .and_then(|links| links.prev_word_index(into_idx))
            .or_else(|| Self::previous_word_upper(tokens, into_idx).map(|(_, idx)| idx));
        let Some(prev_idx) = prev_word_idx else {
            return false;
        };
        let Some(SqlToken::Word(prev_word)) = tokens.get(prev_idx) else {
            return false;
        };
        if !prev_word.eq_ignore_ascii_case("ERRORS") {
            return false;
        }

        let second_prev_word_idx = statement_word_links
            .and_then(|links| links.prev_word_index(prev_idx))
            .or_else(|| Self::previous_word_upper(tokens, prev_idx).map(|(_, idx)| idx));
        second_prev_word_idx
            .and_then(|idx| tokens.get(idx))
            .is_some_and(
                |token| matches!(token, SqlToken::Word(word) if word.eq_ignore_ascii_case("LOG")),
            )
    }

    fn is_multiset_set_operator(
        tokens: &[SqlToken],
        idx: usize,
        prev_word_upper: Option<&str>,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        if matches!(prev_word_upper, Some("MULTISET")) {
            return true;
        }

        statement_word_links
            .and_then(|links| links.prev_word_index(idx))
            .and_then(|prev_idx| tokens.get(prev_idx))
            .is_some_and(
                |token| matches!(token, SqlToken::Word(word) if word.eq_ignore_ascii_case("MULTISET")),
            )
    }

    fn is_inline_clause_phrase(
        tokens: &[SqlToken],
        idx: usize,
        keyword: &str,
        prev_word_upper: Option<&str>,
        current_scope: FormatScope,
        construct: &ConstructState,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        if construct.forall_pending.is_active() && keyword == "VALUES" {
            return true;
        }
        if keyword == "INTO" && Self::is_log_errors_into_clause(tokens, idx, statement_word_links) {
            return true;
        }
        if keyword == "LIMIT" && matches!(prev_word_upper, Some("REJECT")) {
            return true;
        }
        if crate::sql_text::is_format_set_operator_keyword(keyword)
            && Self::is_multiset_set_operator(tokens, idx, prev_word_upper, statement_word_links)
        {
            return true;
        }
        if construct
            .model_active
            .is_active_at_paren_depth(current_scope.paren_depth)
            && keyword == "UPDATE"
            && matches!(prev_word_upper, Some("RULES"))
        {
            return true;
        }

        false
    }

    fn significant_tokens<'a>(
        tokens: &'a [SqlToken],
    ) -> impl DoubleEndedIterator<Item = &'a SqlToken> + 'a {
        tokens
            .iter()
            .filter(|token| !matches!(token, SqlToken::Comment(_)))
    }

    fn starts_with_end_suffix_terminator_tokens(tokens: &[SqlToken]) -> bool {
        let mut meaningful = Self::significant_tokens(tokens);
        matches!(
            (meaningful.next(), meaningful.next()),
            (Some(SqlToken::Word(first)), Some(SqlToken::Word(second)))
                if first.eq_ignore_ascii_case("END")
                    && crate::sql_text::is_format_plain_end_suffix_keyword(second)
        )
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn starts_with_end_suffix_terminator(line: &str) -> bool {
        let tokens = Self::tokenize_sql(line);
        Self::starts_with_end_suffix_terminator_tokens(&tokens)
    }

    fn tokens_continue_plsql_condition_terminator(tokens: &[SqlToken], idx: usize) -> bool {
        for token in tokens.iter().skip(idx.saturating_add(1)) {
            match token {
                SqlToken::Comment(comment) if comment.contains('\n') => break,
                SqlToken::Comment(_) => {}
                SqlToken::Symbol(sym) if sym == ")" => {}
                SqlToken::Symbol(sym) if sym == ";" || sym == "," => break,
                SqlToken::Word(word)
                    if word.eq_ignore_ascii_case("THEN") || word.eq_ignore_ascii_case("LOOP") =>
                {
                    return true;
                }
                _ => break,
            }
        }

        false
    }

    fn starts_with_plain_end_tokens(tokens: &[SqlToken]) -> bool {
        let mut meaningful = Self::significant_tokens(tokens);
        matches!(meaningful.next(), Some(SqlToken::Word(first)) if first.eq_ignore_ascii_case("END"))
            && !matches!(
                meaningful.next(),
                Some(SqlToken::Word(second))
                    if crate::sql_text::is_format_plain_end_suffix_keyword(second)
            )
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn starts_with_plain_end(line: &str) -> bool {
        let tokens = Self::tokenize_sql(line);
        Self::starts_with_plain_end_tokens(&tokens)
    }

    fn starts_with_bare_end_tokens(tokens: &[SqlToken]) -> bool {
        let mut meaningful = Self::significant_tokens(tokens);
        match meaningful.next() {
            Some(SqlToken::Word(first)) if first.eq_ignore_ascii_case("END") => {}
            _ => return false,
        }

        match meaningful.next() {
            None => true,
            Some(SqlToken::Symbol(symbol)) if symbol == ";" => meaningful.next().is_none(),
            Some(SqlToken::Word(word))
                if crate::sql_text::is_format_plain_end_suffix_keyword(word) =>
            {
                false
            }
            _ => false,
        }
    }

    #[cfg(test)]
    fn starts_with_mysql_custom_delimited_end(line: &str) -> bool {
        let trimmed = line.trim_start();
        let Some(prefix) = trimmed.get(..3) else {
            return false;
        };
        if !prefix.eq_ignore_ascii_case("END") {
            return false;
        }

        let mut delimiter_end = None;
        for (idx, ch) in trimmed[3..].trim_start().char_indices() {
            if matches!(ch, '$' | '/') {
                delimiter_end = Some(idx + ch.len_utf8());
                continue;
            }
            break;
        }

        let Some(delimiter_end) = delimiter_end else {
            return false;
        };

        let rest = &trimmed[3..].trim_start()[delimiter_end..];
        let trailing = rest.trim_start();
        trailing.is_empty()
            || trailing.starts_with("--")
            || trailing.starts_with('#')
            || trailing.starts_with("/*")
    }

    #[cfg(test)]
    fn starts_with_block_terminating_end(line: &str, tokens: &[SqlToken]) -> bool {
        Self::starts_with_bare_end_tokens(tokens)
            || Self::starts_with_mysql_custom_delimited_end(line)
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn starts_with_bare_end(line: &str) -> bool {
        let tokens = Self::tokenize_sql(line);
        Self::starts_with_bare_end_tokens(&tokens)
    }

    fn line_ends_with_semicolon_before_inline_comment(line: &str) -> bool {
        crate::sql_text::line_ends_with_semicolon_before_inline_comment(line)
    }

    fn paren_opens_analytic_layout(
        current_clause: Option<&str>,
        prev_word_upper: Option<&str>,
    ) -> bool {
        matches!(prev_word_upper, Some("OVER"))
            || (matches!(current_clause, Some("WINDOW")) && matches!(prev_word_upper, Some("AS")))
    }

    fn query_apply_flags(tokens: &[SqlToken]) -> Vec<bool> {
        let mut flags = vec![false; tokens.len()];
        let mut frames: Vec<QueryApplyFrame> = Vec::new();
        let mut active_frame_ids: Vec<usize> = Vec::new();
        let mut token_frame_ids: Vec<Option<usize>> = vec![None; tokens.len()];
        let mut paren_depth = 0usize;
        let mut apply_paren_pending = false;
        let mut apply_clause_paren_depths: Vec<usize> = Vec::new();

        for (idx, token) in tokens.iter().enumerate() {
            token_frame_ids[idx] = active_frame_ids.last().copied();

            match token {
                SqlToken::Word(word) if word.eq_ignore_ascii_case("SELECT") => {
                    let frame_id = frames.len();
                    frames.push(QueryApplyFrame {
                        start_paren_depth: paren_depth,
                        started_inside_paren: paren_depth > 0,
                        has_apply: false,
                        in_apply_clause: apply_clause_paren_depths
                            .last()
                            .is_some_and(|depth| *depth == paren_depth),
                    });
                    active_frame_ids.push(frame_id);
                    token_frame_ids[idx] = Some(frame_id);
                    apply_paren_pending = false;
                }
                SqlToken::Word(word) if word.eq_ignore_ascii_case("APPLY") => {
                    if let Some(frame_id) = active_frame_ids.last().copied() {
                        if let Some(frame) = frames.get_mut(frame_id) {
                            frame.has_apply = true;
                        }
                    }
                    apply_paren_pending = true;
                }
                SqlToken::Symbol(symbol) if symbol == "(" => {
                    paren_depth = paren_depth.saturating_add(1);
                    if apply_paren_pending {
                        apply_clause_paren_depths.push(paren_depth);
                        apply_paren_pending = false;
                    }
                }
                SqlToken::Symbol(symbol) if symbol == ")" => {
                    apply_paren_pending = false;
                    paren_depth = paren_depth.saturating_sub(1);
                    while apply_clause_paren_depths
                        .last()
                        .is_some_and(|depth| paren_depth < *depth)
                    {
                        apply_clause_paren_depths.pop();
                    }
                    while active_frame_ids.last().is_some_and(|frame_id| {
                        frames.get(*frame_id).is_some_and(|frame| {
                            frame.started_inside_paren && paren_depth < frame.start_paren_depth
                        })
                    }) {
                        active_frame_ids.pop();
                    }
                }
                SqlToken::Symbol(symbol) if symbol == ";" => {
                    apply_paren_pending = false;
                    while active_frame_ids.last().is_some_and(|frame_id| {
                        frames
                            .get(*frame_id)
                            .is_some_and(|frame| !frame.started_inside_paren)
                    }) {
                        active_frame_ids.pop();
                    }
                }
                SqlToken::Comment(_) => {}
                _ => {
                    apply_paren_pending = false;
                }
            }
        }

        for (idx, frame_id) in token_frame_ids.into_iter().enumerate() {
            if let Some(frame_id) = frame_id {
                if let Some(frame) = frames.get(frame_id) {
                    flags[idx] = frame.has_apply || frame.in_apply_clause;
                }
            }
        }

        flags
    }

    #[cfg_attr(not(test), allow(dead_code))]
    pub(super) fn format_for_auto_formatting(source: &str, selected_only: bool) -> String {
        Self::format_for_auto_formatting_with_db_type(source, selected_only, None)
    }

    pub(super) fn format_for_auto_formatting_with_db_type(
        source: &str,
        selected_only: bool,
        preferred_db_type: Option<DatabaseType>,
    ) -> String {
        // A selected SQL fragment should keep canonical statement terminators.
        // Otherwise select-all / partial-selection formatting can drop semicolons
        // that `split_format_items()` strips internally, which then breaks
        // statement boundaries for Ctrl+Enter execution on the formatted text.
        let preserve_missing_selection_terminator =
            selected_only && !Self::selected_formatting_has_statement(source);

        let formatted = if preserve_missing_selection_terminator {
            Self::format_sql_basic_with_terminator_policy_for_db_type(
                source,
                false,
                preferred_db_type,
            )
        } else {
            Self::format_sql_basic_for_preferred_db_type(source, preferred_db_type)
        };

        if preserve_missing_selection_terminator {
            Self::preserve_selected_text_terminator(source, formatted)
        } else {
            formatted
        }
    }

    pub(super) fn selected_formatting_has_statement(source: &str) -> bool {
        // Comment-only / tool-command-only selections still use the
        // "preserve original missing terminator" path. Any real SQL statement
        // should format to the same canonical shape as whole-buffer formatting.
        super::query_text::split_script_items(source)
            .iter()
            .any(|item| matches!(item, ScriptItem::Statement(_)))
    }

    pub(super) fn normalize_index(text: &str, index: i32) -> usize {
        if index <= 0 {
            0
        } else {
            Self::clamp_to_char_boundary(text, index as usize)
        }
    }

    pub(super) fn clamp_to_char_boundary(text: &str, index: usize) -> usize {
        let mut idx = index.min(text.len());
        if text.is_char_boundary(idx) {
            return idx;
        }

        // Clamp invalid UTF-8 byte offsets to the previous valid boundary.
        while idx > 0 && !text.is_char_boundary(idx) {
            idx -= 1;
        }
        idx
    }

    #[cfg_attr(not(test), allow(dead_code))]
    pub(super) fn map_cursor_after_format(source: &str, formatted: &str, original_pos: i32) -> i32 {
        Self::map_cursor_after_format_with_policy(source, formatted, original_pos, false)
    }

    #[cfg_attr(not(test), allow(dead_code))]
    pub(super) fn map_cursor_after_format_with_policy(
        source: &str,
        formatted: &str,
        original_pos: i32,
        selected_only: bool,
    ) -> i32 {
        Self::map_cursor_after_format_with_policy_for_db_type(
            source,
            formatted,
            original_pos,
            selected_only,
            None,
        )
    }

    pub(super) fn map_cursor_after_format_with_policy_for_db_type(
        source: &str,
        formatted: &str,
        original_pos: i32,
        selected_only: bool,
        preferred_db_type: Option<DatabaseType>,
    ) -> i32 {
        if original_pos <= 0 {
            return 0;
        }

        let source_pos = Self::clamp_to_char_boundary(source, original_pos as usize);
        if source.len() >= CURSOR_MAPPING_FULL_REFORMAT_THRESHOLD_BYTES {
            if source.is_empty() || formatted.is_empty() {
                return 0;
            }
            let scaled_pos = (source_pos as u128)
                .saturating_mul(formatted.len() as u128)
                .checked_div(source.len() as u128)
                .unwrap_or(0);
            return Self::clamp_to_char_boundary(formatted, scaled_pos as usize) as i32;
        }

        let source_prefix = &source[..source_pos];
        let formatted_prefix = if selected_only {
            Self::format_for_auto_formatting_with_db_type(source_prefix, true, preferred_db_type)
        } else {
            Self::format_sql_basic_for_preferred_db_type(source_prefix, preferred_db_type)
        };
        let mut formatted_pos = formatted_prefix.len().min(formatted.len());
        formatted_pos = Self::clamp_to_char_boundary(formatted, formatted_pos);
        formatted_pos = Self::advance_over_inserted_layout_whitespace(
            source,
            source_pos,
            formatted,
            formatted_pos,
        );
        formatted_pos as i32
    }

    pub(super) fn advance_over_inserted_layout_whitespace(
        source: &str,
        source_pos: usize,
        formatted: &str,
        formatted_pos: usize,
    ) -> usize {
        let source_byte = match source.as_bytes().get(source_pos) {
            Some(byte) => *byte,
            None => return formatted_pos,
        };

        if source_byte.is_ascii_whitespace() {
            return formatted_pos;
        }

        let mut cursor = formatted_pos;
        while let Some(byte) = formatted.as_bytes().get(cursor) {
            if !byte.is_ascii_whitespace() {
                break;
            }
            cursor += 1;
        }

        Self::clamp_to_char_boundary(formatted, cursor)
    }

    pub(super) fn preserve_selected_text_terminator(source: &str, formatted: String) -> String {
        if Self::source_has_explicit_semicolon_terminator(source) {
            return formatted;
        }

        if let Some(without_semicolon) = Self::remove_trailing_statement_semicolon(&formatted) {
            return without_semicolon;
        }

        formatted
    }

    fn removable_trailing_semicolon_span(formatted: &str) -> Option<(usize, usize)> {
        let mut trimmed_len = formatted.trim_end().len();
        while trimmed_len > 0 {
            let prefix = &formatted[..trimmed_len];
            let line_start = prefix.rfind('\n').map_or(0, |idx| idx + 1);
            let line = &prefix[line_start..trimmed_len];
            let line_trimmed = line.trim_start();

            let is_trailing_comment_line = line_trimmed.starts_with("--")
                || Self::is_sqlplus_remark_comment_statement(line_trimmed);

            if !is_trailing_comment_line {
                break;
            }

            trimmed_len = prefix[..line_start].trim_end().len();
        }

        if trimmed_len == 0 {
            return None;
        }
        let trimmed = &formatted[..trimmed_len];
        if let Some(last_line_start) = trimmed.rfind('\n').map(|idx| idx + 1).or(Some(0)) {
            let last_line = &trimmed[last_line_start..];
            let leading_ws = last_line.len().saturating_sub(last_line.trim_start().len());
            let last_line_trimmed = &last_line[leading_ws..];
            if let Some(rest) = last_line_trimmed.strip_prefix(';') {
                let rest_trimmed = rest.trim_start();
                if Self::is_sqlplus_remark_comment_statement(rest_trimmed) {
                    let semicolon_start = last_line_start + leading_ws;
                    return Some((semicolon_start, semicolon_start + 1));
                }
            }
        }

        let spans = super::query_text::tokenize_sql_spanned(trimmed);

        let mut semicolon_span: Option<(usize, usize)> = None;

        for span in spans.iter().rev() {
            match &span.token {
                SqlToken::Comment(comment_text) if comment_text.starts_with("--") => continue,
                SqlToken::Comment(_) => continue,
                SqlToken::Symbol(sym) if sym == "/" => continue,
                SqlToken::Symbol(sym) if sym == ";" => {
                    if Self::semicolon_belongs_to_non_sql_line(trimmed, span.start) {
                        continue;
                    }
                    semicolon_span = Some((span.start, span.end));
                    break;
                }
                _ => break,
            }
        }

        semicolon_span
    }

    fn remove_trailing_statement_semicolon(formatted: &str) -> Option<String> {
        let (semicolon_start, semicolon_end) = Self::removable_trailing_semicolon_span(formatted)?;

        let mut out = String::with_capacity(
            formatted
                .len()
                .saturating_sub(semicolon_end.saturating_sub(semicolon_start)),
        );
        out.push_str(&formatted[..semicolon_start]);
        out.push_str(&formatted[semicolon_end..]);
        Some(out)
    }

    fn append_statement_terminator(
        formatted_statement: &mut String,
        terminator: &str,
        mysql_compatible: bool,
    ) {
        let trim_len = formatted_statement.trim_end().len();
        if trim_len == 0 || terminator.is_empty() {
            return;
        }

        let trimmed = &formatted_statement[..trim_len];
        let mut insert_at = trim_len;
        let mut has_trailing_comment = false;

        let mut trailing_comment_start = trim_len;
        loop {
            let prefix = &trimmed[..trailing_comment_start];
            let line_start = prefix.rfind('\n').map_or(0, |idx| idx + 1);
            let line = &prefix[line_start..trailing_comment_start];
            let line_trimmed = line.trim_start();
            if Self::is_sqlplus_remark_comment_statement(line_trimmed) {
                has_trailing_comment = true;
                insert_at = line_start;
                trailing_comment_start = prefix[..line_start].trim_end().len();
                if trailing_comment_start == 0 {
                    break;
                }
                continue;
            }
            break;
        }

        let spans = if mysql_compatible {
            super::query_text::tokenize_sql_spanned_with_mysql_compat(trimmed, true)
        } else {
            super::query_text::tokenize_sql_spanned(trimmed)
        };
        for span in spans.iter().rev() {
            match &span.token {
                SqlToken::Comment(comment) if Self::is_mysql_executable_comment_token(comment) => {
                    break;
                }
                SqlToken::Comment(_) => {
                    has_trailing_comment = true;
                    insert_at = insert_at.min(span.start);
                }
                SqlToken::Symbol(sym) if sym == "/" => continue,
                _ => break,
            }
        }

        if has_trailing_comment {
            while insert_at > 0 {
                match trimmed.as_bytes().get(insert_at - 1) {
                    Some(b' ' | b'\t' | b'\n' | b'\r') => insert_at -= 1,
                    _ => break,
                }
            }
            let suffix = &formatted_statement[insert_at..trim_len];
            let separator = match suffix.as_bytes().first() {
                Some(b' ' | b'\t' | b'\n' | b'\r') => terminator.to_string(),
                _ => format!("{terminator} "),
            };
            formatted_statement.insert_str(insert_at, &separator);
        } else {
            formatted_statement.insert_str(insert_at, terminator);
        }
    }

    fn normalize_mysql_trigger_terminator_indent(
        formatted_statement: &mut String,
        terminator: &str,
    ) {
        let trim_len = formatted_statement.trim_end().len();
        if trim_len == 0 {
            return;
        }

        let trimmed = &formatted_statement[..trim_len];
        let Some(line_start) = trimmed.rfind('\n').map(|idx| idx + 1).or(Some(0)) else {
            return;
        };
        let line = &trimmed[line_start..];
        let line_trimmed = line.trim_start();
        let Some(prefix) = line_trimmed.get(..3) else {
            return;
        };
        if !prefix.eq_ignore_ascii_case("END") {
            return;
        }
        let rest = &line_trimmed[3..];
        if !rest.starts_with(terminator) {
            return;
        }

        let mut normalized = String::with_capacity(formatted_statement.len());
        normalized.push_str(&trimmed[..line_start]);
        normalized.push_str(line_trimmed);
        normalized.push_str(&formatted_statement[trim_len..]);
        *formatted_statement = normalized;
    }

    fn append_missing_statement_terminator(formatted_statement: &mut String) {
        Self::append_statement_terminator(formatted_statement, ";", false);
    }

    fn split_inline_statement_separators(formatted: &str) -> String {
        if formatted.is_empty() {
            return String::new();
        }

        let spans = super::query_text::tokenize_sql_spanned(formatted);
        let mut split_points: Vec<usize> = Vec::new();

        for (idx, span) in spans.iter().enumerate() {
            if !matches!(&span.token, SqlToken::Symbol(sym) if sym == ";")
                || Self::semicolon_belongs_to_non_sql_line(formatted, span.start)
            {
                continue;
            }

            let line_end = formatted[span.end..]
                .find('\n')
                .map_or(formatted.len(), |offset| span.end + offset);
            let mut split_at = None;

            for next_span in spans.iter().skip(idx.saturating_add(1)) {
                if next_span.start >= line_end {
                    break;
                }

                match &next_span.token {
                    SqlToken::Comment(comment) if comment.contains('\n') => break,
                    SqlToken::Comment(_) => {}
                    _ => {
                        let mut candidate = next_span.start;
                        while candidate > span.end {
                            match formatted.as_bytes().get(candidate.saturating_sub(1)) {
                                Some(b' ' | b'\t') => candidate = candidate.saturating_sub(1),
                                _ => break,
                            }
                        }
                        split_at = Some(candidate.max(span.end));
                        break;
                    }
                }
            }

            if let Some(split_at) = split_at {
                split_points.push(split_at);
            }
        }

        if split_points.is_empty() {
            return formatted.to_string();
        }

        split_points.sort_unstable();
        split_points.dedup();

        let mut out = String::with_capacity(formatted.len().saturating_add(split_points.len()));
        let mut cursor = 0usize;

        for split_at in split_points {
            if split_at <= cursor || split_at > formatted.len() {
                continue;
            }

            out.push_str(&formatted[cursor..split_at]);
            if !out.ends_with('\n') {
                out.push('\n');
            }
            cursor = split_at;
        }

        out.push_str(&formatted[cursor..]);

        out
    }

    #[cfg_attr(not(test), allow(dead_code))]
    pub(crate) fn format_sql_basic(sql: &str) -> String {
        Self::format_sql_basic_with_terminator_policy_for_db_type(sql, true, None)
    }

    #[cfg_attr(not(test), allow(dead_code))]
    pub(crate) fn format_sql_basic_for_db_type(sql: &str, db_type: DatabaseType) -> String {
        Self::format_sql_basic_with_terminator_policy_for_db_type(sql, true, Some(db_type))
    }

    fn normalize_format_items(items: Vec<FormatItem>) -> Vec<FormatItem> {
        let mut normalized: Vec<FormatItem> = Vec::with_capacity(items.len());
        let mut index = 0usize;

        while index < items.len() {
            if let Some((combined, consumed)) =
                Self::merge_fragmented_unterminated_plsql_label(&items, index)
            {
                normalized.push(FormatItem::Statement(combined));
                index += consumed;
                continue;
            }

            if let Some((combined, consumed)) =
                Self::merge_fragmented_with_single_letter_cte(&items, index)
            {
                normalized.push(FormatItem::Statement(combined));
                index += consumed;
                continue;
            }

            let item = items[index].clone();
            let should_merge = match (normalized.last(), &item) {
                (Some(FormatItem::Statement(previous)), FormatItem::Statement(fragment)) => {
                    Self::should_merge_order_modifier_fragment(previous, fragment)
                }
                _ => false,
            };

            if should_merge {
                if let Some(FormatItem::Statement(previous)) = normalized.last_mut() {
                    Self::append_statement_fragment(previous, &item);
                    index += 1;
                    continue;
                }
            }

            normalized.push(item);
            index += 1;
        }

        normalized
    }

    fn merge_fragmented_unterminated_plsql_label(
        items: &[FormatItem],
        start_index: usize,
    ) -> Option<(String, usize)> {
        let head = match items.get(start_index) {
            Some(FormatItem::Statement(statement)) => statement,
            _ => return None,
        };
        let trailing = match items.get(start_index + 1) {
            Some(FormatItem::Statement(statement)) => statement.trim_start(),
            _ => return None,
        };
        if trailing.is_empty() || !Self::statement_has_unterminated_plsql_label(head) {
            return None;
        }

        Some((format!("{}\n{trailing}", head.trim_end()), 2))
    }

    fn statement_has_unterminated_plsql_label(statement: &str) -> bool {
        let tokens = Self::tokenize_sql(statement);
        let mut idx = 0usize;
        let mut open_label_count = 0usize;

        while idx < tokens.len() {
            match tokens.get(idx) {
                Some(SqlToken::Word(word)) => {
                    let opens_label = word.starts_with("<<");
                    let closes_label = word.ends_with(">>");
                    if opens_label {
                        if closes_label && word.len() > 4 {
                            // Fully closed `<<label>>` token.
                        } else {
                            open_label_count = open_label_count.saturating_add(1);
                        }
                    } else if closes_label {
                        open_label_count = open_label_count.saturating_sub(1);
                    }
                }
                Some(SqlToken::Symbol(sym)) if sym == "<<" => {
                    open_label_count = open_label_count.saturating_add(1);
                }
                Some(SqlToken::Symbol(sym)) if sym == ">>" => {
                    open_label_count = open_label_count.saturating_sub(1);
                }
                Some(SqlToken::Symbol(sym)) if sym == "<" => {
                    if matches!(tokens.get(idx + 1), Some(SqlToken::Symbol(next)) if next == "<") {
                        open_label_count = open_label_count.saturating_add(1);
                        idx = idx.saturating_add(1);
                    }
                }
                Some(SqlToken::Symbol(sym)) if sym == ">" => {
                    if matches!(tokens.get(idx + 1), Some(SqlToken::Symbol(next)) if next == ">") {
                        open_label_count = open_label_count.saturating_sub(1);
                        idx = idx.saturating_add(1);
                    }
                }
                _ => {}
            }

            idx = idx.saturating_add(1);
        }

        open_label_count > 0
    }

    fn merge_fragmented_with_single_letter_cte(
        items: &[FormatItem],
        start_index: usize,
    ) -> Option<(String, usize)> {
        let with_head = match items.get(start_index) {
            Some(FormatItem::Statement(statement))
                if statement.trim().eq_ignore_ascii_case("WITH") =>
            {
                statement.trim()
            }
            _ => return None,
        };

        let cte_name = match items.get(start_index + 1) {
            Some(FormatItem::ToolCommand(ToolCommand::Unsupported { raw, .. })) => raw.trim(),
            _ => return None,
        };
        if !Self::is_single_letter_cte_identifier(cte_name) {
            return None;
        }

        let trailing = match items.get(start_index + 2) {
            Some(FormatItem::Statement(statement)) => statement.trim_start(),
            _ => return None,
        };
        if !Self::starts_with_ascii_keyword_token_ci(trailing, "AS") {
            return None;
        }

        Some((format!("{with_head} {cte_name}\n{trailing}"), 3))
    }

    fn is_single_letter_cte_identifier(value: &str) -> bool {
        let mut chars = value.chars();
        let Some(ch) = chars.next() else {
            return false;
        };
        chars.next().is_none() && (ch.is_ascii_alphabetic() || ch == '_')
    }

    fn should_merge_order_modifier_fragment(previous: &str, fragment: &str) -> bool {
        let previous_trimmed = previous.trim_end();
        if previous_trimmed.is_empty()
            || Self::line_ends_with_semicolon_before_inline_comment(previous_trimmed)
        {
            return false;
        }

        let fragment_trimmed = fragment.trim_start();
        if fragment_trimmed.is_empty() {
            return false;
        }

        let starts_order_modifier =
            Self::starts_with_ascii_keyword_token_ci(fragment_trimmed, "ASC")
                || Self::starts_with_ascii_keyword_token_ci(fragment_trimmed, "DESC")
                || Self::starts_with_ascii_keyword_token_ci(fragment_trimmed, "NULLS");
        if !starts_order_modifier {
            return false;
        }

        let previous_search_window =
            Self::tail_search_window(previous_trimmed, 4096).unwrap_or(previous_trimmed);
        Self::contains_ascii_case_insensitive(previous_search_window, "ORDER BY")
            || Self::contains_ascii_case_insensitive(previous_search_window, "ORDER SIBLINGS BY")
    }

    fn starts_with_ascii_keyword_token_ci(text: &str, keyword: &str) -> bool {
        let text_bytes = text.as_bytes();
        let keyword_bytes = keyword.as_bytes();
        if text_bytes.len() < keyword_bytes.len() {
            return false;
        }
        if !text_bytes[..keyword_bytes.len()].eq_ignore_ascii_case(keyword_bytes) {
            return false;
        }

        !text_bytes
            .get(keyword_bytes.len())
            .is_some_and(|next| next.is_ascii_alphanumeric() || *next == b'_')
    }

    fn contains_ascii_case_insensitive(haystack: &str, needle: &str) -> bool {
        let haystack_bytes = haystack.as_bytes();
        let needle_bytes = needle.as_bytes();
        if needle_bytes.is_empty() {
            return true;
        }
        if haystack_bytes.len() < needle_bytes.len() {
            return false;
        }

        haystack_bytes
            .windows(needle_bytes.len())
            .rev()
            .any(|window| window.eq_ignore_ascii_case(needle_bytes))
    }

    fn tail_search_window(text: &str, max_bytes: usize) -> Option<&str> {
        if text.len() <= max_bytes {
            return None;
        }

        let mut start = text.len().saturating_sub(max_bytes);
        while start < text.len() && !text.is_char_boundary(start) {
            start = start.saturating_add(1);
        }
        text.get(start..)
    }

    fn append_statement_fragment(previous: &mut String, item: &FormatItem) {
        let FormatItem::Statement(fragment) = item else {
            return;
        };

        let fragment_trimmed = fragment.trim_start();
        if fragment_trimmed.is_empty() {
            return;
        }

        let needs_space = previous
            .chars()
            .last()
            .is_some_and(|ch| !ch.is_whitespace());
        if needs_space {
            previous.push(' ');
        }
        previous.push_str(fragment_trimmed);
    }

    fn format_result_cache_lookup(
        sql: &str,
        append_missing_terminator: bool,
        preferred_db_type: Option<DatabaseType>,
    ) -> Option<String> {
        let mut cache = format_result_cache_guard();
        let entry_idx = cache.iter().position(|entry| {
            entry.append_missing_terminator == append_missing_terminator
                && entry.preferred_db_type == preferred_db_type
                && entry.input == sql
        })?;
        let entry = cache.remove(entry_idx)?;
        let output = entry.output.clone();
        cache.push_front(entry);
        Some(output)
    }

    fn format_result_cache_store(
        sql: &str,
        formatted: &str,
        append_missing_terminator: bool,
        preferred_db_type: Option<DatabaseType>,
    ) {
        let mut cache = format_result_cache_guard();
        let mut push_entry = |input: &str, output: &str| {
            if let Some(existing_idx) = cache.iter().position(|entry| {
                entry.append_missing_terminator == append_missing_terminator
                    && entry.preferred_db_type == preferred_db_type
                    && entry.input == input
            }) {
                let _ = cache.remove(existing_idx);
            }
            cache.push_front(FormatResultCacheEntry {
                preferred_db_type,
                append_missing_terminator,
                input: input.to_string(),
                output: output.to_string(),
            });
            while cache.len() > FORMAT_RESULT_CACHE_CAPACITY {
                let _ = cache.pop_back();
            }
        };

        push_entry(sql, formatted);
        push_entry(formatted, formatted);
    }

    fn format_sql_basic_for_preferred_db_type(
        sql: &str,
        preferred_db_type: Option<DatabaseType>,
    ) -> String {
        Self::format_sql_basic_with_terminator_policy_for_db_type(sql, true, preferred_db_type)
    }

    fn format_sql_basic_with_terminator_policy_for_db_type(
        sql: &str,
        append_missing_terminator: bool,
        preferred_db_type: Option<DatabaseType>,
    ) -> String {
        if let Some(cached) =
            Self::format_result_cache_lookup(sql, append_missing_terminator, preferred_db_type)
        {
            return cached;
        }

        let mut formatted = String::with_capacity(sql.len().saturating_add(64));
        let items = Self::normalize_format_items(
            super::query_text::split_format_items_for_db_type(sql, preferred_db_type),
        );
        if items.is_empty() {
            return String::new();
        }

        let mut select_list_break_state = SelectListBreakState::None;
        let mut active_mysql_delimiter: Option<String> = None;
        for (idx, item) in items.iter().enumerate() {
            let next_item = items.get(idx + 1);

            match item {
                FormatItem::Statement(statement) => {
                    let mysql_compatible_statement = active_mysql_delimiter.is_some()
                        || sql_text::mysql_compatibility_for_sql(statement, preferred_db_type);
                    let mysql_profile =
                        mysql_compatible_statement && Self::mysql_formatter_profile_enabled();
                    let statement_tokens =
                        Self::tokenize_sql_with_mysql_compat(statement, mysql_compatible_statement);
                    let formatted_statement = Self::profile_mysql_formatter_stage(
                        "format_statement",
                        statement.len(),
                        mysql_profile,
                        || {
                            Self::format_statement(
                                statement,
                                &statement_tokens,
                                select_list_break_state,
                                mysql_compatible_statement,
                            )
                        },
                    );
                    let has_code = Self::statement_has_code(statement, &statement_tokens);
                    let mut formatted_statement = formatted_statement;
                    if let Some(delimiter) = active_mysql_delimiter.as_deref() {
                        Self::append_statement_terminator(
                            &mut formatted_statement,
                            delimiter,
                            true,
                        );
                        if Self::is_create_trigger_statement(statement) {
                            Self::normalize_mysql_trigger_terminator_indent(
                                &mut formatted_statement,
                                delimiter,
                            );
                        }
                    } else if append_missing_terminator
                        && has_code
                        && !Self::statement_ends_with_semicolon_tokens(&statement_tokens)
                        && Self::should_append_missing_statement_terminator(&statement_tokens)
                    {
                        Self::append_missing_statement_terminator(&mut formatted_statement);
                    }
                    formatted.push_str(&formatted_statement);
                }
                FormatItem::ToolCommand(command) => {
                    if let ToolCommand::MysqlDelimiter { delimiter } = command {
                        active_mysql_delimiter = if delimiter == ";" {
                            None
                        } else {
                            Some(delimiter.clone())
                        };
                    }
                    formatted.push_str(&Self::format_tool_command(command));
                    select_list_break_state.clear();
                }
                FormatItem::Verbatim(text) => {
                    formatted.push_str(text);
                    select_list_break_state.clear();
                }
                FormatItem::Slash => {
                    formatted.push('/');
                    select_list_break_state.clear();
                }
            }

            if let Some(next_item) = next_item {
                formatted.push_str(Self::item_separator(item, next_item));
            }
        }

        Self::format_result_cache_store(
            sql,
            &formatted,
            append_missing_terminator,
            preferred_db_type,
        );
        formatted
    }

    fn item_separator(current: &FormatItem, next: &FormatItem) -> &'static str {
        if matches!(next, FormatItem::Slash) || Self::keeps_tight_spacing(current, next) {
            "\n"
        } else {
            "\n\n"
        }
    }

    fn keeps_tight_spacing(current: &FormatItem, next: &FormatItem) -> bool {
        match (current, next) {
            (FormatItem::Statement(left), FormatItem::Statement(right)) => {
                (Self::is_sqlplus_comment_line(left) && Self::is_sqlplus_comment_line(right))
                    || (Self::is_create_trigger_statement(left)
                        && Self::is_alter_trigger_statement(right))
            }
            (FormatItem::Slash, FormatItem::Statement(right)) => {
                Self::is_alter_trigger_statement(right)
            }
            _ if Self::is_prompt_format_item(current) && Self::is_prompt_format_item(next) => true,
            (
                FormatItem::ToolCommand(ToolCommand::ClearBreaks),
                FormatItem::ToolCommand(ToolCommand::ClearComputes),
            )
            | (
                FormatItem::ToolCommand(ToolCommand::ClearComputes),
                FormatItem::ToolCommand(ToolCommand::ClearBreaks),
            ) => true,
            _ => false,
        }
    }

    fn is_prompt_format_item(item: &FormatItem) -> bool {
        match item {
            FormatItem::ToolCommand(ToolCommand::Prompt { .. }) => true,
            FormatItem::Verbatim(text) => QueryExecutor::parse_tool_command(text)
                .is_some_and(|cmd| matches!(cmd, ToolCommand::Prompt { .. })),
            _ => false,
        }
    }

    fn is_sqlplus_comment_line(statement: &str) -> bool {
        crate::sql_text::is_sqlplus_comment_line(statement)
    }

    fn is_create_trigger_statement(statement: &str) -> bool {
        let mut word_idx = 0usize;
        let mut has_trigger_in_prefix = false;

        for token in Self::tokenize_sql(statement) {
            let SqlToken::Word(word) = token else {
                continue;
            };

            if word_idx == 0 && !word.eq_ignore_ascii_case("CREATE") {
                return false;
            }

            if word_idx < 8 && word.eq_ignore_ascii_case("TRIGGER") {
                has_trigger_in_prefix = true;
            }

            word_idx += 1;
        }

        word_idx > 0 && has_trigger_in_prefix
    }

    fn is_mysql_executable_comment_token(comment: &str) -> bool {
        crate::sql_text::is_mysql_executable_comment_start(comment.trim_start().as_bytes(), 0)
    }

    fn is_alter_trigger_statement(statement: &str) -> bool {
        let mut words = Self::tokenize_sql(statement)
            .into_iter()
            .filter_map(|token| match token {
                SqlToken::Word(word) => Some(word),
                _ => None,
            });

        matches!(
            (words.next(), words.next()),
            (Some(first), Some(second))
                if first.eq_ignore_ascii_case("ALTER")
                    && second.eq_ignore_ascii_case("TRIGGER")
        )
    }

    fn statement_has_code(statement: &str, tokens: &[SqlToken]) -> bool {
        let trimmed = statement.trim_start();
        if let Some(first_word) = trimmed.split_whitespace().next() {
            if first_word.eq_ignore_ascii_case("REM") || first_word.eq_ignore_ascii_case("REMARK") {
                return false;
            }
        }

        tokens.iter().any(|token| match token {
            SqlToken::Comment(comment) => Self::is_mysql_executable_comment_token(comment),
            _ => true,
        })
    }

    fn is_mysql_block_label_colon(tokens: &[SqlToken], idx: usize, sym: &str) -> bool {
        if sym != ":" {
            return false;
        }

        let previous = idx.checked_sub(1).and_then(|prev_idx| tokens.get(prev_idx));
        let next = tokens.get(idx + 1);

        matches!(previous, Some(SqlToken::Word(_)))
            && matches!(
                next,
                Some(SqlToken::Word(word))
                    if crate::sql_text::is_mysql_block_label_target(word)
            )
    }

    fn is_mysql_labeled_block_header_word(tokens: &[SqlToken], idx: usize) -> bool {
        tokens
            .get(idx)
            .is_some_and(|token| matches!(token, SqlToken::Word(_)))
            && tokens
                .get(idx.saturating_add(1))
                .is_some_and(|token| matches!(token, SqlToken::Symbol(sym) if sym == ":"))
            && Self::is_mysql_block_label_colon(tokens, idx.saturating_add(1), ":")
    }

    fn is_mysql_labeled_block_target_word(tokens: &[SqlToken], idx: usize) -> bool {
        tokens
            .get(idx)
            .is_some_and(|token| matches!(token, SqlToken::Word(_)))
            && idx.checked_sub(1).is_some_and(|prev_idx| {
                tokens
                    .get(prev_idx)
                    .is_some_and(|token| matches!(token, SqlToken::Symbol(sym) if sym == ":"))
                    && Self::is_mysql_block_label_colon(tokens, prev_idx, ":")
            })
    }

    fn next_meaningful_token_index(tokens: &[SqlToken], start_idx: usize) -> Option<usize> {
        let mut idx = start_idx.saturating_add(1);
        while let Some(token) = tokens.get(idx) {
            if !matches!(token, SqlToken::Comment(_)) {
                return Some(idx);
            }
            idx = idx.saturating_add(1);
        }

        None
    }

    fn previous_meaningful_token_index(tokens: &[SqlToken], start_idx: usize) -> Option<usize> {
        let mut idx = start_idx;
        while idx > 0 {
            idx = idx.saturating_sub(1);
            if !matches!(tokens.get(idx), Some(SqlToken::Comment(_))) {
                return Some(idx);
            }
        }

        None
    }

    fn mysql_identifier_left_boundary_symbol(sym: &str) -> bool {
        matches!(
            sym,
            "(" | ","
                | "."
                | "="
                | "+"
                | "-"
                | "*"
                | "/"
                | "%"
                | "<"
                | ">"
                | "<="
                | ">="
                | "<>"
                | "!="
                | ":="
                | "=>"
        )
    }

    fn mysql_identifier_right_boundary_symbol(sym: &str) -> bool {
        matches!(
            sym,
            ")" | ","
                | "."
                | ";"
                | "="
                | "+"
                | "-"
                | "*"
                | "/"
                | "%"
                | "<"
                | ">"
                | "<="
                | ">="
                | "<>"
                | "!="
                | ":="
                | "=>"
        )
    }

    fn mysql_keyword_must_stay_keyword_in_expression(word: &str) -> bool {
        matches!(
            word,
            "AND"
                | "BETWEEN"
                | "CASE"
                | "DIV"
                | "ELSE"
                | "END"
                | "EXISTS"
                | "FALSE"
                | "IN"
                | "INTERVAL"
                | "IS"
                | "LIKE"
                | "LIKE2"
                | "LIKE4"
                | "LIKEC"
                | "MOD"
                | "NOT"
                | "NULL"
                | "OR"
                | "REGEXP"
                | "RLIKE"
                | "THEN"
                | "TRUE"
                | "WHEN"
        )
    }

    fn mysql_formatter_keyword(word: &str) -> bool {
        sql_text::is_oracle_sql_keyword(word) || sql_text::is_mysql_sql_keyword(word)
    }

    fn mysql_keyword_should_render_as_identifier(
        tokens: &[SqlToken],
        idx: usize,
        current_clause: Option<&str>,
        on_duplicate_key_update_active: bool,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
    ) -> bool {
        let Some(SqlToken::Word(word)) = tokens.get(idx) else {
            return false;
        };
        if !word.bytes().any(|byte| byte.is_ascii_lowercase()) {
            return false;
        }

        let upper = word.to_ascii_uppercase();
        if !Self::mysql_formatter_keyword(upper.as_str()) {
            return false;
        }
        if Self::mysql_keyword_must_stay_keyword_in_expression(upper.as_str()) {
            return false;
        }

        let prev_idx = meaningful_token_links
            .and_then(|links| links.prev_index(idx))
            .or_else(|| Self::previous_meaningful_token_index(tokens, idx));
        let next_idx = meaningful_token_links
            .and_then(|links| links.next_index(idx))
            .or_else(|| Self::next_meaningful_token_index(tokens, idx));
        let prev_token = prev_idx.and_then(|prev_idx| tokens.get(prev_idx));
        let next_token = next_idx.and_then(|next_idx| tokens.get(next_idx));
        let next_is_open_paren = matches!(next_token, Some(SqlToken::Symbol(sym)) if sym == "(");

        if next_is_open_paren && Self::mysql_keyword_prefers_space_before_paren(upper.as_str()) {
            return upper == "VALUES" && on_duplicate_key_update_active;
        }

        let prev_is_boundary = matches!(
            prev_token,
            Some(SqlToken::Symbol(sym)) if Self::mysql_identifier_left_boundary_symbol(sym)
        );
        let next_is_boundary = matches!(
            next_token,
            Some(SqlToken::Symbol(sym)) if Self::mysql_identifier_right_boundary_symbol(sym)
        ) || next_token.is_none();
        let previous_is_current_clause_head = matches!(
            (prev_token, current_clause),
            (Some(SqlToken::Word(prev_word)), Some(current_clause_word))
                if prev_word.eq_ignore_ascii_case(current_clause_word)
        );
        let follows_alias_keyword = matches!(
            prev_token,
            Some(SqlToken::Word(prev_word)) if prev_word.eq_ignore_ascii_case("AS")
                || prev_word.eq_ignore_ascii_case("IS")
        );
        let next_is_alias_keyword = matches!(
            next_token,
            Some(SqlToken::Word(next_word))
                if next_word.eq_ignore_ascii_case("AS") || next_word.eq_ignore_ascii_case("IS")
        );
        let next_is_clause_keyword = matches!(
            next_token,
            Some(SqlToken::Word(next_word))
                if Self::is_dml_clause_starter(next_word.to_ascii_uppercase().as_str())
                    || crate::sql_text::is_format_set_operator_keyword(
                        next_word.to_ascii_uppercase().as_str(),
                    )
        );
        let in_select_clause = matches!(current_clause, Some("SELECT"));
        let in_table_alias_clause = matches!(
            current_clause,
            Some("FROM" | "UPDATE" | "DELETE" | "INTO" | "MERGE" | "USING")
        );

        if matches!(
            current_clause,
            Some("SELECT" | "WHERE" | "HAVING" | "ON" | "SET" | "GROUP" | "ORDER")
        ) && (prev_is_boundary || previous_is_current_clause_head)
            && (next_is_boundary || next_is_clause_keyword || next_is_alias_keyword)
        {
            return true;
        }

        if follows_alias_keyword {
            return true;
        }

        if (in_select_clause || in_table_alias_clause)
            && !prev_is_boundary
            && !previous_is_current_clause_head
            && (next_is_boundary || next_is_clause_keyword)
        {
            return true;
        }

        prev_is_boundary && next_is_boundary
    }

    fn count_star_call_should_stay_tight(
        tokens: &[SqlToken],
        open_paren_idx: usize,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let prev_word_idx = statement_word_links
            .and_then(|links| links.prev_word_index(open_paren_idx))
            .or_else(|| Self::previous_word_upper(tokens, open_paren_idx).map(|(_, idx)| idx));
        let Some(prev_word) = prev_word_idx
            .and_then(|idx| tokens.get(idx))
            .and_then(|token| match token {
                SqlToken::Word(word) => Some(word.as_str()),
                _ => None,
            })
        else {
            return false;
        };
        if !prev_word.eq_ignore_ascii_case("COUNT") {
            return false;
        }

        let Some(star_idx) = meaningful_token_links
            .and_then(|links| links.next_index(open_paren_idx))
            .or_else(|| Self::next_meaningful_token_index(tokens, open_paren_idx))
        else {
            return false;
        };
        let Some(close_idx) = meaningful_token_links
            .and_then(|links| links.next_index(star_idx))
            .or_else(|| Self::next_meaningful_token_index(tokens, star_idx))
        else {
            return false;
        };

        matches!(tokens.get(star_idx), Some(SqlToken::Symbol(sym)) if sym == "*")
            && matches!(tokens.get(close_idx), Some(SqlToken::Symbol(sym)) if sym == ")")
    }

    fn mysql_keyword_prefers_space_before_paren(word: &str) -> bool {
        matches!(
            word,
            "ALL"
                | "AND"
                | "AS"
                | "BEGIN"
                | "BETWEEN"
                | "BY"
                | "CASE"
                | "CHECK"
                | "ELSE"
                | "ELSEIF"
                | "ELSIF"
                | "EXISTS"
                | "FOR"
                | "FROM"
                | "GROUP"
                | "HAVING"
                | "IF"
                | "IN"
                | "INTO"
                | "JOIN"
                | "KEY"
                | "LIMIT"
                | "NOT"
                | "ON"
                | "OR"
                | "ORDER"
                | "OVER"
                | "PARTITION"
                | "PRIMARY"
                | "REFERENCES"
                | "REPEAT"
                | "RETURN"
                | "RETURNS"
                | "SELECT"
                | "SET"
                | "TABLE"
                | "THEN"
                | "UNIQUE"
                | "UNTIL"
                | "USING"
                | "VALUES"
                | "WHEN"
                | "WHERE"
                | "WHILE"
                | "WINDOW"
        )
    }

    fn mysql_paren_belongs_to_insert_target_column_list(
        tokens: &[SqlToken],
        open_paren_idx: usize,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let mut has_into = false;
        let mut has_insert_or_replace = false;

        Self::scan_recent_statement_words(
            tokens,
            open_paren_idx,
            6,
            statement_word_links,
            |word, pos| {
                if pos > 0 && word.eq_ignore_ascii_case("INTO") {
                    has_into = true;
                }
                if word.eq_ignore_ascii_case("INSERT") || word.eq_ignore_ascii_case("REPLACE") {
                    has_insert_or_replace = true;
                }
                !(has_into && has_insert_or_replace)
            },
        );

        has_into && has_insert_or_replace
    }

    fn mysql_paren_follows_named_key_definition(
        tokens: &[SqlToken],
        open_paren_idx: usize,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let prev_word_idx = statement_word_links
            .and_then(|links| links.prev_word_index(open_paren_idx))
            .or_else(|| Self::previous_word_upper(tokens, open_paren_idx).map(|(_, idx)| idx));
        let Some(prev_word_idx) = prev_word_idx else {
            return false;
        };
        let Some(key_idx) = meaningful_token_links
            .and_then(|links| links.prev_index(prev_word_idx))
            .or_else(|| Self::previous_meaningful_token_index(tokens, prev_word_idx))
        else {
            return false;
        };
        let Some(SqlToken::Word(key_word)) = tokens.get(key_idx) else {
            return false;
        };
        if !key_word.eq_ignore_ascii_case("KEY") && !key_word.eq_ignore_ascii_case("INDEX") {
            return false;
        }
        true
    }

    fn mysql_word_paren_should_stay_tight(
        tokens: &[SqlToken],
        open_paren_idx: usize,
        on_duplicate_key_update_active: bool,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
        statement_word_links: Option<&StatementWordLinks>,
        matching_paren_close_indices: Option<&[Option<usize>]>,
    ) -> bool {
        let prev_word_idx = statement_word_links
            .and_then(|links| links.prev_word_index(open_paren_idx))
            .or_else(|| Self::previous_word_upper(tokens, open_paren_idx).map(|(_, idx)| idx));
        let Some(prev_word_idx) = prev_word_idx else {
            return false;
        };
        let Some(prev_word) = tokens.get(prev_word_idx).and_then(|token| match token {
            SqlToken::Word(word) => Some(word.to_ascii_uppercase()),
            _ => None,
        }) else {
            return false;
        };
        let prev_word = prev_word.as_str();

        let prev_meaningful_idx = meaningful_token_links
            .and_then(|links| links.prev_index(open_paren_idx))
            .or_else(|| Self::previous_meaningful_token_index(tokens, open_paren_idx));
        let Some(prev_meaningful_idx) = prev_meaningful_idx else {
            return false;
        };

        // Tight MySQL word-paren spacing is only valid when the immediate token
        // before `(` is the callee/type word itself. If an operator/symbol sits
        // between the nearest word and `(` (e.g. `x = (` or `a + (`), preserve
        // normal operator spacing.
        if prev_meaningful_idx != prev_word_idx {
            return false;
        }

        if prev_word == "IF"
            && Self::mysql_if_is_scalar_function(
                tokens,
                prev_meaningful_idx,
                meaningful_token_links,
                matching_paren_close_indices,
            )
        {
            return true;
        }

        if prev_word == "VALUES" {
            return on_duplicate_key_update_active;
        }

        if Self::mysql_keyword_prefers_space_before_paren(prev_word) {
            return false;
        }

        let insert_target_column_list = Self::mysql_paren_belongs_to_insert_target_column_list(
            tokens,
            open_paren_idx,
            statement_word_links,
        );
        if Self::mysql_paren_follows_named_key_definition(
            tokens,
            open_paren_idx,
            meaningful_token_links,
            statement_word_links,
        ) {
            return false;
        }
        if Self::paren_opens_call_argument_list(tokens, open_paren_idx, statement_word_links)
            || insert_target_column_list
        {
            return !insert_target_column_list;
        }

        true
    }

    fn mysql_if_is_scalar_function(
        tokens: &[SqlToken],
        if_idx: usize,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
        matching_paren_close_indices: Option<&[Option<usize>]>,
    ) -> bool {
        let open_idx = meaningful_token_links
            .and_then(|links| links.next_index(if_idx))
            .or_else(|| Self::next_meaningful_token_index(tokens, if_idx));
        let Some(open_idx) = open_idx else {
            return false;
        };
        if !matches!(tokens.get(open_idx), Some(SqlToken::Symbol(sym)) if sym == "(") {
            return false;
        }

        let Some(close_idx) =
            Self::matching_paren_close_index(tokens, open_idx, matching_paren_close_indices)
        else {
            return false;
        };
        !matches!(
            meaningful_token_links
                .and_then(|links| links.next_index(close_idx))
                .or_else(|| Self::next_meaningful_token_index(tokens, close_idx))
                .and_then(|idx| tokens.get(idx)),
            Some(SqlToken::Word(word)) if word.eq_ignore_ascii_case("THEN")
        )
    }

    fn matching_paren_close_index(
        tokens: &[SqlToken],
        open_idx: usize,
        matching_paren_close_indices: Option<&[Option<usize>]>,
    ) -> Option<usize> {
        if let Some(close_idx) = matching_paren_close_indices
            .and_then(|indices| indices.get(open_idx))
            .copied()
            .flatten()
        {
            return Some(close_idx);
        }
        if !matches!(tokens.get(open_idx), Some(SqlToken::Symbol(sym)) if sym == "(") {
            return None;
        }

        let mut depth = 0usize;
        for (idx, token) in tokens.iter().enumerate().skip(open_idx) {
            match token {
                SqlToken::Symbol(sym) if sym == "(" => {
                    depth = depth.saturating_add(1);
                }
                SqlToken::Symbol(sym) if sym == ")" => {
                    depth = depth.saturating_sub(1);
                    if depth == 0 {
                        return Some(idx);
                    }
                }
                _ => {}
            }
        }

        None
    }

    fn paren_opens_call_argument_list(
        tokens: &[SqlToken],
        open_idx: usize,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let mut second_recent_is_call = false;
        Self::scan_recent_statement_words(
            tokens,
            open_idx,
            2,
            statement_word_links,
            |word, pos| {
                if pos == 1 && word.eq_ignore_ascii_case("CALL") {
                    second_recent_is_call = true;
                    return false;
                }
                true
            },
        );
        second_recent_is_call
    }

    fn scan_recent_statement_words<F>(
        tokens: &[SqlToken],
        idx: usize,
        max_words: usize,
        statement_word_links: Option<&StatementWordLinks>,
        mut visitor: F,
    ) where
        F: FnMut(&str, usize) -> bool,
    {
        if max_words == 0 {
            return;
        }

        if let Some(links) = statement_word_links {
            let mut seen = 0usize;
            let mut word_idx = links.prev_word_index(idx);
            while let Some(current_word_idx) = word_idx {
                let Some(SqlToken::Word(word)) = tokens.get(current_word_idx) else {
                    break;
                };
                if !visitor(word.as_str(), seen) {
                    break;
                }
                seen = seen.saturating_add(1);
                if seen >= max_words {
                    break;
                }
                word_idx = links.prev_word_index(current_word_idx);
            }
            return;
        }

        let capped_idx = idx.min(tokens.len());
        let mut seen = 0usize;
        for token in tokens[..capped_idx].iter().rev() {
            match token {
                SqlToken::Symbol(sym) if sym == ";" => break,
                SqlToken::Word(word) => {
                    if !visitor(word.as_str(), seen) {
                        break;
                    }
                    seen = seen.saturating_add(1);
                    if seen >= max_words {
                        break;
                    }
                }
                _ => {}
            }
        }
    }

    fn recent_statement_words_before<'a>(
        tokens: &'a [SqlToken],
        idx: usize,
        max_words: usize,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> Vec<&'a str> {
        if let Some(links) = statement_word_links {
            let mut words = Vec::with_capacity(max_words);
            let mut word_idx = links.prev_word_index(idx);
            while let Some(current_word_idx) = word_idx {
                let Some(SqlToken::Word(word)) = tokens.get(current_word_idx) else {
                    break;
                };
                words.push(word.as_str());
                if words.len() >= max_words {
                    break;
                }
                word_idx = links.prev_word_index(current_word_idx);
            }
            return words;
        }

        let capped_idx = idx.min(tokens.len());
        let mut words = Vec::with_capacity(max_words);
        for token in tokens[..capped_idx].iter().rev() {
            match token {
                SqlToken::Symbol(sym) if sym == ";" => break,
                SqlToken::Word(word) => {
                    words.push(word.as_str());
                    if words.len() >= max_words {
                        break;
                    }
                }
                _ => {}
            }
        }

        words
    }

    fn is_mysql_declare_cursor_for_clause(
        tokens: &[SqlToken],
        idx: usize,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let mut has_declare = false;
        let mut has_cursor = false;
        Self::scan_recent_statement_words(tokens, idx, 6, statement_word_links, |word, _| {
            if word.eq_ignore_ascii_case("DECLARE") {
                has_declare = true;
            } else if word.eq_ignore_ascii_case("CURSOR") {
                has_cursor = true;
            }
            !(has_declare && has_cursor)
        });
        has_declare && has_cursor
    }

    fn is_mysql_declare_handler_for_clause(
        tokens: &[SqlToken],
        idx: usize,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let mut has_declare = false;
        let mut has_handler = false;
        Self::scan_recent_statement_words(tokens, idx, 6, statement_word_links, |word, _| {
            if word.eq_ignore_ascii_case("DECLARE") {
                has_declare = true;
            } else if word.eq_ignore_ascii_case("HANDLER") {
                has_handler = true;
            }
            !(has_declare && has_handler)
        });
        has_declare && has_handler
    }

    fn is_mysql_if_exists_modifier(
        tokens: &[SqlToken],
        idx: usize,
        next_word: Option<&str>,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        if !matches!(
            next_word,
            Some(word) if word.eq_ignore_ascii_case("EXISTS") || word.eq_ignore_ascii_case("NOT")
        ) {
            return false;
        }

        let mut has_ddl_verb = false;
        Self::scan_recent_statement_words(tokens, idx, 6, statement_word_links, |word, _| {
            if word.eq_ignore_ascii_case("DROP")
                || word.eq_ignore_ascii_case("CREATE")
                || word.eq_ignore_ascii_case("ALTER")
            {
                has_ddl_verb = true;
                return false;
            }
            true
        });
        has_ddl_verb
    }

    /// Returns true when SET is a sub-clause of a MySQL SIGNAL/RESIGNAL statement.
    /// In MySQL, SIGNAL SQLSTATE '...' SET MESSAGE_TEXT = ... has SET as a
    /// continuation of the SIGNAL statement, not a new independent clause.
    fn is_mysql_signal_set_clause(
        tokens: &[SqlToken],
        idx: usize,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let mut has_signal = false;
        Self::scan_recent_statement_words(tokens, idx, 8, statement_word_links, |word, _| {
            if word.eq_ignore_ascii_case("SIGNAL") || word.eq_ignore_ascii_case("RESIGNAL") {
                has_signal = true;
                return false;
            }
            true
        });
        has_signal
    }

    /// Returns true when UPDATE is the keyword following ON DUPLICATE KEY,
    /// forming MySQL's ON DUPLICATE KEY UPDATE clause.
    fn is_mysql_on_duplicate_key_update(
        tokens: &[SqlToken],
        idx: usize,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let mut first_is_key = false;
        let mut second_is_duplicate = false;
        let mut third_is_on = false;
        Self::scan_recent_statement_words(tokens, idx, 3, statement_word_links, |word, pos| {
            match pos {
                0 => first_is_key = word.eq_ignore_ascii_case("KEY"),
                1 => second_is_duplicate = word.eq_ignore_ascii_case("DUPLICATE"),
                2 => third_is_on = word.eq_ignore_ascii_case("ON"),
                _ => {}
            }
            true
        });
        first_is_key && second_is_duplicate && third_is_on
    }

    fn is_sqlplus_remark_comment_statement(statement: &str) -> bool {
        statement
            .split_whitespace()
            .next()
            .is_some_and(|first_word| {
                first_word.eq_ignore_ascii_case("REM") || first_word.eq_ignore_ascii_case("REMARK")
            })
    }

    fn source_has_explicit_semicolon_terminator(statement: &str) -> bool {
        let trimmed = statement.trim_end();
        if trimmed.is_empty() {
            return false;
        }

        let spans = super::query_text::tokenize_sql_spanned(trimmed);
        spans.iter().rev().any(|span| {
            matches!(&span.token, SqlToken::Symbol(sym) if sym == ";")
                && !Self::semicolon_belongs_to_non_sql_line(trimmed, span.start)
                && Self::trailing_segment_allows_semicolon_terminator(&trimmed[span.end..])
        })
    }

    fn semicolon_belongs_to_non_sql_line(statement: &str, semicolon_start: usize) -> bool {
        let line_start = statement[..semicolon_start]
            .rfind('\n')
            .map_or(0, |idx| idx + 1);
        let line_end = statement[semicolon_start..]
            .find('\n')
            .map_or(statement.len(), |idx| semicolon_start + idx);
        let line = statement[line_start..line_end].trim();

        if line.starts_with("--")
            || line.starts_with('#')
            || Self::is_sqlplus_remark_comment_statement(line)
        {
            return true;
        }

        QueryExecutor::parse_tool_command(line)
            .is_some_and(|command| !matches!(command, ToolCommand::Unsupported { .. }))
    }

    fn trailing_segment_allows_semicolon_terminator(suffix: &str) -> bool {
        let mut rest = suffix.trim_start();
        if rest.is_empty() {
            return true;
        }

        loop {
            let line_end = rest.find('\n').unwrap_or(rest.len());
            let line = rest[..line_end].trim();

            if line.is_empty() {
                rest = rest[line_end..].trim_start();
                if rest.is_empty() {
                    return true;
                }
                continue;
            }

            if line == "/" {
                rest = rest[line_end..].trim_start();
                if rest.is_empty() {
                    return true;
                }
                continue;
            }

            if line.starts_with("--")
                || line.starts_with('#')
                || Self::is_sqlplus_remark_comment_statement(line)
            {
                rest = rest[line_end..].trim_start();
                if rest.is_empty() {
                    return true;
                }
                continue;
            }

            return false;
        }
    }

    #[cfg(test)]
    fn statement_ends_with_semicolon(statement: &str) -> bool {
        let tokens = Self::tokenize_sql(statement);
        if Self::statement_ends_with_semicolon_tokens(&tokens) {
            return true;
        }

        let trimmed = statement.trim_end();
        if trimmed.is_empty() {
            return false;
        }

        let spans = super::query_text::tokenize_sql_spanned(trimmed);
        spans
            .iter()
            .rev()
            .find(|span| matches!(&span.token, SqlToken::Symbol(sym) if sym == ";"))
            .is_some_and(|span| {
                Self::trailing_segment_allows_semicolon_terminator(&trimmed[span.end..])
            })
    }

    fn statement_ends_with_semicolon_tokens(tokens: &[SqlToken]) -> bool {
        let mut saw_sqlplus_slash = false;
        for token in tokens.iter().rev() {
            match token {
                SqlToken::Comment(_) => continue,
                SqlToken::Symbol(sym) if sym == "/" => {
                    saw_sqlplus_slash = true;
                }
                SqlToken::Symbol(sym) if sym == ";" => return true,
                _ => return saw_sqlplus_slash,
            }
        }
        false
    }

    fn should_append_missing_statement_terminator(tokens: &[SqlToken]) -> bool {
        let trailing_tokens = Self::tokens_after_last_semicolon(tokens);
        if !Self::delimiter_pairs_are_balanced(trailing_tokens) {
            return false;
        }

        let mut trailing_token = None;

        for token in trailing_tokens.iter().rev() {
            match token {
                SqlToken::Comment(comment) if !Self::is_mysql_executable_comment_token(comment) => {
                    continue;
                }
                SqlToken::Symbol(sym) if sym == "/" => continue,
                other => {
                    trailing_token = Some(other);
                    break;
                }
            }
        }

        trailing_token.is_some_and(Self::token_can_terminate_statement)
    }

    fn tokens_after_last_semicolon(tokens: &[SqlToken]) -> &[SqlToken] {
        let mut last_semicolon_idx = None;

        for (idx, token) in tokens.iter().enumerate() {
            if matches!(token, SqlToken::Symbol(sym) if sym == ";") {
                last_semicolon_idx = Some(idx);
            }
        }

        if let Some(semicolon_idx) = last_semicolon_idx {
            &tokens[semicolon_idx.saturating_add(1)..]
        } else {
            tokens
        }
    }

    fn delimiter_pairs_are_balanced(tokens: &[SqlToken]) -> bool {
        let mut paren_depth = 0usize;
        let mut bracket_depth = 0usize;

        for token in tokens {
            let SqlToken::Symbol(symbol) = token else {
                continue;
            };

            match symbol.as_str() {
                "(" => paren_depth = paren_depth.saturating_add(1),
                ")" => {
                    if paren_depth == 0 {
                        return false;
                    }
                    paren_depth -= 1;
                }
                "[" => bracket_depth = bracket_depth.saturating_add(1),
                "]" => {
                    if bracket_depth == 0 {
                        return false;
                    }
                    bracket_depth -= 1;
                }
                _ => {}
            }
        }

        paren_depth == 0 && bracket_depth == 0
    }

    fn token_can_terminate_statement(token: &SqlToken) -> bool {
        match token {
            SqlToken::Word(word) => Self::word_token_can_terminate_statement(word),
            SqlToken::String(literal) => Self::string_token_can_terminate_statement(literal),
            SqlToken::Symbol(symbol) => matches!(symbol.as_str(), ")" | "]"),
            SqlToken::Comment(comment) => Self::is_mysql_executable_comment_token(comment),
        }
    }

    fn word_token_can_terminate_statement(word: &str) -> bool {
        if word.starts_with('"') {
            return word.ends_with('"') && word.len() > 1;
        }

        if word.starts_with("<<") {
            return word.ends_with(">>") && word.len() > 3;
        }

        true
    }

    fn string_token_can_terminate_statement(literal: &str) -> bool {
        if literal.starts_with('$') {
            return Self::has_closed_dollar_quote(literal);
        }

        literal.ends_with('\'') && literal.len() > 1
    }

    fn has_closed_dollar_quote(literal: &str) -> bool {
        let bytes = literal.as_bytes();
        if bytes.first().copied() != Some(b'$') {
            return false;
        }

        let close_tag_idx =
            bytes.iter().enumerate().skip(1).find_map(
                |(idx, byte)| {
                    if *byte == b'$' {
                        Some(idx)
                    } else {
                        None
                    }
                },
            );

        let Some(close_tag_idx) = close_tag_idx else {
            return false;
        };

        let tag_end = close_tag_idx + 1;
        let Some(tag) = literal.get(..tag_end) else {
            return false;
        };

        literal.len() >= tag.len().saturating_mul(2) && literal.ends_with(tag)
    }

    fn classify_comment_attachment(
        out: &str,
        at_line_start: bool,
        has_leading_newline: bool,
        is_multiline_block_comment: bool,
    ) -> CommentAttachment {
        if out.trim().is_empty() {
            return CommentAttachment::FileHeader;
        }

        if has_leading_newline {
            return CommentAttachment::Next;
        }

        if at_line_start {
            if is_multiline_block_comment {
                CommentAttachment::Block
            } else {
                CommentAttachment::Next
            }
        } else {
            CommentAttachment::Previous
        }
    }

    fn mysql_identifier_requires_quotes(segment: &str) -> bool {
        if segment.is_empty() {
            return true;
        }

        let mut chars = segment.chars();
        let Some(first) = chars.next() else {
            return true;
        };

        if first.is_ascii_digit() || !(first.is_ascii_alphabetic() || matches!(first, '_' | '$')) {
            return true;
        }

        if chars.any(|ch| !(ch.is_ascii_alphanumeric() || matches!(ch, '_' | '$'))) {
            return true;
        }

        sql_text::is_mysql_sql_keyword(&segment.to_ascii_uppercase())
    }

    fn quote_mysql_identifier(identifier: &str) -> String {
        format!("`{}`", identifier.replace('`', "``"))
    }

    fn format_mysql_identifier(identifier: &str) -> String {
        let trimmed = identifier.trim();
        if trimmed.is_empty() {
            return String::new();
        }

        if trimmed.contains('`') || trimmed.contains('"') || trimmed.contains('\'') {
            return trimmed.to_string();
        }

        if trimmed.contains('.') {
            return trimmed
                .split('.')
                .map(|segment| {
                    if Self::mysql_identifier_requires_quotes(segment) {
                        Self::quote_mysql_identifier(segment)
                    } else {
                        segment.to_string()
                    }
                })
                .collect::<Vec<_>>()
                .join(".");
        }

        if Self::mysql_identifier_requires_quotes(trimmed) {
            Self::quote_mysql_identifier(trimmed)
        } else {
            trimmed.to_string()
        }
    }

    pub(super) fn format_tool_command(command: &ToolCommand) -> String {
        match command {
            ToolCommand::Var { name, data_type } => {
                format!("VAR {} {}", name, data_type.display())
            }
            ToolCommand::Print { name } => match name {
                Some(name) => format!("PRINT {}", name),
                None => "PRINT".to_string(),
            },
            ToolCommand::SetServerOutput {
                enabled,
                size,
                unlimited,
            } => {
                if !*enabled {
                    "SET SERVEROUTPUT OFF".to_string()
                } else if *unlimited {
                    "SET SERVEROUTPUT ON SIZE UNLIMITED".to_string()
                } else if let Some(size) = size {
                    format!("SET SERVEROUTPUT ON SIZE {}", size)
                } else {
                    "SET SERVEROUTPUT ON".to_string()
                }
            }
            ToolCommand::ShowErrors {
                object_type,
                object_name,
            } => {
                if let (Some(obj_type), Some(obj_name)) = (object_type, object_name) {
                    format!("SHOW ERRORS {} {}", obj_type, obj_name)
                } else {
                    "SHOW ERRORS".to_string()
                }
            }
            ToolCommand::ShowUser => "SHOW USER".to_string(),
            ToolCommand::ShowAll => "SHOW ALL".to_string(),
            ToolCommand::Describe { name } => format!("DESCRIBE {}", name),
            ToolCommand::Prompt { text } => {
                if text.trim().is_empty() {
                    "PROMPT".to_string()
                } else {
                    format!("PROMPT {}", text)
                }
            }
            ToolCommand::Pause { message } => match message {
                Some(text) if !text.trim().is_empty() => format!("PAUSE {}", text),
                _ => "PAUSE".to_string(),
            },
            ToolCommand::Accept { name, prompt } => match prompt {
                Some(text) => {
                    format!(
                        "ACCEPT {} PROMPT '{}'",
                        name,
                        Self::escape_sql_literal(text)
                    )
                }
                None => format!("ACCEPT {}", name),
            },
            ToolCommand::Define { name, value } => format!("DEFINE {} = {}", name, value),
            ToolCommand::Undefine { name } => format!("UNDEFINE {}", name),
            ToolCommand::ColumnNewValue {
                column_name,
                variable_name,
            } => format!("COLUMN {} NEW_VALUE {}", column_name, variable_name),
            ToolCommand::BreakOn { column_name } => format!("BREAK ON {}", column_name),
            ToolCommand::BreakOff => "BREAK OFF".to_string(),
            ToolCommand::ClearBreaks => "CLEAR BREAKS".to_string(),
            ToolCommand::ClearComputes => "CLEAR COMPUTES".to_string(),
            ToolCommand::ClearBreaksComputes => "CLEAR BREAKS\nCLEAR COMPUTES".to_string(),
            ToolCommand::Compute {
                mode,
                of_column,
                on_column,
            } => {
                let mode_text = match mode {
                    crate::db::ComputeMode::Sum => "SUM",
                    crate::db::ComputeMode::Count => "COUNT",
                };
                match (of_column.as_deref(), on_column.as_deref()) {
                    (Some(of_col), Some(on_col)) => {
                        format!("COMPUTE {} OF {} ON {}", mode_text, of_col, on_col)
                    }
                    _ => format!("COMPUTE {}", mode_text),
                }
            }
            ToolCommand::ComputeOff => "COMPUTE OFF".to_string(),
            ToolCommand::SetErrorContinue { enabled } => {
                if *enabled {
                    "SET ERRORCONTINUE ON".to_string()
                } else {
                    "SET ERRORCONTINUE OFF".to_string()
                }
            }
            ToolCommand::SetAutoCommit { enabled } => {
                if *enabled {
                    "SET AUTOCOMMIT ON".to_string()
                } else {
                    "SET AUTOCOMMIT OFF".to_string()
                }
            }
            ToolCommand::SetDefine {
                enabled,
                define_char,
            } => {
                if let Some(ch) = define_char {
                    format!("SET DEFINE '{}'", ch)
                } else if *enabled {
                    "SET DEFINE ON".to_string()
                } else {
                    "SET DEFINE OFF".to_string()
                }
            }
            ToolCommand::SetScan { enabled } => {
                if *enabled {
                    "SET SCAN ON".to_string()
                } else {
                    "SET SCAN OFF".to_string()
                }
            }
            ToolCommand::SetVerify { enabled } => {
                if *enabled {
                    "SET VERIFY ON".to_string()
                } else {
                    "SET VERIFY OFF".to_string()
                }
            }
            ToolCommand::SetEcho { enabled } => {
                if *enabled {
                    "SET ECHO ON".to_string()
                } else {
                    "SET ECHO OFF".to_string()
                }
            }
            ToolCommand::SetTiming { enabled } => {
                if *enabled {
                    "SET TIMING ON".to_string()
                } else {
                    "SET TIMING OFF".to_string()
                }
            }
            ToolCommand::SetFeedback { enabled } => {
                if *enabled {
                    "SET FEEDBACK ON".to_string()
                } else {
                    "SET FEEDBACK OFF".to_string()
                }
            }
            ToolCommand::SetHeading { enabled } => {
                if *enabled {
                    "SET HEADING ON".to_string()
                } else {
                    "SET HEADING OFF".to_string()
                }
            }
            ToolCommand::SetPageSize { size } => format!("SET PAGESIZE {}", size),
            ToolCommand::SetLineSize { size } => format!("SET LINESIZE {}", size),
            ToolCommand::SetTrimSpool { enabled } => {
                if *enabled {
                    "SET TRIMSPOOL ON".to_string()
                } else {
                    "SET TRIMSPOOL OFF".to_string()
                }
            }
            ToolCommand::SetTrimOut { enabled } => {
                if *enabled {
                    "SET TRIMOUT ON".to_string()
                } else {
                    "SET TRIMOUT OFF".to_string()
                }
            }
            ToolCommand::SetSqlBlankLines { enabled } => {
                if *enabled {
                    "SET SQLBLANKLINES ON".to_string()
                } else {
                    "SET SQLBLANKLINES OFF".to_string()
                }
            }
            ToolCommand::SetTab { enabled } => {
                if *enabled {
                    "SET TAB ON".to_string()
                } else {
                    "SET TAB OFF".to_string()
                }
            }
            ToolCommand::SetColSep { separator } => format!("SET COLSEP {}", separator),
            ToolCommand::SetNull { null_text } => format!("SET NULL {}", null_text),
            ToolCommand::Spool { path, append } => match path {
                Some(path) if *append => format!("SPOOL {} APPEND", path),
                Some(path) => format!("SPOOL {}", path),
                None if *append => "SPOOL APPEND".to_string(),
                None => "SPOOL OFF".to_string(),
            },
            ToolCommand::WheneverSqlError { exit, action } => {
                let mode = if *exit { "EXIT" } else { "CONTINUE" };
                match action.as_deref() {
                    Some(extra) if !extra.trim().is_empty() => {
                        format!("WHENEVER SQLERROR {} {}", mode, extra.trim())
                    }
                    _ => format!("WHENEVER SQLERROR {}", mode),
                }
            }
            ToolCommand::WheneverOsError { exit } => {
                if *exit {
                    "WHENEVER OSERROR EXIT".to_string()
                } else {
                    "WHENEVER OSERROR CONTINUE".to_string()
                }
            }
            ToolCommand::Exit => "EXIT".to_string(),
            ToolCommand::Quit => "QUIT".to_string(),
            ToolCommand::RunScript {
                path,
                relative_to_caller,
            } => {
                if *relative_to_caller {
                    format!("@@{}", path)
                } else {
                    format!("@{}", path)
                }
            }
            ToolCommand::Connect {
                username,
                password,
                host,
                port,
                service_name,
            } => {
                // 자동 포맷팅 결과를 AI(Codex/Claude)가 재마스킹하지 않도록 실제 비밀번호를 그대로 유지한다.
                format!(
                    "CONNECT {}/{}@{}:{}/{}",
                    username, password, host, port, service_name
                )
            }
            ToolCommand::Disconnect => "DISCONNECT".to_string(),
            // MySQL-specific commands — format as-is
            ToolCommand::Use { database } => {
                format!("USE {};", Self::format_mysql_identifier(database))
            }
            ToolCommand::ShowDatabases => "SHOW DATABASES".to_string(),
            ToolCommand::ShowTables => "SHOW TABLES".to_string(),
            ToolCommand::ShowColumns { table, schema } => match schema {
                Some(schema_name) => {
                    format!(
                        "SHOW COLUMNS FROM {} FROM {}",
                        Self::format_mysql_identifier(table),
                        Self::format_mysql_identifier(schema_name)
                    )
                }
                None => format!("SHOW COLUMNS FROM {}", Self::format_mysql_identifier(table)),
            },
            ToolCommand::ShowCreateTable { table } => {
                format!("SHOW CREATE TABLE {}", Self::format_mysql_identifier(table))
            }
            ToolCommand::ShowProcessList => "SHOW PROCESSLIST".to_string(),
            ToolCommand::ShowVariables { filter } => match filter {
                Some(f) => format!("SHOW VARIABLES LIKE '{}'", Self::escape_sql_literal(f)),
                None => "SHOW VARIABLES".to_string(),
            },
            ToolCommand::ShowStatus { filter } => match filter {
                Some(f) => format!("SHOW STATUS LIKE '{}'", Self::escape_sql_literal(f)),
                None => "SHOW STATUS".to_string(),
            },
            ToolCommand::MysqlDelimiter { delimiter } => format!("DELIMITER {}", delimiter),
            ToolCommand::ShowWarnings => "SHOW WARNINGS".to_string(),
            ToolCommand::MysqlShowErrors => "SHOW ERRORS".to_string(),
            ToolCommand::MysqlSource { path } => format!("SOURCE {}", path),
            ToolCommand::Unsupported { raw, .. } => raw.clone(),
        }
    }

    fn format_statement(
        statement: &str,
        tokens: &[SqlToken],
        select_list_break_state_on_start: SelectListBreakState,
        mysql_compatible: bool,
    ) -> String {
        if Self::is_sqlplus_remark_comment_statement(statement) {
            return statement.to_string();
        }

        if let Some(formatted) = Self::format_create_table(statement, mysql_compatible) {
            return formatted;
        }

        let clause_keywords = FORMAT_CLAUSE_KEYWORDS;
        let join_modifiers = FORMAT_JOIN_MODIFIER_KEYWORDS;
        let join_keyword = "JOIN";
        let outer_keyword = "OUTER";
        let condition_keywords = FORMAT_CONDITION_KEYWORDS; // ELSE handled separately for IF blocks
                                                            // BEGIN is handled separately to support DECLARE ... BEGIN ... END blocks
                                                            // CASE is handled separately for SELECT vs PL/SQL context
                                                            // LOOP is handled separately for FOR ... LOOP on same line
        let block_start_keywords = FORMAT_BLOCK_START_KEYWORDS;
        let block_end_qualifiers = FORMAT_BLOCK_END_QUALIFIER_KEYWORDS; // END LOOP, END IF, END CASE, END REPEAT

        let mut out = String::new();
        let mut indent_level = 0usize;
        let mut suppress_comma_break_depth = 0usize;
        let mut paren_stack: Vec<ParenFormatFrame> = Vec::new();
        let mut paren_clause_restore_stack: Vec<Option<QueryLikeParenRestoreState>> = Vec::new();
        let mut block_stack: Vec<String> = Vec::new(); // Track which block keywords started blocks
        let mut block_indent_stack: Vec<FormatBlockDepthFrame> = Vec::new();
        let mut at_line_start = true;
        let mut needs_space = false;
        let mut line_indent = 0usize;
        let mut line_start_token_paren_depth = 0usize;
        let mut join_modifier_active = false;
        let mut join_on_condition_frames: Vec<(usize, usize)> = Vec::new();
        let mut after_for_while = false; // Track FOR/WHILE for LOOP on same line
        let mut prev_word_upper: Option<String> = None;
        let mut construct = ConstructState::default();
        let mut current_clause: Option<String> = None;
        let mut pending_package_member_separator = false;
        let mut active_package_member_name: Option<String> = None;
        let mut open_cursor_state = OpenCursorFormatState::None;
        let mut open_for_select_stack: Vec<OpenCursorFormatState> = Vec::new();
        let mut mysql_handler_state = MySqlHandlerFormatState::None;
        let mut case_branch_started: Vec<bool> = Vec::new();
        let mut exception_branch_started: Vec<bool> = Vec::new();
        let mut between_paren_depths: Vec<usize> = Vec::new();
        let mut phase1_wrapped_owner_frames: Vec<Phase1WrappedOwnerFrame> = Vec::new();
        let mut select_list_layout_state = SelectListLayoutState::Inactive;
        let mut select_list_break_state = select_list_break_state_on_start;
        let mut exit_condition_state = ExitConditionState::None;
        let mut with_cte_state = WithCteFormatState::default();
        let mut statement_has_with_clause = false;
        let mut query_body_clause_base_depth: Option<usize> = None;
        let mut query_base_stack: Vec<Option<usize>> = vec![None];
        let mut control_condition_header_stack: Vec<usize> = Vec::new();
        let mut control_condition_header_parenthesized_stack: Vec<bool> = Vec::new();
        let mut insert_all_branch_body_indent: Option<usize> = None;
        let mut pending_split_end_suffix_indent: Option<usize> = None;
        let mut pending_split_end_suffix_kind: Option<PendingSplitEndSuffixKind> = None;
        let mut pending_plsql_label_body_indent: Option<usize> = None;
        // MySQL ON DUPLICATE KEY UPDATE: tracks when VALUES() is a function, not a clause
        let mut on_duplicate_key_update_active = false;
        let mut mysql_handler_begin_block_depths: Vec<usize> = Vec::new();
        let mut mysql_handler_body_indent_pending: Option<usize> = None;
        let mut trigger_header_state = TriggerHeaderState::default();
        let mut compound_trigger_state = CompoundTriggerState::default();
        let mut plsql_context_state = ScopedFlag::default();
        let mut inline_comment_continuation_state = InlineCommentContinuationState::None;
        let is_package_body_statement = Self::statement_starts_with_package_body_header(tokens);
        let statement_has_apply = Self::statement_contains_keyword(tokens, "APPLY");
        let query_apply_flags = Self::query_apply_flags(tokens);
        let token_spans =
            super::query_text::tokenize_sql_spanned_with_mysql_compat(statement, mysql_compatible);
        let token_paren_depths = paren_depths(tokens);
        let token_cache = FormatterTokenCache::build(tokens);
        let comment_prefix_cache = CommentPrefixCache::build(tokens);

        let newline_with = |out: &mut String,
                            indent_level: usize,
                            extra: usize,
                            at_line_start: &mut bool,
                            needs_space: &mut bool,
                            line_indent: &mut usize| {
            if !out.is_empty() && !out.ends_with('\n') {
                out.push('\n');
            }
            *line_indent = indent_level + extra;
            *at_line_start = true;
            *needs_space = false;
        };
        let newline_with_spaces = |out: &mut String,
                                   indent_spaces: usize,
                                   at_line_start: &mut bool,
                                   needs_space: &mut bool,
                                   line_indent: &mut usize| {
            if !out.is_empty() && !out.ends_with('\n') {
                out.push('\n');
            }
            out.push_str(&" ".repeat(indent_spaces));
            *line_indent = Self::safe_indent_div(indent_spaces);
            *at_line_start = false;
            *needs_space = false;
        };

        let base_indent = |indent_level: usize, open_cursor_state: OpenCursorFormatState| {
            open_cursor_state.base_indent(indent_level)
        };

        let clause_indent =
            |indent_level: usize,
             open_cursor_state: OpenCursorFormatState,
             _keyword: &str,
             _open_for_select_active: bool,
             _in_cursor_sql: bool| base_indent(indent_level, open_cursor_state);

        let list_item_indent =
            |indent_level: usize,
             open_cursor_state: OpenCursorFormatState,
             select_list_layout_state: SelectListLayoutState| {
                let base = base_indent(indent_level, open_cursor_state);
                select_list_layout_state.indentation_or(base + 1)
            };
        let clause_list_indent = |indent_level: usize,
                                  open_cursor_state: OpenCursorFormatState,
                                  select_list_layout_state: SelectListLayoutState,
                                  _current_clause: Option<&str>,
                                  merge_active: bool| {
            let base = base_indent(indent_level, open_cursor_state);
            let _ = merge_active;
            list_item_indent(indent_level, open_cursor_state, select_list_layout_state)
                .max(base + 1)
        };
        let active_list_indent = |indent_level: usize,
                                  open_cursor_state: OpenCursorFormatState,
                                  select_list_layout_state: SelectListLayoutState,
                                  current_clause: Option<&str>,
                                  merge_active: bool,
                                  in_column_list: bool| {
            if in_column_list {
                base_indent(indent_level, open_cursor_state)
            } else {
                clause_list_indent(
                    indent_level,
                    open_cursor_state,
                    select_list_layout_state,
                    current_clause,
                    merge_active,
                )
            }
        };
        let ensure_indent = |out: &mut String, at_line_start: &mut bool, line_indent: usize| {
            if *at_line_start {
                out.push_str(&" ".repeat(line_indent * 4));
                *at_line_start = false;
            }
        };

        let trim_trailing_space = |out: &mut String| {
            while out.ends_with(' ') {
                out.pop();
            }
        };
        let current_output_line_indent = |out: &str, fallback: usize| {
            out.rsplit('\n')
                .next()
                .map(|line| Self::safe_indent_div(line.chars().take_while(|ch| *ch == ' ').count()))
                .unwrap_or(fallback)
        };
        let token_gap_contains_newline = |idx: usize| -> bool {
            let Some(current_span) = token_spans.get(idx) else {
                return false;
            };
            let previous_end = idx
                .checked_sub(1)
                .and_then(|previous_idx| token_spans.get(previous_idx))
                .map(|span| span.end)
                .unwrap_or(0);
            statement
                .get(previous_end..current_span.start)
                .is_some_and(|gap| gap.contains('\n'))
        };
        let force_select_list_newline =
            |out: &mut String, select_list_layout_state: &mut SelectListLayoutState| {
                *select_list_layout_state = select_list_layout_state.force_newline_if_possible(out);
            };

        let mut mysql_begin_not_atomic_header_open = false;
        let mut idx = 0;
        while idx < tokens.len() {
            let current_token_paren_depth = token_paren_depths.get(idx).copied().unwrap_or(0);
            let current_scope = FormatScope::new(paren_stack.len(), block_stack.len());
            while between_paren_depths
                .last()
                .is_some_and(|depth| *depth > current_scope.paren_depth)
            {
                between_paren_depths.pop();
            }
            while join_on_condition_frames
                .last()
                .is_some_and(|(paren_depth, _)| *paren_depth > current_scope.paren_depth)
            {
                join_on_condition_frames.pop();
            }
            let top_level_select_item_context =
                paren_stack.iter().all(|frame| frame.is_query_like());
            if top_level_select_item_context && select_list_layout_state.has_active_indent() {
                let current_clause_name = if matches!(current_clause.as_deref(), Some("SET")) {
                    "SET"
                } else {
                    "SELECT"
                };
                let token_keeps_clause_structural = match tokens.get(idx) {
                    Some(SqlToken::Word(word)) => {
                        let upper = token_cache
                            .upper_word(idx)
                            .map(|value| value.to_string())
                            .unwrap_or_else(|| word.to_ascii_uppercase());
                        Self::is_dml_clause_starter(upper.as_str())
                            || crate::sql_text::is_format_set_operator_keyword(upper.as_str())
                    }
                    _ => false,
                };
                if !token_keeps_clause_structural {
                    current_clause = Some(current_clause_name.to_string());
                }
            }
            if at_line_start {
                if let Some(frame) = paren_stack.last_mut() {
                    frame.record_body_indent(line_indent);
                }
            }
            construct.sync_scope(current_scope);
            trigger_header_state.sync_scope(current_scope);
            compound_trigger_state.sync_scope(current_scope);
            plsql_context_state.sync_scope(current_scope);
            let in_plsql_block = plsql_context_state.is_active();
            let current_query_has_apply = query_apply_flags.get(idx).copied().unwrap_or(false);
            if let Some(label_indent) = pending_plsql_label_body_indent {
                if !matches!(tokens[idx], SqlToken::Comment(_)) {
                    if !at_line_start && out.ends_with('\n') {
                        at_line_start = true;
                    }
                    if at_line_start {
                        line_indent = line_indent.max(label_indent);
                    }
                }
            }
            if at_line_start && !matches!(tokens[idx], SqlToken::Comment(_)) {
                if let InlineCommentContinuationState::Operand { indent } =
                    inline_comment_continuation_state
                {
                    line_indent = indent;
                    inline_comment_continuation_state = InlineCommentContinuationState::None;
                }
            }
            let next_word = token_cache.next_word(tokens, idx);
            let third_word = token_cache.second_next_word(tokens, idx);
            let next_non_comment = token_cache.next_non_comment(tokens, idx);
            let next_word_is =
                |expected: &str| next_word.is_some_and(|word| word.eq_ignore_ascii_case(expected));
            let marks_multiline_child_continuation = match &tokens[idx] {
                SqlToken::Comment(_) => false,
                SqlToken::Symbol(sym) if sym == ")" || sym == "," => false,
                _ => true,
            };
            if marks_multiline_child_continuation {
                if let Some(frame) = paren_stack.last_mut() {
                    if frame.has_pending_multiline_child_continuation()
                        || frame.post_multiline_child_tail_token_count > 0
                    {
                        frame.note_continuation_token();
                    }
                }
            }
            if at_line_start {
                line_start_token_paren_depth = current_token_paren_depth;
            }

            match &tokens[idx] {
                SqlToken::Word(word) => {
                    let cached_upper;
                    let upper = if let Some(upper) = token_cache.upper_word(idx) {
                        upper
                    } else {
                        cached_upper = word.to_ascii_uppercase();
                        cached_upper.as_str()
                    };
                    let opens_unterminated_plsql_label =
                        word.starts_with("<<") && !word.ends_with(">>");
                    if opens_unterminated_plsql_label {
                        pending_plsql_label_body_indent =
                            Some(base_indent(indent_level, open_cursor_state));
                    } else if word.ends_with(">>") || pending_plsql_label_body_indent.is_some() {
                        pending_plsql_label_body_indent = None;
                    }
                    let mysql_labeled_block_header_word =
                        mysql_compatible && Self::is_mysql_labeled_block_header_word(tokens, idx);
                    let mysql_labeled_block_target_word =
                        mysql_compatible && Self::is_mysql_labeled_block_target_word(tokens, idx);
                    let is_formatter_keyword = |value: &str| {
                        sql_text::is_oracle_sql_keyword(value)
                            || (mysql_compatible && sql_text::is_mysql_sql_keyword(value))
                    };
                    let mysql_keyword_identifier = mysql_compatible
                        && Self::mysql_keyword_should_render_as_identifier(
                            tokens,
                            idx,
                            current_clause.as_deref(),
                            on_duplicate_key_update_active,
                            Some(token_cache.meaningful_links()),
                        );
                    let as_belongs_to_constructor_result_clause = upper == "AS"
                        && matches!(prev_word_upper.as_deref(), Some("SELF"))
                        && next_word_is("RESULT");
                    let mysql_begin_not_atomic_header = mysql_compatible
                        && upper == "BEGIN"
                        && next_word_is("NOT")
                        && third_word.is_some_and(|word| word.eq_ignore_ascii_case("ATOMIC"));
                    let inside_function_local_non_query_paren =
                        ConstructState::has_compact_non_query_frame_since_last_query(&paren_stack);
                    let with_cte_keyword_inside_function_local =
                        upper == "WITH" && inside_function_local_non_query_paren;
                    let with_plsql_body_starts_here = matches!(upper, "AS" | "IS")
                        && !as_belongs_to_constructor_result_clause
                        && with_cte_state.collecting_routine_declaration_body_start();
                    if !with_cte_keyword_inside_function_local {
                        with_cte_state.on_word(upper, prev_word_upper.as_deref());
                    }
                    let with_plsql_declaration_header =
                        sql_text::is_with_plsql_declaration_keyword(upper)
                            && (prev_word_upper.as_deref() == Some("WITH")
                                || with_cte_state.collecting_plsql_declaration_header());
                    let in_sql_case_clause = matches!(
                        current_clause.as_deref(),
                        Some(
                            "SELECT"
                                | "WHERE"
                                | "ORDER"
                                | "GROUP"
                                | "HAVING"
                                | "VALUES"
                                | "SET"
                                | "INTO"
                                | "RETURNING"
                        )
                    );
                    let is_keyword = is_formatter_keyword(upper);
                    let is_analytic_within_group = upper == "GROUP"
                        && matches!(prev_word_upper.as_deref(), Some("WITHIN"))
                        && {
                            let mut paren_depth = 0usize;
                            let mut saw_group_paren = false;
                            let mut lookahead_idx = idx.saturating_add(1);
                            let mut has_over = false;
                            while lookahead_idx < tokens.len() {
                                match &tokens[lookahead_idx] {
                                    SqlToken::Comment(_) => {}
                                    SqlToken::Symbol(sym) if sym == "(" => {
                                        paren_depth = paren_depth.saturating_add(1);
                                        saw_group_paren = true;
                                    }
                                    SqlToken::Symbol(sym) if sym == ")" => {
                                        if paren_depth == 0 {
                                            break;
                                        }
                                        paren_depth = paren_depth.saturating_sub(1);
                                    }
                                    SqlToken::Symbol(sym)
                                        if paren_depth == 0 && (sym == "," || sym == ";") =>
                                    {
                                        break;
                                    }
                                    SqlToken::Word(word)
                                        if paren_depth == 0
                                            && saw_group_paren
                                            && word.eq_ignore_ascii_case("OVER") =>
                                    {
                                        has_over = true;
                                        break;
                                    }
                                    _ => {}
                                }
                                lookahead_idx = lookahead_idx.saturating_add(1);
                            }
                            has_over
                        };
                    let is_within_group = upper == "GROUP"
                        && matches!(prev_word_upper.as_deref(), Some("WITHIN"))
                        && !is_analytic_within_group;
                    let active_phase1_wrapped_owner_kind =
                        Self::active_phase1_wrapped_owner_kind_at_depth(
                            &phase1_wrapped_owner_frames,
                            paren_stack.len(),
                        );
                    let mut newline_after_keyword = false;
                    let mut newline_after_keyword_extra = 0usize;
                    let between_pending =
                        between_paren_depths.last().copied() == Some(current_scope.paren_depth);
                    let is_between_and = upper == "AND" && between_pending;
                    let is_exit_when = exit_condition_state.is_exit_when(upper);
                    let should_break_condition = condition_keywords.contains(&upper)
                        && !(is_between_and
                            || is_exit_when
                            || construct.suppresses_condition_break(
                                upper,
                                prev_word_upper.as_deref(),
                                &trigger_header_state,
                            )
                            // ON inside non-subquery parens (e.g. JSON_VALUE ... ON ERROR)
                            // should not cause a condition line break.
                            || (upper == "ON"
                                && inside_function_local_non_query_paren));
                    let top_level_query_body_base_indent = query_body_clause_base_depth
                        .filter(|_| paren_stack.is_empty())
                        .unwrap_or_else(|| base_indent(indent_level, open_cursor_state));
                    let mysql_declare_cursor_for_clause = mysql_compatible
                        && upper == "FOR"
                        && Self::is_mysql_declare_cursor_for_clause(
                            tokens,
                            idx,
                            Some(token_cache.statement_word_links()),
                        );
                    let mysql_declare_handler_for_clause = mysql_compatible
                        && upper == "FOR"
                        && Self::is_mysql_declare_handler_for_clause(
                            tokens,
                            idx,
                            Some(token_cache.statement_word_links()),
                        );
                    let mysql_handler_body_line_pending = mysql_handler_state.body_line_pending();
                    let mysql_handler_block_begin = mysql_handler_body_line_pending
                        && upper == "BEGIN"
                        && !mysql_declare_handler_for_clause;
                    let mysql_declare_for_clause =
                        mysql_declare_cursor_for_clause || mysql_declare_handler_for_clause;
                    let mysql_if_exists_modifier = upper == "IF"
                        && Self::is_mysql_if_exists_modifier(
                            tokens,
                            idx,
                            next_word,
                            Some(token_cache.statement_word_links()),
                        );
                    let mysql_scalar_if_function = mysql_compatible
                        && upper == "IF"
                        && Self::mysql_if_is_scalar_function(
                            tokens,
                            idx,
                            Some(token_cache.meaningful_links()),
                            Some(token_cache.matching_paren_close_indices()),
                        );
                    let is_trigger_event_keyword = trigger_header_state.is_active()
                        && matches!(upper, "INSERT" | "UPDATE" | "DELETE");
                    let is_compound_trigger_timing_header = compound_trigger_state
                        .is_in_outer_body()
                        && block_stack.last().is_some_and(|s| s == "COMPOUND_TRIGGER")
                        && (matches!(upper, "BEFORE" | "AFTER")
                            && next_word.is_some_and(|word| {
                                matches!(word.to_ascii_uppercase().as_str(), "STATEMENT" | "EACH")
                            })
                            || (upper == "INSTEAD" && next_word_is("OF")));
                    let is_create_index_on =
                        upper == "ON" && construct.create_index_pending.is_active();
                    let follows_alias_keyword =
                        matches!(prev_word_upper.as_deref(), Some("AS" | "IS"));
                    let in_table_alias_clause = matches!(
                        current_clause.as_deref(),
                        Some("FROM" | "UPDATE" | "DELETE" | "INTO" | "MERGE" | "USING")
                    );
                    let in_select_clause = matches!(current_clause.as_deref(), Some("SELECT"));
                    let next_word_is_clause_keyword = next_word.is_none_or(|word| {
                        let next_upper = word.to_ascii_uppercase();
                        is_formatter_keyword(next_upper.as_str())
                    });
                    let next_token_ends_select_item = matches!(
                        next_non_comment,
                        Some(SqlToken::Symbol(sym)) if matches!(sym.as_str(), "," | ")")
                    ) || next_word_is_clause_keyword;
                    let next_token_ends_from_alias = matches!(
                        next_non_comment,
                        Some(SqlToken::Symbol(sym)) if matches!(sym.as_str(), "," | ")")
                    ) || next_word_is_clause_keyword;
                    let next_token_is_dot =
                        matches!(next_non_comment, Some(SqlToken::Symbol(sym)) if sym == ".");
                    let closes_case_expression =
                        upper == "END" && block_stack.last().is_some_and(|s| s == "CASE");
                    let treat_control_keyword_as_identifier =
                        sql_text::is_plsql_control_keyword(upper)
                            && !closes_case_expression
                            && !next_word_is("THEN")
                            && (follows_alias_keyword
                                || (in_table_alias_clause && next_token_ends_from_alias)
                                || (in_select_clause
                                    && !next_word_is("AS")
                                    && next_token_ends_select_item)
                                || (next_token_is_dot
                                    && matches!(
                                        current_clause.as_deref(),
                                        Some(
                                            "SELECT"
                                                | "FROM"
                                                | "WHERE"
                                                | "ON"
                                                | "GROUP"
                                                | "HAVING"
                                                | "ORDER"
                                        )
                                    )));
                    let mysql_compound_declare =
                        mysql_compatible && upper == "DECLARE" && in_plsql_block;
                    let follows_alias_control_keyword = follows_alias_keyword
                        && sql_text::is_plsql_control_keyword(upper)
                        && !next_word_is("THEN");
                    let mysql_create_function_header_attribute = mysql_compatible
                        && matches!(construct.create_object.as_deref(), Some("FUNCTION"))
                        && matches!(upper, "RETURNS" | "DETERMINISTIC");
                    if mysql_handler_block_begin {
                        indent_level = indent_level.saturating_add(1);
                    }
                    if mysql_handler_body_line_pending && !at_line_start {
                        let handler_body_indent =
                            mysql_handler_body_indent_pending.unwrap_or_else(|| {
                                let base =
                                    line_indent.max(base_indent(indent_level, open_cursor_state));
                                if mysql_handler_block_begin {
                                    base
                                } else {
                                    base.saturating_add(1)
                                }
                            });
                        newline_with(
                            &mut out,
                            handler_body_indent,
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    }
                    if mysql_labeled_block_header_word && !at_line_start {
                        newline_with(
                            &mut out,
                            base_indent(indent_level, open_cursor_state),
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    }
                    let should_treat_as_block_start = block_start_keywords.contains(&upper)
                        && !(pending_split_end_suffix_indent.is_some()
                            || mysql_if_exists_modifier
                            || mysql_scalar_if_function
                            || mysql_compound_declare
                            || treat_control_keyword_as_identifier
                            || follows_alias_control_keyword);
                    let follows_type_method_modifier = matches!(
                        prev_word_upper.as_deref(),
                        Some("MEMBER" | "STATIC" | "CONSTRUCTOR")
                    );
                    let at_package_body_member_depth =
                        is_package_body_statement && indent_level == 1;
                    if upper == "END" && !treat_control_keyword_as_identifier {
                        let active_end_block = block_stack.last().map(String::as_str);
                        let end_qualifier = {
                            let mut qualifier = None;
                            for (lookahead_idx, t) in tokens.iter().enumerate().skip(idx + 1) {
                                if token_gap_contains_newline(lookahead_idx) {
                                    break;
                                }
                                match t {
                                    SqlToken::Comment(comment) => {
                                        if comment.contains('\n') {
                                            break;
                                        }
                                    }
                                    SqlToken::Word(w) => {
                                        qualifier = Some(w.to_uppercase());
                                        break;
                                    }
                                    SqlToken::Symbol(sym) if sym == ";" => break,
                                    _ => break,
                                }
                            }
                            qualifier
                        };
                        let split_end_qualifier = if end_qualifier.is_none() {
                            let mut qualifier = None;
                            let mut crossed_line = false;
                            for (lookahead_idx, t) in tokens.iter().enumerate().skip(idx + 1) {
                                crossed_line |= token_gap_contains_newline(lookahead_idx);
                                match t {
                                    SqlToken::Comment(comment) => {
                                        crossed_line |= comment.contains('\n');
                                    }
                                    SqlToken::Word(w) => {
                                        if crossed_line {
                                            qualifier = Some(w.to_uppercase());
                                        }
                                        break;
                                    }
                                    SqlToken::Symbol(sym) if sym == ";" => break,
                                    _ => break,
                                }
                            }
                            qualifier
                        } else {
                            None
                        };
                        // Check if this is END LOOP, END IF, END CASE, etc.
                        let mut end_tail: Vec<String> = Vec::new();
                        if let Some(qualifier) = end_qualifier.as_deref() {
                            match qualifier {
                                "LOOP" | "IF" | "CASE" | "REPEAT" | "FOR" | "WHILE" => {
                                    let qualifier_belongs_to_case_end =
                                        active_end_block == Some("CASE") && qualifier == "CASE";
                                    let qualifier_is_case_expression_follower =
                                        active_end_block == Some("CASE") && qualifier != "CASE";
                                    if qualifier_belongs_to_case_end
                                        || !qualifier_is_case_expression_follower
                                    {
                                        end_tail.push(qualifier.to_string());
                                    }
                                }
                                "BEFORE" | "AFTER" => {
                                    end_tail.push(qualifier.to_string());
                                    let mut lookahead = idx + 1;
                                    while lookahead < tokens.len() {
                                        match &tokens[lookahead] {
                                            SqlToken::Comment(_) => {
                                                lookahead += 1;
                                                continue;
                                            }
                                            SqlToken::Word(word) => {
                                                let qualifier_part = word.to_uppercase();
                                                if end_tail
                                                    .last()
                                                    .is_some_and(|value| value == "EACH")
                                                {
                                                    if qualifier_part == "ROW" {
                                                        end_tail.push(qualifier_part);
                                                    }
                                                    break;
                                                }
                                                if matches!(
                                                    qualifier_part.as_str(),
                                                    "EACH" | "STATEMENT"
                                                ) {
                                                    end_tail.push(qualifier_part);
                                                    lookahead += 1;
                                                    continue;
                                                }
                                                break;
                                            }
                                            SqlToken::Symbol(sym) if sym == ";" => break,
                                            _ => break,
                                        }
                                    }
                                }
                                _ => {}
                            }
                        }
                        let effective_end_qualifier = end_tail
                            .first()
                            .map(String::as_str)
                            .or(split_end_qualifier.as_deref());
                        let is_qualified_end = matches!(
                            effective_end_qualifier,
                            Some("LOOP" | "IF" | "CASE" | "REPEAT" | "FOR" | "WHILE")
                        );
                        let paren_extra = Self::paren_extra_depth(&paren_stack);
                        let mut closed_block = None;
                        let mut restored_indent_level = None;
                        let mut closed_owner_depth = None;

                        let end_qualifier_is_keyword =
                            end_qualifier.as_deref().is_some_and(|qualifier| {
                                sql_text::is_oracle_sql_keyword(qualifier)
                                    || sql_text::is_mysql_sql_keyword(qualifier)
                            });
                        let case_expression_end = !is_qualified_end
                            && block_stack.last().is_some_and(|s| s == "CASE")
                            && (end_qualifier.is_none() || end_qualifier_is_keyword);
                        let closes_active_package_member = is_package_body_statement
                            && end_qualifier
                                .as_deref()
                                .zip(active_package_member_name.as_deref())
                                .is_some_and(|(qualifier, member_name)| {
                                    qualifier.eq_ignore_ascii_case(member_name)
                                })
                            && block_stack.iter().any(|block| block == "PACKAGE_BODY");

                        if is_qualified_end {
                            // END LOOP, END IF, END CASE - pop matching block
                            if let Some(top) = block_stack.last() {
                                if block_end_qualifiers.contains(&top.as_str()) {
                                    if let Some((_, depth_frame)) =
                                        pop_format_block(&mut block_stack, &mut block_indent_stack)
                                    {
                                        restored_indent_level =
                                            Some(depth_frame.previous_indent_level);
                                        closed_owner_depth = Some(depth_frame.owner_depth);
                                    }
                                }
                            }
                            if effective_end_qualifier.is_some_and(|q| q == "CASE")
                                && !case_branch_started.is_empty()
                            {
                                case_branch_started.pop();
                            }
                        } else if case_expression_end {
                            if let Some((_, depth_frame)) =
                                pop_format_block(&mut block_stack, &mut block_indent_stack)
                            {
                                restored_indent_level = Some(depth_frame.previous_indent_level);
                                closed_owner_depth = Some(depth_frame.owner_depth);
                            }
                            if !case_branch_started.is_empty() {
                                case_branch_started.pop();
                            }
                        } else {
                            // Plain END - closes BEGIN or DECLARE/PACKAGE_BODY block
                            // Pop until we find BEGIN or DECLARE/PACKAGE_BODY
                            while let Some((top, depth_frame)) =
                                pop_format_block(&mut block_stack, &mut block_indent_stack)
                            {
                                restored_indent_level = Some(depth_frame.previous_indent_level);
                                closed_owner_depth = Some(depth_frame.owner_depth);
                                if top == "EXCEPTION" && !exception_branch_started.is_empty() {
                                    exception_branch_started.pop();
                                }
                                let reached_package_body =
                                    block_stack.last().is_some_and(|s| s == "PACKAGE_BODY");
                                if closes_active_package_member {
                                    if reached_package_body {
                                        closed_block = Some(top);
                                        break;
                                    }
                                } else if top == "BEGIN"
                                    || top == "DECLARE"
                                    || top == "PACKAGE_BODY"
                                    || top == "COMPOUND_TRIGGER"
                                {
                                    closed_block = Some(top);
                                    break;
                                }
                            }
                            if matches!(closed_block.as_deref(), Some("BEGIN" | "DECLARE"))
                                && (block_stack.last().is_some_and(|s| s == "PACKAGE_BODY")
                                    || at_package_body_member_depth)
                            {
                                pending_package_member_separator = true;
                            }
                            if closes_active_package_member && closed_block.is_some() {
                                active_package_member_name = None;
                                pending_package_member_separator = true;
                            }
                        }

                        indent_level =
                            restored_indent_level.unwrap_or_else(|| indent_level.saturating_sub(1));
                        let end_line_indent = closed_owner_depth.unwrap_or(indent_level);
                        let closed_mysql_handler_begin =
                            matches!(closed_block.as_deref(), Some("BEGIN"))
                                && mysql_handler_begin_block_depths
                                    .last()
                                    .copied()
                                    .is_some_and(|depth| {
                                        depth == block_stack.len().saturating_add(1)
                                    });
                        if !block_stack.iter().any(|s| s == "COMPOUND_TRIGGER") {
                            compound_trigger_state.clear();
                        }
                        if is_package_body_statement
                            && !is_qualified_end
                            && !case_expression_end
                            && indent_level == 1
                        {
                            pending_package_member_separator = true;
                        }
                        let end_extra = if closed_owner_depth.is_some() {
                            0
                        } else if case_expression_end && (in_sql_case_clause || !in_plsql_block) {
                            1
                        } else {
                            0
                        };
                        newline_with(
                            &mut out,
                            base_indent(end_line_indent, open_cursor_state),
                            end_extra + usize::from(closed_owner_depth.is_none()) * paren_extra,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );

                        // Output "END"
                        ensure_indent(&mut out, &mut at_line_start, line_indent);
                        out.push_str("END");

                        // If qualified (END LOOP/IF/CASE/REPEAT/BEFORE/AFTER), output tail and skip it.
                        let skip_count = end_tail.len();
                        for qualifier in end_tail.iter() {
                            out.push(' ');
                            out.push_str(qualifier);
                        }
                        needs_space = true;
                        if skip_count == 0 {
                            idx += 1;
                        } else {
                            let mut lookahead = idx + 1;
                            let mut words_skipped = 0usize;
                            while lookahead < tokens.len() && words_skipped < skip_count {
                                match &tokens[lookahead] {
                                    SqlToken::Word(_) => {
                                        words_skipped += 1;
                                    }
                                    SqlToken::Comment(comment) => {
                                        if comment.contains('\n') {
                                            break;
                                        }
                                    }
                                    _ => {}
                                }
                                lookahead += 1;
                            }
                            idx = lookahead;
                        }
                        if closed_mysql_handler_begin {
                            let _ = mysql_handler_begin_block_depths.pop();
                            indent_level = indent_level.saturating_sub(1);
                        }
                        if skip_count == 0 && split_end_qualifier.is_some() && !case_expression_end
                        {
                            pending_split_end_suffix_indent = Some(end_line_indent);
                            if let Some(qualifier) = split_end_qualifier.as_deref() {
                                pending_split_end_suffix_kind = Some(
                                    PendingSplitEndSuffixKind::from_first_suffix_word(qualifier),
                                );
                            }
                        } else {
                            pending_split_end_suffix_kind = None;
                        }
                        continue;
                    } else if is_compound_trigger_timing_header {
                        compound_trigger_state.start_timing_point();
                        newline_with(
                            &mut out,
                            base_indent(indent_level, open_cursor_state),
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else if trigger_header_state.is_active()
                        && matches!(upper, "BEFORE" | "AFTER" | "INSTEAD" | "REFERENCING")
                    {
                        newline_with(
                            &mut out,
                            base_indent(indent_level, open_cursor_state),
                            1,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else if mysql_create_function_header_attribute {
                        newline_with(
                            &mut out,
                            base_indent(indent_level, open_cursor_state),
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else if is_trigger_event_keyword
                        && matches!(prev_word_upper.as_deref(), Some("BEFORE" | "AFTER" | "OF"))
                    {
                        // Keep trigger event verbs on the same line as BEFORE/AFTER/INSTEAD OF.
                    } else if construct.merge_when_branch_active.is_active() && upper == "SET" {
                        // MERGE UPDATE SET keeps SET inline with UPDATE, but we still need
                        // SET clause context so following list comments/commas align correctly.
                        current_clause = Some(upper.to_string());
                        select_list_layout_state.clear();
                    } else if upper == "ORDER"
                        && active_phase1_wrapped_owner_kind
                            == Some(FormatIndentedParenOwnerKind::WithinGroup)
                    {
                        let owner_relative_body_indent = paren_stack
                            .last()
                            .map(|frame| frame.open_line_indent.saturating_add(1))
                            .unwrap_or_else(|| base_indent(indent_level, open_cursor_state));
                        if let Some(frame) = paren_stack.last_mut() {
                            frame.record_body_indent(owner_relative_body_indent);
                        }
                        newline_with(
                            &mut out,
                            owner_relative_body_indent,
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                        current_clause = Some(upper.to_string());
                        select_list_layout_state.clear();
                    } else if clause_keywords.contains(&upper)
                        && !mysql_keyword_identifier
                        && !mysql_declare_for_clause
                        // VALUES() inside ON DUPLICATE KEY UPDATE is a function, not a clause
                        && (!on_duplicate_key_update_active || upper != "VALUES")
                        && !construct.suppresses_clause_break(
                            tokens,
                            idx,
                            upper,
                            prev_word_upper.as_deref(),
                            in_plsql_block,
                            suppress_comma_break_depth,
                            paren_stack.iter().any(|frame| frame.is_query_like()),
                            inside_function_local_non_query_paren,
                            current_scope,
                            &trigger_header_state,
                            is_analytic_within_group,
                            !Self::fetch_into_has_multiple_targets(tokens, idx),
                            construct.in_analytic_over_paren(paren_stack.len()),
                            construct.in_keep_paren(paren_stack.len()),
                            Some(token_cache.statement_word_links()),
                        )
                    {
                        // FORALL body is always exactly one structural level
                        // deeper than the FORALL header, regardless of the
                        // surrounding PL/SQL nesting.
                        if construct.forall_pending.is_active()
                            && matches!(upper, "INSERT" | "UPDATE" | "DELETE" | "MERGE")
                        {
                            indent_level = indent_level.saturating_add(1);
                            construct.forall_pending.deactivate();
                            construct.forall_body_active.activate(current_scope);
                        }
                        if !is_within_group {
                            let insert_all_active_in_scope = construct
                                .insert_all_active
                                .is_active_at_paren_depth(current_scope.paren_depth);
                            let insert_all_branch_indent =
                                insert_all_branch_body_indent.filter(|_| {
                                    insert_all_active_in_scope && matches!(upper, "INTO" | "VALUES")
                                });
                            let insert_all_extra = usize::from(
                                insert_all_active_in_scope
                                    && insert_all_branch_indent.is_none()
                                    && matches!(upper, "INTO" | "VALUES"),
                            );
                            let mysql_handler_body_extra = usize::from(
                                mysql_handler_body_line_pending && !mysql_handler_block_begin,
                            );
                            let create_query_body_base_depth =
                                (crate::sql_text::is_subquery_head_keyword(upper)
                                    && paren_stack.is_empty())
                                .then(|| active_query_owner_line(&out, at_line_start))
                                .filter(|owner_line| {
                                    sql_text::line_is_create_query_body_header(owner_line)
                                })
                                .map(|owner_line| {
                                    rendered_line_indent(owner_line).saturating_add(1)
                                });
                            if let Some(base_depth) = create_query_body_base_depth {
                                query_body_clause_base_depth = Some(base_depth);
                            }
                            let window_body_header_indent = construct
                                .in_window_paren(paren_stack.len())
                                .then(|| {
                                    FormatIndentedParenOwnerKind::Window
                                        .starts_phase1_body_header_words(
                                            upper, next_word, third_word,
                                        )
                                })
                                .filter(|is_header| *is_header)
                                .and_then(|_| paren_stack.last().copied())
                                .map(|frame| frame.open_line_indent.saturating_add(1));
                            let returning_function_option_indent = (upper == "RETURNING")
                                .then_some(())
                                .filter(|_| {
                                    matches!(current_clause.as_deref(), Some("SELECT"))
                                        && paren_stack
                                            .last()
                                            .is_some_and(|frame| !frame.is_query_like())
                                })
                                .map(|_| {
                                    let rendered_indent =
                                        current_output_line_indent(&out, line_indent);
                                    let owner_indent = if at_line_start
                                        && rendered_indent == 0
                                        && line_indent > 0
                                    {
                                        line_indent
                                    } else {
                                        rendered_indent
                                    };
                                    owner_indent.saturating_add(1)
                                });
                            let returning_owner_body_indent = (upper == "RETURNING"
                                && !matches!(current_clause.as_deref(), Some("SELECT" | "SET"))
                                && !open_cursor_state.in_select()
                                && !construct.cursor_sql_active.is_active())
                            .then(|| {
                                paren_stack
                                    .last()
                                    .and_then(|frame| frame.sibling_body_indent())
                            })
                            .flatten();
                            // INSERT ALL: stop at SELECT (the trailing query)
                            if insert_all_active_in_scope && upper == "SELECT" {
                                construct.insert_all_active.deactivate();
                                insert_all_branch_body_indent = None;
                            }
                            let query_head_indent = (at_line_start
                                && crate::sql_text::is_subquery_head_keyword(upper))
                            .then_some(line_indent)
                            .filter(|_| {
                                paren_stack
                                    .last()
                                    .is_some_and(|frame| frame.is_query_like())
                            });
                            if let Some(returning_indent) =
                                returning_function_option_indent.or(returning_owner_body_indent)
                            {
                                newline_with(
                                    &mut out,
                                    returning_indent,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else if let Some(window_indent) = window_body_header_indent {
                                newline_with(
                                    &mut out,
                                    window_indent,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else if let Some(query_body_depth) =
                                query_body_clause_base_depth.filter(|_| paren_stack.is_empty())
                            {
                                newline_with(
                                    &mut out,
                                    query_body_depth,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else if let Some(query_indent) = query_head_indent {
                                newline_with(
                                    &mut out,
                                    query_indent,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else if let Some(branch_indent) = insert_all_branch_indent {
                                newline_with(
                                    &mut out,
                                    branch_indent,
                                    mysql_handler_body_extra,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else {
                                let select_clause_header_indent =
                                    matches!(current_clause.as_deref(), Some("SELECT"))
                                        .then_some(())
                                        .filter(|_| {
                                            select_list_layout_state.has_active_indent()
                                                && matches!(
                                                    upper,
                                                    "FROM"
                                                        | "WHERE"
                                                        | "GROUP"
                                                        | "HAVING"
                                                        | "ORDER"
                                                        | "LIMIT"
                                                        | "WINDOW"
                                                )
                                        })
                                        .map(|_| {
                                            select_list_layout_state
                                                .indentation_or(current_output_line_indent(
                                                    &out,
                                                    line_indent,
                                                ))
                                                .saturating_sub(1)
                                        });
                                newline_with(
                                    &mut out,
                                    select_clause_header_indent.unwrap_or_else(|| {
                                        clause_indent(
                                            indent_level,
                                            open_cursor_state,
                                            upper,
                                            open_cursor_state
                                                .select_depth()
                                                .is_some_and(|depth| paren_stack.len() == depth),
                                            construct.cursor_sql_active.is_active(),
                                        )
                                    }),
                                    insert_all_extra + mysql_handler_body_extra,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                        }
                        if !is_within_group {
                            if upper != "MODEL" {
                                construct
                                    .model_active
                                    .deactivate_at_or_above_paren_depth(current_scope.paren_depth);
                                construct
                                    .model_reference_pending
                                    .deactivate_at_or_above_paren_depth(current_scope.paren_depth);
                            }
                            current_clause = Some(upper.to_string());
                            if upper != "SELECT" {
                                select_list_layout_state.clear();
                            }
                            if crate::sql_text::is_subquery_head_keyword(upper) {
                                if let Some(base_depth) = query_base_stack.last_mut() {
                                    *base_depth = Some(line_indent);
                                } else {
                                    query_base_stack.push(Some(line_indent));
                                }
                            }
                            if upper == "SELECT"
                                && open_cursor_state.in_select()
                                && !with_cte_state.in_definitions()
                            {
                                // OPEN ... FOR WITH ... SELECT should anchor to the main query
                                // head after CTE definitions, not to inner SELECTs inside the
                                // WITH body. Otherwise a later `FOR` in PIVOT/UNPIVOT or
                                // similar syntax can be misread as a new OPEN ... FOR.
                                open_cursor_state.set_select_depth(paren_stack.len());
                            }
                            if upper == "WITH" {
                                statement_has_with_clause = true;
                            }
                            if upper == "MODEL"
                                && !construct
                                    .model_active
                                    .is_active_at_paren_depth(current_scope.paren_depth)
                            {
                                construct.model_active.activate(current_scope);
                            }
                            if matches!(
                                upper,
                                "SELECT"
                                    | "FROM"
                                    | "WHERE"
                                    | "GROUP"
                                    | "HAVING"
                                    | "ORDER"
                                    | "UPDATE"
                                    | "DELETE"
                                    | "INSERT"
                                    | "MERGE"
                            ) || crate::sql_text::is_format_set_operator_keyword(upper)
                            {
                                construct.search_cycle_clause_active.deactivate();
                            }
                        }
                    } else if is_analytic_within_group {
                        newline_with(
                            &mut out,
                            list_item_indent(
                                indent_level,
                                open_cursor_state,
                                select_list_layout_state,
                            ),
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else if trigger_header_state.is_active() && upper == "WHEN" {
                        // Trigger WHEN clause: align with other trigger header keywords
                        newline_with(
                            &mut out,
                            base_indent(indent_level, open_cursor_state),
                            1,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else if should_break_condition {
                        let control_header_condition_indent = matches!(upper, "AND" | "OR")
                            .then(|| control_condition_header_stack.last().copied())
                            .flatten();
                        let in_control_header_condition = control_header_condition_indent.is_some()
                            || (matches!(upper, "AND" | "OR")
                                && block_stack
                                    .last()
                                    .is_some_and(|block| matches!(block.as_str(), "IF" | "WHILE"))
                                && !matches!(current_clause.as_deref(), Some("SELECT")));
                        let control_header_is_parenthesized = matches!(upper, "AND" | "OR")
                            .then(|| control_condition_header_parenthesized_stack.last().copied())
                            .flatten()
                            .unwrap_or(false);
                        let control_header_previous_token_is_close_paren = matches!(
                            comment_prefix_cache
                                .previous_non_comment_token_index(idx)
                                .and_then(|token_idx| tokens.get(token_idx)),
                            Some(SqlToken::Symbol(sym)) if sym == ")"
                        );
                        let clause_base_indent =
                            if let Some(header_indent) = control_header_condition_indent {
                                header_indent
                            } else if in_control_header_condition {
                                if matches!(upper, "AND" | "OR")
                                    && block_stack.last().is_some_and(|block| {
                                        matches!(block.as_str(), "IF" | "WHILE")
                                    })
                                {
                                    block_indent_stack
                                        .last()
                                        .map(|frame| frame.owner_depth)
                                        .unwrap_or_else(|| {
                                            base_indent(
                                                indent_level.saturating_sub(1),
                                                open_cursor_state,
                                            )
                                        })
                                } else {
                                    base_indent(indent_level.saturating_sub(1), open_cursor_state)
                                }
                            } else {
                                if paren_stack.is_empty() {
                                    top_level_query_body_base_indent
                                } else {
                                    clause_indent(
                                        indent_level,
                                        open_cursor_state,
                                        upper,
                                        open_cursor_state
                                            .select_depth()
                                            .is_some_and(|depth| paren_stack.len() == depth),
                                        construct.cursor_sql_active.is_active(),
                                    )
                                }
                            };
                        let paren_extra = Self::paren_extra_depth(&paren_stack);
                        if construct
                            .insert_all_active
                            .is_active_at_paren_depth(current_scope.paren_depth)
                            && matches!(upper, "WHEN" | "ELSE")
                        {
                            insert_all_branch_body_indent = None;
                        }
                        if upper == "WHEN"
                            && block_stack.last().is_some_and(|s| s == "CASE")
                            && case_branch_started.last().is_some()
                        {
                            if let Some(last) = case_branch_started.last_mut() {
                                *last = true;
                            }
                        }
                        let is_merge_when = upper == "WHEN"
                            && construct.merge_active.is_active()
                            && block_stack.last().is_none_or(|s| s != "CASE");
                        let in_exception_block =
                            upper == "WHEN" && block_stack.last().is_some_and(|s| s == "EXCEPTION");
                        if in_exception_block {
                            if let Some(last) = exception_branch_started.last_mut() {
                                *last = false;
                            }
                        }
                        let pending_create_query_body_owner_depth = (upper == "ON")
                            .then(|| current_rendered_line(&out))
                            .filter(|owner_line| {
                                matches!(
                                    sql_text::format_query_owner_pending_header_kind(owner_line),
                                    Some(sql_text::PendingFormatQueryOwnerHeaderKind::CreateQueryBody)
                                )
                            })
                            .map(rendered_line_indent);
                        let case_owner_depth = (upper == "WHEN"
                            && block_stack.last().is_some_and(|s| s == "CASE"))
                        .then(|| block_indent_stack.last().map(|frame| frame.owner_depth))
                        .flatten();
                        if is_merge_when {
                            // MERGE WHEN MATCHED/NOT MATCHED: at base indent
                            if construct.merge_when_branch_active.is_active() {
                                indent_level = indent_level.saturating_sub(1);
                                construct.merge_when_branch_active.deactivate();
                            }
                            newline_with(
                                &mut out,
                                base_indent(indent_level, open_cursor_state),
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else if let Some(owner_depth) = pending_create_query_body_owner_depth {
                            query_body_clause_base_depth = Some(owner_depth.saturating_add(1));
                            newline_with(
                                &mut out,
                                owner_depth,
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else if in_exception_block {
                            newline_with(
                                &mut out,
                                clause_base_indent,
                                paren_extra,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else if let Some(owner_depth) = case_owner_depth {
                            newline_with(
                                &mut out,
                                owner_depth,
                                1,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else {
                            let join_condition_owner_frame = join_on_condition_frames
                                .last()
                                .copied()
                                .filter(|(paren_depth, _)| {
                                    current_scope.paren_depth >= *paren_depth
                                        && matches!(upper, "AND" | "OR")
                                });
                            if let Some((owner_paren_depth, owner_depth)) =
                                join_condition_owner_frame
                            {
                                newline_with(
                                    &mut out,
                                    owner_depth,
                                    1 + current_scope.paren_depth.saturating_sub(owner_paren_depth),
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else {
                                let condition_extra = if in_control_header_condition
                                    && matches!(upper, "AND" | "OR")
                                {
                                    if control_header_is_parenthesized {
                                        paren_extra.max(1)
                                    } else if control_header_previous_token_is_close_paren {
                                        paren_extra
                                    } else {
                                        paren_extra.max(1)
                                    }
                                } else if in_control_header_condition {
                                    paren_extra.max(1)
                                } else if upper == "ON" {
                                    1
                                } else {
                                    paren_extra + 1
                                };
                                newline_with(
                                    &mut out,
                                    clause_base_indent,
                                    condition_extra,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                        }
                        if upper == "ON" {
                            current_clause = Some(upper.to_string());
                            select_list_layout_state.clear();
                        }
                    } else if upper == "EXCEPTION" && in_plsql_block {
                        newline_with(
                            &mut out,
                            base_indent(indent_level.saturating_sub(1), open_cursor_state),
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else if construct.model_reference_pending.is_active()
                        && at_line_start
                        && upper != "ON"
                    {
                        newline_with(
                            &mut out,
                            base_indent(indent_level, open_cursor_state),
                            1,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else if construct.model_reference_pending.is_active() && upper == "ON" {
                        construct.model_reference_pending.deactivate();
                    } else if upper == "CREATE" {
                        construct.create_pending.activate(current_scope);
                        construct.create_object.clear();
                    } else if construct.create_pending.is_active()
                        && (upper == "OR" || upper == "REPLACE")
                    {
                        // part of CREATE OR REPLACE
                    } else if construct.create_pending.is_active() && upper == "PACKAGE" {
                        if next_word_is("BODY") {
                            construct
                                .create_object
                                .replace(current_scope, "PACKAGE_BODY".to_string());
                        } else {
                            construct
                                .create_object
                                .replace(current_scope, "PACKAGE".to_string());
                        }
                        construct.create_pending.deactivate();
                    } else if construct.create_pending.is_active() && upper == "TABLE" {
                        construct
                            .create_table_paren_expected
                            .activate(current_scope);
                        construct.create_pending.deactivate();
                    } else if construct.create_pending.is_active()
                        && matches!(upper, "INDEX" | "UNIQUE")
                    {
                        if upper == "INDEX" {
                            construct.create_index_pending.activate(current_scope);
                            construct.create_pending.deactivate();
                        }
                        // UNIQUE stays in construct.create_pending to catch UNIQUE INDEX
                    } else if construct.create_pending.is_active() && upper == "SEQUENCE" {
                        construct.create_sequence_active.activate(current_scope);
                        construct.create_pending.deactivate();
                    } else if construct.create_pending.is_active() && upper == "SYNONYM" {
                        construct.create_synonym_active.activate(current_scope);
                        construct.create_pending.deactivate();
                    } else if construct.create_pending.is_active()
                        && matches!(upper, "PROCEDURE" | "FUNCTION" | "TYPE" | "TRIGGER")
                    {
                        construct
                            .create_object
                            .replace(current_scope, upper.to_string());
                        if upper == "TRIGGER" {
                            trigger_header_state.start(current_scope);
                        }
                        construct.create_pending.deactivate();
                    } else if with_plsql_declaration_header {
                        if !at_line_start {
                            newline_with(
                                &mut out,
                                base_indent(indent_level, open_cursor_state),
                                1,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        }
                        if matches!(upper, "PROCEDURE" | "FUNCTION") {
                            construct.routine_decl_pending.activate(current_scope);
                        } else if upper == "PACKAGE" {
                            construct
                                .create_object
                                .replace(current_scope, upper.to_string());
                        }
                    } else if matches!(upper, "PROCEDURE" | "FUNCTION")
                        && (block_stack.last().is_some_and(|s| s == "DECLARE")
                            || block_stack.iter().any(|s| s == "PACKAGE_BODY")
                            || at_package_body_member_depth)
                    {
                        if !at_line_start && !follows_type_method_modifier {
                            newline_with(
                                &mut out,
                                base_indent(indent_level, open_cursor_state),
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        }
                        construct.routine_decl_pending.activate(current_scope);
                    } else if matches!(upper, "ELSE" | "ELSIF" | "ELSEIF") {
                        // ELSE/ELSIF/ELSEIF in IF block: same level as IF
                        let in_if_block = block_stack.last().is_some_and(|s| s == "IF");
                        let in_case_block = block_stack.last().is_some_and(|s| s == "CASE");
                        let paren_extra = Self::paren_extra_depth(&paren_stack);
                        if upper == "ELSE"
                            && in_case_block
                            && case_branch_started.last().is_some()
                            && !in_if_block
                        {
                            if let Some(last) = case_branch_started.last_mut() {
                                *last = true;
                            }
                        }
                        if in_if_block {
                            newline_with(
                                &mut out,
                                base_indent(indent_level.saturating_sub(1), open_cursor_state),
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else {
                            // ELSE in CASE or other context
                            if let Some(owner_depth) = in_case_block
                                .then(|| block_indent_stack.last().map(|frame| frame.owner_depth))
                                .flatten()
                            {
                                newline_with(
                                    &mut out,
                                    owner_depth,
                                    1,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else {
                                newline_with(
                                    &mut out,
                                    base_indent(indent_level, open_cursor_state),
                                    paren_extra + 1,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                        }
                        if upper == "ELSE"
                            && in_plsql_block
                            && !matches!(current_clause.as_deref(), Some("SELECT"))
                        {
                            newline_after_keyword = true;
                            if in_case_block {
                                newline_after_keyword_extra = 1;
                            }
                        } else if upper == "ELSE" && in_sql_case_clause && next_word_is("CASE") {
                            // Keep ELSE CASE from collapsing into one long SQL expression line.
                            newline_after_keyword = true;
                            newline_after_keyword_extra = 1;
                        }
                    } else if upper == "THEN" {
                        if construct.merge_active.is_active()
                            && block_stack.last().is_none_or(|s| s != "CASE")
                        {
                            // MERGE WHEN MATCHED THEN / WHEN NOT MATCHED THEN
                            indent_level += 1;
                            construct.merge_when_branch_active.activate(current_scope);
                            newline_after_keyword = true;
                        } else if construct
                            .insert_all_active
                            .is_active_at_paren_depth(current_scope.paren_depth)
                        {
                            // INSERT ALL/FIRST branch bodies should stay one
                            // level deeper than WHEN ... THEN headers.
                            insert_all_branch_body_indent = Some(
                                current_output_line_indent(&out, line_indent).saturating_add(1),
                            );
                            newline_after_keyword = true;
                            newline_after_keyword_extra = 1;
                        } else if in_plsql_block
                            && !matches!(current_clause.as_deref(), Some("SELECT"))
                        {
                            newline_after_keyword = true;
                            if block_stack
                                .last()
                                .is_some_and(|s| s == "CASE" || s == "EXCEPTION")
                            {
                                newline_after_keyword_extra = 1;
                                if block_stack.last().is_some_and(|s| s == "EXCEPTION") {
                                    if let Some(last) = exception_branch_started.last_mut() {
                                        *last = true;
                                    }
                                }
                            }
                        } else if in_sql_case_clause && next_word_is("CASE") {
                            // Nested CASE in SQL expressions should start on its own line.
                            newline_after_keyword = true;
                            newline_after_keyword_extra = 1;
                        }
                    } else if upper == join_keyword || upper == "APPLY" {
                        if !join_modifier_active {
                            newline_with(
                                &mut out,
                                top_level_query_body_base_indent,
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        }
                        join_modifier_active = false;
                    } else if join_modifiers.contains(&upper) {
                        let next_leads_to_join = next_word_is("JOIN")
                            || next_word_is("OUTER")
                            || next_word_is("APPLY")
                            || next_word.is_some_and(|w| {
                                join_modifiers.iter().any(|m| w.eq_ignore_ascii_case(m))
                            });
                        if next_leads_to_join {
                            if !join_modifier_active {
                                newline_with(
                                    &mut out,
                                    top_level_query_body_base_indent,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                            join_modifier_active = true;
                        }
                    } else if upper == outer_keyword {
                        if (next_word_is("JOIN") || next_word_is("APPLY")) && !join_modifier_active
                        {
                            newline_with(
                                &mut out,
                                top_level_query_body_base_indent,
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                            join_modifier_active = true;
                        }
                    } else if upper == "SEARCH" || upper == "CYCLE" {
                        construct.search_cycle_clause_active.activate(current_scope);
                        // SEARCH/CYCLE after recursive CTE should start on a
                        // new line at the WITH-clause level.
                        newline_with(
                            &mut out,
                            base_indent(indent_level, open_cursor_state),
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else if matches!(upper, "PIVOT" | "UNPIVOT")
                        && suppress_comma_break_depth == 0
                        && !construct.create_synonym_active.is_active()
                    {
                        // PIVOT/UNPIVOT should start on a new line as a
                        // clause-level keyword at the same depth as FROM.
                        newline_with(
                            &mut out,
                            clause_indent(
                                indent_level,
                                open_cursor_state,
                                upper,
                                open_cursor_state
                                    .select_depth()
                                    .is_some_and(|depth| paren_stack.len() == depth),
                                construct.cursor_sql_active.is_active(),
                            ),
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else {
                        let match_recognize_body_header = construct
                            .in_match_recognize_paren(paren_stack.len())
                            && FormatIndentedParenOwnerKind::MatchRecognize
                                .starts_phase1_body_header_words(upper, next_word, third_word);
                        let analytic_over_body_header = construct
                            .in_analytic_over_paren(paren_stack.len())
                            && FormatIndentedParenOwnerKind::AnalyticOver
                                .starts_phase1_body_header_words(upper, next_word, third_word);
                        let window_body_header = construct.in_window_paren(paren_stack.len())
                            && FormatIndentedParenOwnerKind::Window
                                .starts_phase1_body_header_words(upper, next_word, third_word);
                        if match_recognize_body_header
                            || analytic_over_body_header
                            || window_body_header
                        {
                            let owner_relative_body_indent = (match_recognize_body_header
                                || analytic_over_body_header
                                || window_body_header)
                                .then(|| paren_stack.last().copied())
                                .flatten()
                                .map(|frame| frame.open_line_indent.saturating_add(1));
                            newline_with(
                                &mut out,
                                owner_relative_body_indent.unwrap_or_else(|| {
                                    base_indent(indent_level, open_cursor_state)
                                }),
                                usize::from(owner_relative_body_indent.is_none()),
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else if construct
                            .model_active
                            .is_active_at_paren_depth(current_scope.paren_depth)
                            && FormatIndentedParenOwnerKind::ModelSubclause
                                .starts_phase1_body_header_words(upper, next_word, third_word)
                        {
                            if upper == "REFERENCE" {
                                construct.model_reference_pending.activate(current_scope);
                            } else {
                                construct.model_reference_pending.deactivate();
                            }
                            newline_with(
                                &mut out,
                                base_indent(indent_level, open_cursor_state),
                                1,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else if active_phase1_wrapped_owner_kind.is_some_and(|kind| {
                            kind.starts_phase1_body_header_words(upper, next_word, third_word)
                        }) {
                            newline_with(
                                &mut out,
                                base_indent(indent_level, open_cursor_state),
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else if upper == "OPEN" {
                            open_cursor_state = OpenCursorFormatState::AwaitingFor;
                        } else if upper == "FOR" && mysql_declare_cursor_for_clause {
                            construct.cursor_sql_active.activate(current_scope);
                            indent_level += 1;
                            newline_after_keyword = true;
                        } else if upper == "FOR" && mysql_declare_handler_for_clause {
                            mysql_handler_state.start();
                            mysql_handler_body_indent_pending = None;
                        } else if upper == "FOR"
                            && next_word_is("UPDATE")
                            && !mysql_declare_for_clause
                            && !in_plsql_block
                            && suppress_comma_break_depth == 0
                        {
                            // FOR UPDATE gets its own line at clause base indent.
                            newline_with(
                                &mut out,
                                base_indent(indent_level, open_cursor_state),
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else if (upper == "FOR" || upper == "WHILE")
                            && !mysql_declare_for_clause
                            && !(upper == "FOR"
                                && (construct.create_synonym_active.is_active()
                                    || suppress_comma_break_depth > 0
                                    || (next_word_is("UPDATE") && !in_plsql_block)))
                        {
                            if upper == "FOR" && trigger_header_state.is_active() {
                                newline_with(
                                    &mut out,
                                    base_indent(indent_level, open_cursor_state),
                                    1,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                                after_for_while = false;
                            } else if upper == "FOR"
                                && open_cursor_state == OpenCursorFormatState::AwaitingFor
                            {
                                open_for_select_stack.push(open_cursor_state);
                                open_cursor_state = OpenCursorFormatState::InSelect {
                                    anchor_indent: line_indent.saturating_add(1),
                                    select_paren_depth: None,
                                };
                                newline_after_keyword = true;
                            } else {
                                // FOR/WHILE starts a line, LOOP will follow on same line
                                if !mysql_labeled_block_target_word {
                                    newline_with(
                                        &mut out,
                                        base_indent(indent_level, open_cursor_state),
                                        0,
                                        &mut at_line_start,
                                        &mut needs_space,
                                        &mut line_indent,
                                    );
                                }
                                after_for_while = true;
                            }
                        } else if upper == "LOOP" {
                            // LOOP after FOR/WHILE stays on same line
                            let mysql_labeled_loop = mysql_compatible
                                && idx
                                    .checked_sub(1)
                                    .and_then(|prev_idx| tokens.get(prev_idx))
                                    .is_some_and(
                                        |token| matches!(token, SqlToken::Symbol(sym) if sym == ":"),
                                    )
                                && idx.checked_sub(1).is_some_and(|prev_idx| {
                                    Self::is_mysql_block_label_colon(tokens, prev_idx, ":")
                                });
                            if !after_for_while && !mysql_labeled_loop {
                                newline_with(
                                    &mut out,
                                    base_indent(indent_level, open_cursor_state),
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                            after_for_while = false;
                            // LOOP always starts a block body on the next line.
                            newline_after_keyword = true;
                        } else if upper == "REPEAT" {
                            // REPEAT starts a block body on the next line.
                            if !mysql_labeled_block_target_word {
                                newline_with(
                                    &mut out,
                                    base_indent(indent_level, open_cursor_state),
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                            newline_after_keyword = true;
                        } else if upper == "DO"
                            && mysql_compatible
                            && after_for_while
                            && Self::recent_statement_words_before(
                                tokens,
                                idx,
                                8,
                                Some(token_cache.statement_word_links()),
                            )
                            .iter()
                            .any(|word| word.eq_ignore_ascii_case("WHILE"))
                        {
                            after_for_while = false;
                            push_format_block(
                                &mut block_stack,
                                &mut block_indent_stack,
                                "WHILE",
                                indent_level,
                                line_indent,
                            );
                            indent_level += 1;
                            plsql_context_state
                                .activate(FormatScope::new(paren_stack.len(), block_stack.len()));
                            newline_after_keyword = true;
                        } else if upper == "CASE" {
                            // CASE in PL/SQL block vs SELECT context
                            let values_case_indent =
                                matches!(current_clause.as_deref(), Some("VALUES"))
                                    .then(|| {
                                        paren_stack
                                            .iter()
                                            .rev()
                                            .find(|frame| {
                                                matches!(frame.kind, ParenFormatFrameKind::Compact)
                                            })
                                            .map(|frame| frame.open_line_indent.saturating_add(1))
                                    })
                                    .flatten();
                            if in_sql_case_clause {
                                let paren_extra = Self::paren_extra_depth(&paren_stack);
                                let in_case_branch_body =
                                    block_stack.last().is_some_and(|s| s == "CASE")
                                        && (case_branch_started.last().copied().unwrap_or(false)
                                            || matches!(prev_word_upper.as_deref(), Some("THEN")));
                                if let Some(values_case_indent) = values_case_indent {
                                    newline_with(
                                        &mut out,
                                        values_case_indent,
                                        0,
                                        &mut at_line_start,
                                        &mut needs_space,
                                        &mut line_indent,
                                    );
                                } else if in_case_branch_body {
                                    let branch_case_indent = block_indent_stack
                                        .last()
                                        .map(|frame| frame.owner_depth.saturating_add(2))
                                        .unwrap_or(line_indent);
                                    let parenthesized_branch_case_indent = paren_stack
                                        .last()
                                        .and_then(|frame| frame.sibling_body_indent())
                                        .map(|indent| indent.max(branch_case_indent))
                                        .unwrap_or(branch_case_indent);
                                    newline_with(
                                        &mut out,
                                        parenthesized_branch_case_indent,
                                        0,
                                        &mut at_line_start,
                                        &mut needs_space,
                                        &mut line_indent,
                                    );
                                } else if let Some(paren_body_indent) = paren_stack
                                    .last()
                                    .and_then(|frame| frame.sibling_body_indent())
                                {
                                    newline_with(
                                        &mut out,
                                        paren_body_indent,
                                        0,
                                        &mut at_line_start,
                                        &mut needs_space,
                                        &mut line_indent,
                                    );
                                } else {
                                    newline_with(
                                        &mut out,
                                        base_indent(indent_level, open_cursor_state),
                                        1 + paren_extra,
                                        &mut at_line_start,
                                        &mut needs_space,
                                        &mut line_indent,
                                    );
                                }
                            } else if in_plsql_block {
                                let paren_extra = Self::paren_extra_depth(&paren_stack);
                                let in_case_branch_body =
                                    block_stack.last().is_some_and(|s| s == "CASE")
                                        && case_branch_started.last().copied().unwrap_or(false);
                                let previous_non_comment_token = comment_prefix_cache
                                    .previous_non_comment_token_index(idx)
                                    .and_then(|token_idx| tokens.get(token_idx));
                                let second_previous_non_comment_token = comment_prefix_cache
                                    .second_previous_non_comment_token_index(idx)
                                    .and_then(|token_idx| tokens.get(token_idx));
                                let follows_trailing_operator = previous_non_comment_token
                                    .and_then(Self::format_trailing_meaningful_token_from_sql_token)
                                    .is_some_and(|last| {
                                        let previous = second_previous_non_comment_token
                                            .and_then(Self::format_trailing_meaningful_token_from_sql_token);
                                        crate::sql_text::format_trailing_continuation_operator_kind_from_token_pair(
                                            previous,
                                            last,
                                        )
                                        .is_some()
                                    });
                                let parenthesized_case_indent = if in_case_branch_body {
                                    Some(
                                        paren_stack
                                            .last()
                                            .and_then(|frame| frame.sibling_body_indent())
                                            .map(|indent| indent.max(line_indent))
                                            .unwrap_or(line_indent),
                                    )
                                } else {
                                    values_case_indent.or_else(|| {
                                        paren_stack
                                            .last()
                                            .and_then(|frame| frame.sibling_body_indent())
                                            .or_else(|| {
                                                (paren_extra > 0).then_some(
                                                    line_indent.saturating_add(paren_extra),
                                                )
                                            })
                                            .or_else(|| {
                                                follows_trailing_operator
                                                    .then_some(line_indent.saturating_add(1))
                                            })
                                    })
                                };
                                newline_with(
                                    &mut out,
                                    parenthesized_case_indent.unwrap_or_else(|| {
                                        base_indent(indent_level, open_cursor_state)
                                    }),
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                            // In SELECT context, CASE stays inline
                        } else if should_treat_as_block_start {
                            let block_header_indent = base_indent(indent_level, open_cursor_state);
                            if !at_line_start || line_indent < block_header_indent {
                                newline_with(
                                    &mut out,
                                    block_header_indent,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                        } else if upper == "BEGIN" {
                            // BEGIN handling: check if we're inside a DECLARE block
                            let inside_declare = block_stack
                                .last()
                                .is_some_and(|s| s == "DECLARE" || s == "PACKAGE_BODY");
                            if inside_declare {
                                // DECLARE ... BEGIN - BEGIN is at same level as DECLARE.
                                // PACKAGE BODY initializer BEGIN snaps to package owner depth.
                                let begin_indent =
                                    if block_stack.last().is_some_and(|s| s == "PACKAGE_BODY") {
                                        block_indent_stack
                                            .last()
                                            .map(|frame| frame.owner_depth)
                                            .unwrap_or_else(|| indent_level.saturating_sub(1))
                                    } else {
                                        indent_level.saturating_sub(1)
                                    };
                                newline_with(
                                    &mut out,
                                    base_indent(begin_indent, open_cursor_state),
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else if !mysql_labeled_block_target_word {
                                // BEGIN inside block statements should align with current block depth.
                                newline_with(
                                    &mut out,
                                    base_indent(indent_level, open_cursor_state),
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                        }
                    }

                    let case_branch_body_line = at_line_start
                        && in_plsql_block
                        && block_stack.last().is_some_and(|s| s == "CASE")
                        && case_branch_started.last().copied().unwrap_or(false)
                        && line_indent <= base_indent(indent_level, open_cursor_state)
                        && !word
                            .as_bytes()
                            .first()
                            .is_some_and(|byte| byte.is_ascii_digit())
                        && !matches!(upper, "WHEN" | "ELSE" | "END" | "CASE");
                    let exception_branch_body_line = at_line_start
                        && in_plsql_block
                        && block_stack.last().is_some_and(|s| s == "EXCEPTION")
                        && exception_branch_started.last().copied().unwrap_or(false)
                        && !open_cursor_state.in_select()
                        && !construct.cursor_sql_active.is_active()
                        && line_indent <= base_indent(indent_level, open_cursor_state)
                        && !matches!(upper, "WHEN" | "END");
                    let mysql_handler_header_word = if mysql_declare_handler_for_clause {
                        false
                    } else {
                        mysql_handler_state.consume_word(upper)
                    };
                    if mysql_handler_state.body_line_pending() {
                        let pending_indent =
                            current_output_line_indent(&out, line_indent).saturating_add(1);
                        mysql_handler_body_indent_pending =
                            Some(mysql_handler_body_indent_pending.unwrap_or(pending_indent));
                    }
                    if case_branch_body_line || exception_branch_body_line {
                        line_indent = line_indent.saturating_add(1);
                    }
                    if mysql_handler_block_begin {
                        let handler_body_indent =
                            mysql_handler_body_indent_pending.unwrap_or_else(|| {
                                line_indent
                                    .max(base_indent(indent_level, open_cursor_state))
                                    .saturating_add(1)
                            });
                        line_indent = line_indent.max(handler_body_indent);
                        mysql_handler_body_indent_pending = None;
                    }
                    if mysql_handler_body_line_pending
                        && !mysql_handler_header_word
                        && !mysql_handler_block_begin
                    {
                        let handler_body_indent =
                            mysql_handler_body_indent_pending.unwrap_or_else(|| {
                                line_indent
                                    .max(base_indent(indent_level, open_cursor_state))
                                    .saturating_add(1)
                            });
                        line_indent = line_indent.max(handler_body_indent);
                        mysql_handler_body_indent_pending = None;
                    }
                    let mysql_on_duplicate_values_argument_line = at_line_start
                        && on_duplicate_key_update_active
                        && upper == "VALUES"
                        && paren_stack.last().is_some();
                    if mysql_on_duplicate_values_argument_line {
                        if let Some(frame) = paren_stack.last().copied() {
                            line_indent = line_indent.max(frame.open_line_indent.saturating_add(1));
                        }
                    }
                    let starts_control_condition_header = in_plsql_block
                        && matches!(upper, "IF" | "WHILE" | "ELSIF" | "ELSEIF")
                        && !mysql_scalar_if_function
                        && !matches!(current_clause.as_deref(), Some("SELECT" | "VALUES" | "SET"));
                    if starts_control_condition_header
                        && control_condition_header_stack.last().copied() != Some(line_indent)
                    {
                        control_condition_header_stack.push(line_indent);
                        control_condition_header_parenthesized_stack.push(matches!(
                            next_non_comment,
                            Some(SqlToken::Symbol(sym)) if sym == "("
                        ));
                    }
                    if !at_line_start && token_gap_contains_newline(idx) {
                        if let Some(split_end_indent) = pending_split_end_suffix_indent {
                            newline_with(
                                &mut out,
                                split_end_indent,
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        } else if !matches!(upper, "THEN" | "LOOP" | "DO") {
                            if let Some(header_indent) =
                                control_condition_header_stack.last().copied()
                            {
                                newline_with(
                                    &mut out,
                                    header_indent,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                        }
                    }
                    let control_condition_continuation_line =
                        control_condition_header_stack.last().copied().filter(|_| {
                            at_line_start
                                && !matches!(
                                    upper,
                                    "AND"
                                        | "OR"
                                        | "ELSIF"
                                        | "ELSEIF"
                                        | "ELSE"
                                        | "END"
                                        | "THEN"
                                        | "LOOP"
                                        | "DO"
                                )
                                && !matches!(current_clause.as_deref(), Some("SELECT"))
                        });
                    if let Some(header_indent) = control_condition_continuation_line {
                        line_indent = line_indent.max(header_indent);
                    }
                    if let Some(split_end_indent) = pending_split_end_suffix_indent {
                        if at_line_start {
                            line_indent = split_end_indent;
                        }
                    }
                    if at_line_start
                        && upper == "BEGIN"
                        && (block_stack.last().is_some_and(|s| s == "PACKAGE_BODY")
                            || pending_package_member_separator)
                    {
                        let package_owner_depth = block_stack
                            .last()
                            .filter(|block| block.as_str() == "PACKAGE_BODY")
                            .and_then(|_| block_indent_stack.last().map(|frame| frame.owner_depth))
                            .unwrap_or(0);
                        line_indent = package_owner_depth;
                    }
                    let opens_unterminated_plsql_label_with_embedded_lines =
                        opens_unterminated_plsql_label && word.contains('\n');
                    ensure_indent(&mut out, &mut at_line_start, line_indent);
                    if needs_space {
                        out.push(' ');
                    }
                    let rendered_word = if is_keyword && !mysql_keyword_identifier {
                        upper
                    } else {
                        word
                    };
                    if rendered_word.contains('\n') {
                        let continuation_indent =
                            if opens_unterminated_plsql_label_with_embedded_lines {
                                pending_plsql_label_body_indent.unwrap_or(line_indent)
                            } else {
                                line_indent
                            };
                        for (segment_idx, segment) in rendered_word.split('\n').enumerate() {
                            if segment_idx == 0 {
                                out.push_str(segment);
                                continue;
                            }
                            out.push('\n');
                            at_line_start = true;
                            line_indent = line_indent.max(continuation_indent);
                            if segment.is_empty() {
                                continue;
                            }
                            ensure_indent(&mut out, &mut at_line_start, line_indent);
                            out.push_str(segment);
                        }
                    } else {
                        out.push_str(rendered_word);
                    }
                    if upper == "WITH"
                        && is_keyword
                        && !mysql_keyword_identifier
                        && !with_cte_keyword_inside_function_local
                    {
                        with_cte_state.record_with_owner_depth(line_indent);
                    }
                    needs_space = true;
                    if pending_split_end_suffix_indent.is_some() {
                        if let Some(kind) = pending_split_end_suffix_kind {
                            if let Some(next_kind) = kind.advance(upper) {
                                pending_split_end_suffix_kind = Some(next_kind);
                            } else {
                                pending_split_end_suffix_kind = None;
                                pending_split_end_suffix_indent = None;
                            }
                        } else {
                            pending_split_end_suffix_indent = None;
                        }
                    }
                    if is_package_body_statement
                        && block_stack
                            .last()
                            .is_some_and(|block| block == "PACKAGE_BODY")
                        && matches!(upper, "PROCEDURE" | "FUNCTION")
                    {
                        active_package_member_name =
                            next_word.map(|word| word.to_ascii_uppercase());
                    }
                    if upper == "SELECT" {
                        select_list_layout_state.activate(out.len(), line_indent.saturating_add(1));
                    } else if upper == "WINDOW"
                        && matches!(current_clause.as_deref(), Some("WINDOW"))
                    {
                        newline_after_keyword = true;
                        newline_after_keyword_extra = 1;
                    }

                    if prev_word_upper.as_deref() == Some("COMPOUND") && upper == "TRIGGER" {
                        let mut pushed_compound_trigger_block = false;
                        if block_stack
                            .last()
                            .is_none_or(|block| block != "COMPOUND_TRIGGER")
                        {
                            push_format_block(
                                &mut block_stack,
                                &mut block_indent_stack,
                                "COMPOUND_TRIGGER",
                                indent_level,
                                indent_level,
                            );
                            pushed_compound_trigger_block = true;
                        }
                        let compound_scope = FormatScope::new(paren_stack.len(), block_stack.len());
                        compound_trigger_state.mark_compound_header(compound_scope);
                        compound_trigger_state.enter_outer_body();
                        if pushed_compound_trigger_block {
                            indent_level = indent_level.saturating_add(1);
                        }
                        trigger_header_state.clear();
                    }

                    if matches!(upper, "IS" | "AS" | "BEGIN" | "DECLARE") {
                        compound_trigger_state.begin_timing_point_body();
                    }

                    if construct.create_table_paren_expected.is_active()
                        && upper == "AS"
                        && (next_word_is("SELECT")
                            || next_word_is("WITH")
                            || next_word_is("VALUES"))
                    {
                        construct.create_table_paren_expected.deactivate();
                    }

                    // CURSOR ... IS/AS → indent the SQL body
                    if upper == "CURSOR" && in_plsql_block {
                        construct.cursor_decl_pending.activate(current_scope);
                    }
                    if matches!(upper, "IS" | "AS") && construct.cursor_decl_pending.is_active() {
                        construct.cursor_decl_pending.deactivate();
                        construct.cursor_sql_active.activate(current_scope);
                        indent_level = indent_level.max(line_indent).saturating_add(1);
                        newline_after_keyword = true;
                    }

                    // FORALL → indent the DML body
                    if upper == "FORALL" && in_plsql_block {
                        construct.forall_pending.activate(current_scope);
                    }

                    // EXECUTE IMMEDIATE tracking
                    if upper == "EXECUTE" && next_word_is("IMMEDIATE") {
                        construct.execute_immediate_active.activate(current_scope);
                    }

                    // REFERENCES → suppress ON DELETE/UPDATE (referential actions)
                    if upper == "REFERENCES" {
                        construct.referential_action_pending.activate(current_scope);
                    }
                    if construct.referential_action_pending.is_active() && upper == "ON" {
                        construct.referential_action_pending.deactivate();
                        construct.referential_on_active.activate(current_scope);
                    }
                    if construct.referential_on_active.is_active()
                        && !matches!(
                            upper,
                            "ON" | "DELETE"
                                | "UPDATE"
                                | "SET"
                                | "CASCADE"
                                | "RESTRICT"
                                | "NO"
                                | "ACTION"
                                | "NULL"
                        )
                    {
                        construct.referential_on_active.deactivate();
                    }

                    // COMMENT ON tracking
                    if upper == "COMMENT" && next_word_is("ON") {
                        construct.comment_on_active.activate(current_scope);
                    }
                    if construct.comment_on_active.is_active() && upper == "ON" {
                        construct.comment_on_active.deactivate(); // one-shot: suppress ON, then done
                    }

                    // GRANT/REVOKE tracking
                    if matches!(upper, "GRANT" | "REVOKE") && indent_level == 0 {
                        construct.grant_revoke_active.activate(current_scope);
                    }
                    // GRANT/REVOKE ends at ON (for privilege grants) or TO/FROM
                    if construct.grant_revoke_active.is_active() && matches!(upper, "TO" | "FROM") {
                        construct.grant_revoke_active.deactivate();
                    }

                    // RETURNING → suppress next INTO
                    if upper == "RETURNING" {
                        construct.returning_active.activate(current_scope);
                    }
                    if construct.returning_active.is_active() && upper == "INTO" {
                        construct.returning_active.deactivate();
                    }

                    // FETCH cursor → suppress INTO/LIMIT/BULK (PL/SQL FETCH, not SQL FETCH FIRST)
                    if upper == "FETCH" && in_plsql_block {
                        construct.fetch_active.activate(current_scope);
                    }

                    // BULK COLLECT → suppress next INTO
                    if upper == "BULK" && next_word_is("COLLECT") {
                        construct.bulk_collect_active.activate(current_scope);
                    }
                    if construct.bulk_collect_active.is_active() && upper == "INTO" {
                        construct.bulk_collect_active.deactivate();
                    }

                    // MERGE tracking
                    if upper == "MERGE" && matches!(current_clause.as_deref(), None | Some("MERGE"))
                    {
                        construct.merge_active.activate(current_scope);
                    }

                    // INSERT ALL/FIRST tracking
                    if matches!(upper, "ALL" | "FIRST")
                        && matches!(prev_word_upper.as_deref(), Some("INSERT"))
                        && !construct
                            .insert_all_active
                            .is_active_at_paren_depth(current_scope.paren_depth)
                    {
                        construct.insert_all_active.activate(current_scope);
                    }

                    let create_block_disallowed_for_compound_trigger =
                        matches!(construct.create_object.as_deref(), Some("TRIGGER"))
                            && compound_trigger_state.is_in_outer_body();
                    let starts_create_block = matches!(upper, "AS" | "IS")
                        && !as_belongs_to_constructor_result_clause
                        && !trigger_header_state.is_active()
                        && !create_block_disallowed_for_compound_trigger
                        && (construct.create_object.is_some()
                            || construct.routine_decl_pending.is_active()
                            || with_plsql_body_starts_here);
                    let starts_compound_trigger_body = starts_create_block
                        && compound_trigger_state.awaiting_outer_body_start()
                        && matches!(construct.create_object.as_deref(), Some("TRIGGER"));

                    // Handle block start - push to stack and increase indent
                    if should_treat_as_block_start {
                        push_format_block(
                            &mut block_stack,
                            &mut block_indent_stack,
                            upper,
                            indent_level,
                            line_indent,
                        );
                        indent_level = indent_level.max(line_indent).saturating_add(1);
                        if upper == "DECLARE" || upper == "IF" {
                            plsql_context_state
                                .activate(FormatScope::new(paren_stack.len(), block_stack.len()));
                        }
                    } else if upper == "BEGIN" {
                        let package_initializer_begin = pending_package_member_separator;
                        let inside_declare = block_stack
                            .last()
                            .is_some_and(|s| s == "DECLARE" || s == "PACKAGE_BODY")
                            || package_initializer_begin;
                        if inside_declare {
                            // DECLARE ... BEGIN - same block depth.
                            // PACKAGE BODY initialization BEGIN is also same depth as PACKAGE_BODY.
                            if package_initializer_begin {
                                while block_stack
                                    .last()
                                    .is_some_and(|block| block.as_str() != "PACKAGE_BODY")
                                {
                                    let _ =
                                        pop_format_block(&mut block_stack, &mut block_indent_stack);
                                }
                                indent_level = block_stack
                                    .last()
                                    .filter(|block| block.as_str() == "PACKAGE_BODY")
                                    .and_then(|_| {
                                        block_indent_stack
                                            .last()
                                            .map(|frame| frame.owner_depth.saturating_add(1))
                                    })
                                    .unwrap_or(1);
                                pending_package_member_separator = false;
                            } else if block_stack.last().is_some_and(|s| s == "DECLARE") {
                                if let Some(top) = block_stack.last_mut() {
                                    *top = "BEGIN".to_string();
                                }
                            } else if block_stack.last().is_some_and(|s| s == "PACKAGE_BODY") {
                                // Package initializer body always starts one level under
                                // the package owner, regardless of prior member-body depth.
                                indent_level = block_indent_stack
                                    .last()
                                    .map(|frame| frame.owner_depth.saturating_add(1))
                                    .unwrap_or(indent_level);
                            }
                            // DECLARE keeps current depth; PACKAGE BODY resets to owner+1.
                        } else {
                            // Standalone BEGIN block
                            push_format_block(
                                &mut block_stack,
                                &mut block_indent_stack,
                                "BEGIN",
                                indent_level,
                                line_indent,
                            );
                            indent_level += 1;
                        }
                        plsql_context_state
                            .activate(FormatScope::new(paren_stack.len(), block_stack.len()));
                        if mysql_handler_block_begin {
                            mysql_handler_begin_block_depths.push(block_stack.len());
                        }
                        if mysql_compatible && construct.create_object.is_some() {
                            // MySQL/MariaDB stored routines and triggers enter
                            // their executable body at BEGIN instead of AS/IS.
                            // Once we cross that boundary, body-local `AS`
                            // tokens such as `CAST (... AS CHAR)` or
                            // `alias AS col_name` must no longer be treated as
                            // declaration-section starters.
                            construct.create_object.clear();
                            construct.routine_decl_pending.deactivate();
                        }
                    } else if upper == "EXCEPTION" {
                        push_format_block(
                            &mut block_stack,
                            &mut block_indent_stack,
                            "EXCEPTION",
                            indent_level,
                            line_indent,
                        );
                        exception_branch_started.push(false);
                    } else if upper == "LOOP" {
                        push_format_block(
                            &mut block_stack,
                            &mut block_indent_stack,
                            "LOOP",
                            indent_level,
                            line_indent,
                        );
                        indent_level = indent_level.max(line_indent).saturating_add(1);
                        plsql_context_state
                            .activate(FormatScope::new(paren_stack.len(), block_stack.len()));
                    } else if upper == "REPEAT" {
                        push_format_block(
                            &mut block_stack,
                            &mut block_indent_stack,
                            "REPEAT",
                            indent_level,
                            line_indent,
                        );
                        indent_level += 1;
                        plsql_context_state
                            .activate(FormatScope::new(paren_stack.len(), block_stack.len()));
                    } else if upper == "CASE" {
                        push_format_block(
                            &mut block_stack,
                            &mut block_indent_stack,
                            "CASE",
                            indent_level,
                            line_indent,
                        );
                        if in_plsql_block && current_clause.is_none() {
                            case_branch_started.push(false);
                        }
                        indent_level = indent_level.max(line_indent).saturating_add(1);
                        if current_clause.is_none() {
                            plsql_context_state
                                .activate(FormatScope::new(paren_stack.len(), block_stack.len()));
                        }
                    } else if starts_create_block {
                        // Treat AS/IS in CREATE PACKAGE/PROC/FUNC/TYPE/TRIGGER and package-body routines as declaration section start
                        let is_package_body =
                            matches!(construct.create_object.as_deref(), Some("PACKAGE_BODY"));
                        let is_trigger_body =
                            matches!(construct.create_object.as_deref(), Some("TRIGGER"));
                        let package_member_owner_depth = is_package_body_statement
                            .then_some(())
                            .filter(|_| !is_package_body)
                            .and_then(|_| block_stack.last())
                            .filter(|block| block.as_str() == "PACKAGE_BODY")
                            .and_then(|_| {
                                block_indent_stack
                                    .last()
                                    .map(|frame| frame.owner_depth.saturating_add(1))
                            });
                        if starts_compound_trigger_body {
                            push_format_block(
                                &mut block_stack,
                                &mut block_indent_stack,
                                "COMPOUND_TRIGGER",
                                indent_level,
                                indent_level,
                            );
                            compound_trigger_state.enter_outer_body();
                        } else if is_package_body {
                            push_format_block(
                                &mut block_stack,
                                &mut block_indent_stack,
                                "PACKAGE_BODY",
                                indent_level,
                                line_indent,
                            );
                        } else {
                            push_format_block(
                                &mut block_stack,
                                &mut block_indent_stack,
                                "DECLARE",
                                indent_level,
                                package_member_owner_depth.unwrap_or(line_indent),
                            );
                        }
                        indent_level = if starts_compound_trigger_body {
                            indent_level.saturating_add(1)
                        } else if let Some(member_owner_depth) = package_member_owner_depth {
                            member_owner_depth.saturating_add(1)
                        } else {
                            indent_level.max(line_indent).saturating_add(1)
                        };
                        plsql_context_state
                            .activate(FormatScope::new(paren_stack.len(), block_stack.len()));
                        if is_trigger_body {
                            trigger_header_state.clear();
                        }
                        construct.create_object.clear();
                        construct.routine_decl_pending.deactivate();
                        newline_with(
                            &mut out,
                            indent_level,
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    }

                    if upper == "BEGIN" || (upper == "DECLARE" && !mysql_compound_declare) {
                        if upper == "BEGIN" {
                            trigger_header_state.clear();
                            if matches!(construct.create_object.as_deref(), Some("TRIGGER")) {
                                construct.create_object.clear();
                                construct.routine_decl_pending.deactivate();
                            }
                        }
                        compound_trigger_state.begin_timing_point_body();
                        if !mysql_begin_not_atomic_header {
                            newline_with(
                                &mut out,
                                base_indent(indent_level, open_cursor_state),
                                0,
                                &mut at_line_start,
                                &mut needs_space,
                                &mut line_indent,
                            );
                        }
                    }

                    if mysql_begin_not_atomic_header {
                        mysql_begin_not_atomic_header_open = true;
                    } else if mysql_begin_not_atomic_header_open
                        && upper == "ATOMIC"
                        && matches!(prev_word_upper.as_deref(), Some("NOT"))
                    {
                        mysql_begin_not_atomic_header_open = false;
                        newline_with(
                            &mut out,
                            base_indent(indent_level, open_cursor_state),
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    }

                    if newline_after_keyword {
                        let current_output_line_indent = out
                            .rsplit('\n')
                            .next()
                            .map(|line| {
                                Self::safe_indent_div(
                                    line.chars().take_while(|ch| *ch == ' ').count(),
                                )
                            })
                            .unwrap_or(0);
                        let case_branch_body_indent = (in_plsql_block
                            && block_stack.last().is_some_and(|s| s == "CASE")
                            && matches!(upper, "THEN" | "ELSE"))
                        .then_some(
                            current_output_line_indent.saturating_add(newline_after_keyword_extra),
                        );
                        let control_condition_body_indent = matches!(upper, "THEN" | "LOOP" | "DO")
                            .then(|| {
                                control_condition_header_stack
                                    .last()
                                    .copied()
                                    .map(|header_indent| header_indent.saturating_add(1))
                            })
                            .flatten();
                        newline_with(
                            &mut out,
                            case_branch_body_indent
                                .or(control_condition_body_indent)
                                .unwrap_or_else(|| base_indent(indent_level, open_cursor_state)),
                            usize::from(
                                control_condition_body_indent.is_none()
                                    && case_branch_body_indent.is_none(),
                            ) * newline_after_keyword_extra,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    }

                    if upper == "BETWEEN" {
                        between_paren_depths.push(current_scope.paren_depth);
                    } else if upper == "AND" && between_pending {
                        between_paren_depths.pop();
                    }
                    if matches!(upper, "THEN" | "LOOP" | "DO") {
                        let _ = control_condition_header_stack.pop();
                        let _ = control_condition_header_parenthesized_stack.pop();
                    }
                    if is_create_index_on {
                        construct.create_index_pending.deactivate();
                    }
                    exit_condition_state.on_keyword(upper);

                    // MySQL ON DUPLICATE KEY UPDATE: activate flag so that VALUES(col)
                    // inside the UPDATE assignment list is treated as a function call.
                    if upper == "UPDATE"
                        && paren_stack.is_empty()
                        && Self::is_mysql_on_duplicate_key_update(
                            tokens,
                            idx,
                            Some(token_cache.statement_word_links()),
                        )
                    {
                        on_duplicate_key_update_active = true;
                        current_clause = Some(upper.to_string());
                        select_list_layout_state.clear();
                    }
                    if should_break_condition && upper == "ON" {
                        while join_on_condition_frames
                            .last()
                            .is_some_and(|(paren_depth, _)| {
                                *paren_depth >= current_scope.paren_depth
                            })
                        {
                            join_on_condition_frames.pop();
                        }
                        join_on_condition_frames.push((current_scope.paren_depth, line_indent));
                    } else if upper == join_keyword
                        || upper == "APPLY"
                        || (clause_keywords.contains(&upper) && upper != "ON")
                    {
                        while join_on_condition_frames
                            .last()
                            .is_some_and(|(paren_depth, _)| {
                                *paren_depth >= current_scope.paren_depth
                            })
                        {
                            join_on_condition_frames.pop();
                        }
                    }

                    prev_word_upper = Some(upper.to_string());
                }
                SqlToken::String(literal) => {
                    let mysql_handler_body_line_pending =
                        at_line_start && mysql_handler_state.body_line_pending();
                    let mysql_handler_header_literal = mysql_handler_state.consume_string();
                    if mysql_handler_state.body_line_pending() {
                        let pending_indent =
                            current_output_line_indent(&out, line_indent).saturating_add(1);
                        mysql_handler_body_indent_pending =
                            Some(mysql_handler_body_indent_pending.unwrap_or(pending_indent));
                    }
                    if mysql_handler_body_line_pending && !mysql_handler_header_literal {
                        let handler_body_indent =
                            mysql_handler_body_indent_pending.unwrap_or_else(|| {
                                line_indent
                                    .max(base_indent(indent_level, open_cursor_state))
                                    .saturating_add(1)
                            });
                        line_indent = line_indent.max(handler_body_indent);
                        mysql_handler_body_indent_pending = None;
                    }
                    ensure_indent(&mut out, &mut at_line_start, line_indent);
                    if needs_space {
                        out.push(' ');
                    }
                    out.push_str(literal);
                    needs_space = true;
                    if literal.contains('\n') {
                        at_line_start = literal.ends_with('\n');
                    }
                }
                SqlToken::Comment(comment) => {
                    let mut has_leading_newline = comment.starts_with('\n');
                    let raw_comment_body = if has_leading_newline {
                        &comment[1..]
                    } else {
                        comment.as_str()
                    };
                    let trimmed_comment = raw_comment_body.trim_end_matches('\n');
                    let is_block_comment =
                        trimmed_comment.starts_with("/*") && trimmed_comment.ends_with("*/");
                    let is_hint_comment = trimmed_comment.starts_with("/*+");
                    let hint_after_select =
                        is_hint_comment && matches!(prev_word_upper.as_deref(), Some("SELECT"));
                    if hint_after_select {
                        has_leading_newline = false;
                        trim_trailing_space(&mut out);
                        if out.ends_with('\n') {
                            out.pop();
                        }
                        at_line_start = false;
                    }
                    let comment_body = if has_leading_newline {
                        &comment[1..]
                    } else {
                        raw_comment_body
                    };
                    let is_multiline_block_comment =
                        is_block_comment && trimmed_comment.contains('\n');
                    let next_is_word_like = matches!(
                        tokens.get(idx + 1),
                        Some(SqlToken::Word(_) | SqlToken::String(_))
                    );
                    let in_select_list = matches!(current_clause.as_deref(), Some("SELECT"));
                    let in_set_clause = matches!(current_clause.as_deref(), Some("SET"));
                    let top_level_select_list =
                        in_select_list && suppress_comma_break_depth == 0 && paren_stack.is_empty();
                    let top_level_set_list =
                        in_set_clause && suppress_comma_break_depth == 0 && paren_stack.is_empty();
                    let active_list_layout = select_list_layout_state.has_active_indent();
                    let comment_structural_prefix = comment_prefix_cache.prefix_before(idx);
                    let previous_non_comment_token = comment_prefix_cache
                        .previous_non_comment_token_index(idx)
                        .and_then(|token_idx| tokens.get(token_idx));
                    let second_previous_non_comment_token = comment_prefix_cache
                        .second_previous_non_comment_token_index(idx)
                        .and_then(|token_idx| tokens.get(token_idx));
                    let mut keeps_next_line_continuation =
                        Self::comment_keeps_next_line_continuation_for_prefix(
                            comment_structural_prefix,
                            second_previous_non_comment_token,
                            previous_non_comment_token,
                            comment_prefix_cache.has_string_token_before(idx),
                        );
                    let attachment = Self::classify_comment_attachment(
                        &out,
                        at_line_start,
                        has_leading_newline,
                        is_multiline_block_comment,
                    );
                    let comment_ends_source_line = comment_body.contains('\n');
                    let attached_previous_keeps_inline = matches!(
                        attachment,
                        CommentAttachment::Previous
                    ) && !(comment_ends_source_line
                        && matches!(next_non_comment, Some(SqlToken::Symbol(s)) if s == ","));
                    if (top_level_select_list || top_level_set_list)
                        && !has_leading_newline
                        && !is_hint_comment
                        && !attached_previous_keeps_inline
                    {
                        force_select_list_newline(&mut out, &mut select_list_layout_state);
                    }

                    if is_multiline_block_comment
                        && !at_line_start
                        && !matches!(attachment, CommentAttachment::Previous)
                    {
                        newline_with(
                            &mut out,
                            0,
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    }

                    if matches!(
                        attachment,
                        CommentAttachment::Next | CommentAttachment::Block
                    ) && has_leading_newline
                        && !at_line_start
                    {
                        trim_trailing_space(&mut out);
                        newline_with(
                            &mut out,
                            base_indent(indent_level, open_cursor_state),
                            0,
                            &mut at_line_start,
                            &mut needs_space,
                            &mut line_indent,
                        );
                    } else if matches!(attachment, CommentAttachment::Previous) && !at_line_start {
                        trim_trailing_space(&mut out);
                        if !out.ends_with('\n') {
                            out.push(' ');
                        }
                    }

                    let comment_starts_line = at_line_start;
                    if comment_starts_line {
                        let base = base_indent(indent_level, open_cursor_state);
                        let paren_extra = Self::paren_extra_depth(&paren_stack);
                        let in_column_list = paren_stack
                            .last()
                            .is_some_and(|frame| frame.is_column_list());
                        let current_list_indent =
                            if matches!(current_clause.as_deref(), Some("SET"))
                                && construct.merge_active.is_active()
                            {
                                base
                            } else {
                                active_list_indent(
                                    indent_level,
                                    open_cursor_state,
                                    select_list_layout_state,
                                    current_clause.as_deref(),
                                    construct.merge_active.is_active(),
                                    in_column_list,
                                )
                            };
                        let next_is_comma = matches!(
                            next_non_comment,
                            Some(SqlToken::Symbol(s)) if s == ","
                        );
                        let next_is_close_paren = matches!(
                            next_non_comment,
                            Some(SqlToken::Symbol(s)) if s == ")"
                        );
                        let next_word_upper = next_non_comment.and_then(|token| {
                            if let SqlToken::Word(w) = token {
                                Some(w.to_ascii_uppercase())
                            } else {
                                None
                            }
                        });
                        let next_is_condition_keyword =
                            if let Some(upper) = next_word_upper.as_deref() {
                                condition_keywords.contains(&upper)
                                    && !(upper == "AND"
                                        && between_paren_depths.last().copied()
                                            == Some(current_scope.paren_depth))
                            } else {
                                false
                            };
                        let next_is_else = matches!(
                            next_non_comment,
                            Some(SqlToken::Word(w))
                                if w.eq_ignore_ascii_case("ELSE")
                                    || w.eq_ignore_ascii_case("ELSIF")
                                    || w.eq_ignore_ascii_case("EXCEPTION")
                        );
                        let in_clause_list_body = matches!(
                            current_clause.as_deref(),
                            Some("FROM" | "GROUP" | "HAVING" | "ORDER" | "WINDOW" | "INTO")
                        );
                        let in_confirmed_list = in_set_clause
                            || in_clause_list_body
                            || in_column_list
                            || ((in_select_list || active_list_layout)
                                && select_list_layout_state.is_multiline())
                            || next_is_comma
                            || next_is_condition_keyword;
                        let top_level_trailing_comment = next_non_comment.is_none()
                            && paren_stack.is_empty()
                            && block_stack.is_empty();
                        if let Some(split_end_indent) = pending_split_end_suffix_indent {
                            line_indent = split_end_indent;
                        } else if top_level_trailing_comment {
                            line_indent = 0;
                        } else if next_is_close_paren {
                            line_indent = paren_stack
                                .last()
                                .map(|frame| {
                                    if frame.closes_indented() {
                                        frame.close_indent()
                                    } else {
                                        frame.compact_multiline_close_indent()
                                    }
                                })
                                .unwrap_or(base);
                        } else if next_is_else {
                            // Align comment with ELSE/ELSIF/EXCEPTION which
                            // renders at one level below the current body in
                            // IF blocks, or at base+1 in CASE blocks.
                            // EXCEPTION drops to the enclosing BEGIN level
                            // just like ELSE does in IF blocks.
                            let in_if_block = block_stack.last().is_some_and(|s| s == "IF");
                            let in_case_block = block_stack.last().is_some_and(|s| s == "CASE");
                            let next_is_exception =
                                next_word_upper.as_deref().is_some_and(|w| w == "EXCEPTION");
                            line_indent = if next_is_exception {
                                // EXCEPTION always drops to the enclosing
                                // BEGIN level regardless of block type.
                                base_indent(indent_level.saturating_sub(1), open_cursor_state)
                            } else if in_if_block {
                                base_indent(indent_level.saturating_sub(1), open_cursor_state)
                            } else if in_case_block {
                                block_indent_stack
                                    .last()
                                    .map(|frame| frame.owner_depth.saturating_add(1))
                                    .unwrap_or_else(|| base.saturating_add(1))
                            } else {
                                base + 1 + paren_extra
                            };
                        } else if next_is_condition_keyword {
                            // Condition keywords (AND/OR/WHEN/ON) are
                            // indented at base+1, matching the token
                            // handler's paren_extra offset.
                            let case_branch_indent = next_word_upper
                                .as_deref()
                                .filter(|word| *word == "WHEN")
                                .filter(|_| block_stack.last().is_some_and(|s| s == "CASE"))
                                .and_then(|_| {
                                    block_indent_stack
                                        .last()
                                        .map(|frame| frame.owner_depth.saturating_add(1))
                                });
                            let join_condition_indent = next_word_upper
                                .as_deref()
                                .filter(|word| matches!(*word, "AND" | "OR"))
                                .and_then(|_| join_on_condition_frames.last().copied())
                                .filter(|(paren_depth, _)| {
                                    current_scope.paren_depth >= *paren_depth
                                })
                                .map(|(owner_paren_depth, owner_depth)| {
                                    owner_depth.saturating_add(1).saturating_add(
                                        current_scope.paren_depth.saturating_sub(owner_paren_depth),
                                    )
                                });
                            line_indent = case_branch_indent
                                .or(join_condition_indent)
                                .unwrap_or_else(|| {
                                    base.saturating_add(1).saturating_add(paren_extra)
                                });
                        } else if in_confirmed_list {
                            line_indent = current_list_indent;
                        } else if line_indent == 0 {
                            line_indent = paren_stack
                                .last()
                                .and_then(|frame| frame.sibling_body_indent())
                                .unwrap_or(base);
                        }
                        ensure_indent(&mut out, &mut at_line_start, line_indent);
                    }

                    let rendered_comment_body = if matches!(attachment, CommentAttachment::Previous)
                        && !comment_starts_line
                        && comment_body.trim_start().starts_with("--")
                    {
                        comment_body.trim_start()
                    } else {
                        comment_body
                    };

                    out.push_str(rendered_comment_body);

                    needs_space = true;
                    let previous_token_requires_same_depth = previous_non_comment_token
                        .is_some_and(|token| match token {
                            SqlToken::Word(word) => {
                                word.eq_ignore_ascii_case("WITH")
                                    || word.eq_ignore_ascii_case("KEEP")
                            }
                            _ => false,
                        });
                    let comment_header_continuation_kind = if previous_token_requires_same_depth {
                        Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
                    } else {
                        Self::comment_header_continuation_kind_for_prefix(comment_structural_prefix)
                    };
                    keeps_next_line_continuation |= comment_header_continuation_kind.is_some();
                    if hint_after_select {
                        if !out.ends_with('\n') {
                            out.push('\n');
                        }
                        at_line_start = true;
                        needs_space = false;
                        line_indent =
                            base_indent(indent_level, open_cursor_state).saturating_add(1);
                        select_list_layout_state = SelectListLayoutState::Multiline {
                            indent: line_indent,
                            hanging_indent_spaces: None,
                        };
                    } else if is_multiline_block_comment {
                        at_line_start = true;
                        needs_space = false;
                        if !out.ends_with('\n') {
                            out.push('\n');
                        }
                        let in_column_list = paren_stack
                            .last()
                            .is_some_and(|frame| frame.is_column_list());
                        if in_select_list
                            || in_set_clause
                            || active_list_layout
                            || in_column_list
                            || hint_after_select
                        {
                            let list_indent = active_list_indent(
                                indent_level,
                                open_cursor_state,
                                select_list_layout_state,
                                current_clause.as_deref(),
                                construct.merge_active.is_active(),
                                in_column_list,
                            );
                            line_indent = list_indent;
                            if hint_after_select {
                                select_list_layout_state = SelectListLayoutState::Multiline {
                                    indent: list_indent,
                                    hanging_indent_spaces: None,
                                };
                            }
                        } else {
                            line_indent = base_indent(indent_level, open_cursor_state);
                        }
                    } else if comment_body.ends_with('\n') || comment_body.contains('\n') {
                        at_line_start = true;
                        needs_space = false;
                        let starts_after_open_paren = previous_non_comment_token.is_some_and(
                            |token| matches!(token, SqlToken::Symbol(sym) if sym == "("),
                        );
                        if starts_after_open_paren && !comment_starts_line {
                            let opener_body_indent = paren_stack
                                .last()
                                .map(|frame| {
                                    if frame.opens_indented() {
                                        base_indent(indent_level, open_cursor_state)
                                    } else {
                                        current_output_line_indent(&out, line_indent)
                                            .saturating_add(1)
                                    }
                                })
                                .unwrap_or_else(|| {
                                    current_output_line_indent(&out, line_indent).saturating_add(1)
                                });
                            inline_comment_continuation_state =
                                InlineCommentContinuationState::Operand {
                                    indent: opener_body_indent,
                                };
                        } else if keeps_next_line_continuation && !comment_starts_line {
                            let in_column_list = paren_stack
                                .last()
                                .is_some_and(|frame| frame.is_column_list());
                            let base = base_indent(indent_level, open_cursor_state);
                            let list_continuation_indent =
                                if matches!(current_clause.as_deref(), Some("SET"))
                                    && construct.merge_active.is_active()
                                {
                                    base
                                } else {
                                    active_list_indent(
                                        indent_level,
                                        open_cursor_state,
                                        select_list_layout_state,
                                        current_clause.as_deref(),
                                        construct.merge_active.is_active(),
                                        in_column_list,
                                    )
                                };
                            let continuation_indent = if matches!(
                                comment_header_continuation_kind,
                                Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
                            ) {
                                line_indent
                            } else if in_select_list
                                || in_set_clause
                                || active_list_layout
                                || in_column_list
                                || hint_after_select
                            {
                                list_continuation_indent
                            } else if matches!(current_clause.as_deref(), Some("ON" | "USING")) {
                                line_indent
                            } else if comment_header_continuation_kind.is_some() {
                                let fallback_indent = base.saturating_add(usize::from(
                                    current_clause.is_some() || suppress_comma_break_depth > 0,
                                ));
                                let min_indent = Self::resolve_comment_header_continuation_indent(
                                    comment_header_continuation_kind,
                                    line_indent,
                                    base,
                                    line_indent,
                                    fallback_indent,
                                );
                                line_indent.max(min_indent)
                            } else {
                                line_indent.max(
                                    base.saturating_add(usize::from(
                                        current_clause.is_some() || suppress_comma_break_depth > 0,
                                    )),
                                )
                            };
                            inline_comment_continuation_state =
                                InlineCommentContinuationState::Operand {
                                    indent: continuation_indent,
                                };
                        } else {
                            let in_column_list = paren_stack
                                .last()
                                .is_some_and(|frame| frame.is_column_list());
                            if in_select_list
                                || in_set_clause
                                || active_list_layout
                                || in_column_list
                                || hint_after_select
                            {
                                let list_indent =
                                    if in_set_clause && construct.merge_active.is_active() {
                                        base_indent(indent_level, open_cursor_state)
                                    } else {
                                        active_list_indent(
                                            indent_level,
                                            open_cursor_state,
                                            select_list_layout_state,
                                            current_clause.as_deref(),
                                            construct.merge_active.is_active(),
                                            in_column_list,
                                        )
                                    };
                                line_indent = list_indent;
                                if (in_select_list || in_set_clause)
                                    && !select_list_layout_state.is_multiline()
                                    && comment_starts_line
                                {
                                    select_list_layout_state = SelectListLayoutState::Multiline {
                                        indent: list_indent,
                                        hanging_indent_spaces: None,
                                    };
                                }
                            }
                        }
                    } else if is_block_comment && next_is_word_like {
                        let keep_inline_alias_comment = matches!(
                            (prev_word_upper.as_deref(), tokens.get(idx + 1)),
                            (Some("AS" | "IS"), Some(SqlToken::Word(_)))
                        );
                        if !keep_inline_alias_comment {
                            if keeps_next_line_continuation {
                                let in_column_list = paren_stack
                                    .last()
                                    .is_some_and(|frame| frame.is_column_list());
                                let base = base_indent(indent_level, open_cursor_state);
                                let starts_after_open_paren =
                                    previous_non_comment_token.is_some_and(
                                        |token| {
                                            matches!(token, SqlToken::Symbol(sym) if sym == "(")
                                        },
                                    );
                                let list_continuation_indent =
                                    if matches!(current_clause.as_deref(), Some("SET"))
                                        && construct.merge_active.is_active()
                                    {
                                        base
                                    } else {
                                        active_list_indent(
                                            indent_level,
                                            open_cursor_state,
                                            select_list_layout_state,
                                            current_clause.as_deref(),
                                            construct.merge_active.is_active(),
                                            in_column_list,
                                        )
                                    };
                                let continuation_indent = if starts_after_open_paren {
                                    let opener_body_indent =
                                        current_output_line_indent(&out, line_indent)
                                            .saturating_add(1);
                                    paren_stack
                                        .last()
                                        .and_then(|frame| frame.sibling_body_indent())
                                        .map(|indent| indent.min(opener_body_indent))
                                        .unwrap_or(opener_body_indent)
                                } else if matches!(
                                    comment_header_continuation_kind,
                                    Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
                                ) {
                                    line_indent
                                } else if in_select_list
                                    || in_set_clause
                                    || active_list_layout
                                    || in_column_list
                                    || hint_after_select
                                {
                                    list_continuation_indent
                                } else if matches!(
                                    current_clause.as_deref(),
                                    Some("ON" | "USING")
                                ) {
                                    line_indent
                                } else if comment_header_continuation_kind.is_some() {
                                    let fallback_indent =
                                        base.saturating_add(usize::from(
                                            current_clause.is_some()
                                                || suppress_comma_break_depth > 0,
                                        ));
                                    let min_indent =
                                        Self::resolve_comment_header_continuation_indent(
                                            comment_header_continuation_kind,
                                            line_indent,
                                            base,
                                            line_indent,
                                            fallback_indent,
                                        );
                                    line_indent.max(min_indent)
                                } else {
                                    line_indent.max(
                                        base.saturating_add(usize::from(
                                            current_clause.is_some()
                                                || suppress_comma_break_depth > 0,
                                        )),
                                    )
                                };
                                newline_with(
                                    &mut out,
                                    0,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                                inline_comment_continuation_state =
                                    InlineCommentContinuationState::Operand {
                                        indent: continuation_indent,
                                    };
                            } else {
                                let in_column_list = paren_stack
                                    .last()
                                    .is_some_and(|frame| frame.is_column_list());
                                let list_extra = if in_select_list
                                    || in_set_clause
                                    || active_list_layout
                                    || in_column_list
                                    || hint_after_select
                                {
                                    active_list_indent(
                                        indent_level,
                                        open_cursor_state,
                                        select_list_layout_state,
                                        current_clause.as_deref(),
                                        construct.merge_active.is_active(),
                                        in_column_list,
                                    )
                                    .saturating_sub(base_indent(indent_level, open_cursor_state))
                                } else {
                                    0
                                };
                                newline_with(
                                    &mut out,
                                    base_indent(indent_level, open_cursor_state),
                                    list_extra,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }
                            if hint_after_select {
                                select_list_layout_state = SelectListLayoutState::Multiline {
                                    indent: base_indent(indent_level, open_cursor_state) + 1,
                                    hanging_indent_spaces: None,
                                };
                            }
                        }
                    } else if comment_starts_line {
                    }
                }
                SqlToken::Symbol(sym) => {
                    let mysql_handler_condition_separator =
                        sym == "," && mysql_handler_state.body_line_pending();
                    mysql_handler_state.on_symbol(sym.as_str());
                    if mysql_handler_condition_separator || sym == ";" {
                        mysql_handler_body_indent_pending = None;
                    }
                    match sym.as_str() {
                        "," => {
                            with_cte_state.on_separator();
                            let next_is_inline_comment = matches!(
                                tokens.get(idx + 1),
                                Some(SqlToken::Comment(comment))
                                    if !comment.starts_with('\n') && comment.contains('\n')
                            );
                            let next_is_newline_attached_comment = matches!(
                                tokens.get(idx + 1),
                                Some(SqlToken::Comment(comment)) if comment.starts_with('\n')
                            );
                            if statement_has_with_clause
                                && matches!(current_clause.as_deref(), Some("SELECT"))
                                && !open_cursor_state.in_select()
                                && suppress_comma_break_depth == 0
                            {
                                force_select_list_newline(&mut out, &mut select_list_layout_state);
                            }
                            trim_trailing_space(&mut out);
                            if out.ends_with('\n') || at_line_start {
                                let in_column_list = paren_stack
                                    .last()
                                    .is_some_and(|frame| frame.is_column_list());
                                let previous_is_line_comment = matches!(
                                    tokens.get(idx.saturating_sub(1)),
                                    Some(SqlToken::Comment(comment))
                                        if comment.trim_start().starts_with("--")
                                );
                                let comma_starts_clause_list_item = previous_is_line_comment
                                    && matches!(
                                        current_clause.as_deref(),
                                        Some(
                                            "FROM"
                                                | "GROUP"
                                                | "HAVING"
                                                | "ORDER"
                                                | "WINDOW"
                                                | "INTO"
                                        )
                                    );
                                let aligns_clause_list_indent = comma_starts_clause_list_item
                                    || (line_indent == 0
                                        && (matches!(
                                            current_clause.as_deref(),
                                            Some("SELECT" | "SET")
                                        ) || select_list_layout_state.has_active_indent()
                                            || in_column_list
                                            || previous_is_line_comment));
                                if aligns_clause_list_indent {
                                    line_indent = active_list_indent(
                                        indent_level,
                                        open_cursor_state,
                                        select_list_layout_state,
                                        current_clause.as_deref(),
                                        construct.merge_active.is_active(),
                                        in_column_list,
                                    );
                                    if paren_stack.is_empty() {
                                        if let Some(base_depth) = query_body_clause_base_depth {
                                            line_indent =
                                                line_indent.max(base_depth.saturating_add(1));
                                        }
                                    }
                                }
                                ensure_indent(&mut out, &mut at_line_start, line_indent);
                            }
                            out.push(',');
                            while between_paren_depths
                                .last()
                                .is_some_and(|depth| *depth >= current_scope.paren_depth)
                            {
                                between_paren_depths.pop();
                            }
                            let is_with_cte_separator = with_cte_state.can_close_on_select();
                            if paren_stack
                                .last()
                                .is_some_and(|frame| frame.is_column_list())
                                || is_with_cte_separator
                            {
                                let fallback_with_cte_separator_indent =
                                    query_body_clause_base_depth
                                        .filter(|_| paren_stack.is_empty())
                                        .unwrap_or_else(|| {
                                            base_indent(indent_level, open_cursor_state)
                                        });
                                let with_cte_separator_indent = if is_with_cte_separator {
                                    with_cte_state
                                        .separator_indent(fallback_with_cte_separator_indent)
                                } else {
                                    fallback_with_cte_separator_indent
                                };
                                newline_with(
                                    &mut out,
                                    with_cte_separator_indent,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else if next_is_inline_comment {
                                needs_space = true;
                                if matches!(current_clause.as_deref(), Some("SELECT")) {
                                    let select_list_indent =
                                        base_indent(indent_level, open_cursor_state) + 1;
                                    select_list_layout_state = SelectListLayoutState::Multiline {
                                        indent: select_list_indent,
                                        hanging_indent_spaces: current_query_has_apply.then_some(
                                            select_list_layout_state
                                                .hanging_indent_spaces(&out, select_list_indent),
                                        ),
                                    };
                                }
                            } else {
                                let follows_multiline_child_close =
                                    paren_stack.last().is_some_and(|frame| {
                                        frame.has_pending_multiline_child_continuation()
                                    });
                                let active_phase1_wrapped_owner_kind =
                                    Self::active_phase1_wrapped_owner_kind_at_depth(
                                        &phase1_wrapped_owner_frames,
                                        paren_stack.len(),
                                    );
                                let parent_frame_sibling_indent = paren_stack
                                    .last()
                                    .and_then(|frame| frame.sibling_body_indent());
                                let clause_list_indent_follows_current_query_frame =
                                    paren_stack.last().is_none_or(|frame| {
                                        frame.is_query_like() || frame.is_column_list()
                                    });
                                let next_starts_parenthesized_sibling = matches!(next_non_comment, Some(SqlToken::Symbol(sym)) if sym == "(");
                                let keeps_mixed_close_key_subquery_inline =
                                    follows_multiline_child_close
                                        && token_cache
                                            .meaningful_links()
                                            .next_index(idx)
                                            .filter(|next_idx| {
                                                matches!(
                                                    tokens.get(*next_idx),
                                                    Some(SqlToken::String(_))
                                                )
                                            })
                                            .and_then(|key_idx| {
                                                token_cache
                                                    .meaningful_links()
                                                    .next_index(key_idx)
                                                    .map(|comma_idx| (key_idx, comma_idx))
                                            })
                                            .is_some_and(|(_, comma_idx)| {
                                                matches!(
                                                    tokens.get(comma_idx),
                                                    Some(SqlToken::Symbol(sym)) if sym == ","
                                                ) && token_cache
                                                    .meaningful_links()
                                                    .next_index(comma_idx)
                                                    .and_then(|open_idx| tokens.get(open_idx))
                                                    .is_some_and(|token| {
                                                        matches!(
                                                            token,
                                                            SqlToken::Symbol(sym) if sym == "("
                                                        )
                                                    })
                                            });
                                let keeps_mixed_close_value_key_inline =
                                    follows_multiline_child_close
                                        && paren_stack
                                            .last()
                                            .is_some_and(|frame| frame.suppresses_comma_breaks())
                                        && (matches!(next_non_comment, Some(SqlToken::String(_)))
                                            || matches!(
                                                next_non_comment,
                                                Some(SqlToken::Word(word))
                                                    if word.eq_ignore_ascii_case("KEY")
                                            ));
                                let allows_compact_close_continuation_comma_break =
                                    matches!(current_clause.as_deref(), Some("SELECT"))
                                        && follows_multiline_child_close
                                        && (select_list_layout_state.is_multiline()
                                            || open_cursor_state.in_select()
                                            || construct.cursor_sql_active.is_active());
                                let keeps_multiline_values_argument_comma_break = paren_stack
                                    .last()
                                    .copied()
                                    .filter(|frame| frame.suppresses_comma_breaks())
                                    .is_some_and(|frame| {
                                        matches!(current_clause.as_deref(), Some("VALUES"))
                                            && current_output_line_indent(&out, line_indent)
                                                > frame.open_line_indent
                                    });
                                let allows_structural_sibling_comma_break =
                                    follows_multiline_child_close
                                        && (next_starts_parenthesized_sibling
                                            || matches!(current_clause.as_deref(), Some("VALUES")))
                                        || keeps_multiline_values_argument_comma_break;
                                if (suppress_comma_break_depth == 0
                                    || allows_compact_close_continuation_comma_break
                                    || allows_structural_sibling_comma_break)
                                    && !keeps_mixed_close_key_subquery_inline
                                    && !keeps_mixed_close_value_key_inline
                                    && !construct.execute_immediate_active.is_active()
                                    && !construct.grant_revoke_active.is_active()
                                    && !trigger_header_state.is_active()
                                {
                                    let query_like_select_list_indent = paren_stack
                                        .last()
                                        .copied()
                                        .filter(|frame| frame.is_query_like())
                                        .filter(|_| {
                                            matches!(
                                                current_clause.as_deref(),
                                                Some("SELECT" | "SET")
                                            ) && select_list_layout_state.has_active_indent()
                                        })
                                        .map(|_| {
                                            select_list_layout_state
                                                .indentation_or(line_indent.saturating_add(1))
                                        });
                                    let current_list_indent = top_level_select_item_context
                                        .then_some(())
                                        .filter(|_| {
                                            matches!(
                                                current_clause.as_deref(),
                                                Some("SELECT" | "SET")
                                            )
                                        })
                                        .map(|_| {
                                            active_list_indent(
                                                indent_level,
                                                open_cursor_state,
                                                select_list_layout_state,
                                                current_clause.as_deref(),
                                                construct.merge_active.is_active(),
                                                false,
                                            )
                                        });
                                    let clause_list_indent = matches!(
                                        current_clause.as_deref(),
                                        Some(
                                            "FROM"
                                                | "GROUP"
                                                | "HAVING"
                                                | "ORDER"
                                                | "WINDOW"
                                                | "INTO"
                                        )
                                    )
                                    .then_some(())
                                    .filter(|_| {
                                        !matches!(
                                            active_phase1_wrapped_owner_kind,
                                            Some(
                                                FormatIndentedParenOwnerKind::WithinGroup
                                                    | FormatIndentedParenOwnerKind::Keep
                                                    | FormatIndentedParenOwnerKind::Window
                                                    | FormatIndentedParenOwnerKind::AnalyticOver
                                                    | FormatIndentedParenOwnerKind::MatchRecognize
                                                    | FormatIndentedParenOwnerKind::Pivot
                                                    | FormatIndentedParenOwnerKind::Unpivot
                                            )
                                        )
                                    })
                                    .filter(|_| clause_list_indent_follows_current_query_frame)
                                    .map(|_| {
                                        let mut list_indent = active_list_indent(
                                            indent_level,
                                            open_cursor_state,
                                            select_list_layout_state,
                                            current_clause.as_deref(),
                                            construct.merge_active.is_active(),
                                            false,
                                        );
                                        if paren_stack.is_empty() {
                                            if let Some(base_depth) = query_body_clause_base_depth {
                                                list_indent =
                                                    list_indent.max(base_depth.saturating_add(1));
                                            }
                                        }
                                        list_indent
                                    });
                                    let wrapped_owner_clause_sibling =
                                        paren_stack.last().is_some_and(|frame| {
                                            matches!(
                                                frame.kind,
                                                ParenFormatFrameKind::WrappedLayout
                                            ) && matches!(
                                                current_clause.as_deref(),
                                                Some("WINDOW" | "ORDER" | "GROUP")
                                            )
                                        });
                                    let owner_relative_parent_sibling_indent =
                                        parent_frame_sibling_indent.filter(|_| {
                                            follows_multiline_child_close
                                                || wrapped_owner_clause_sibling
                                                || matches!(
                                                    active_phase1_wrapped_owner_kind,
                                                    Some(
                                                        FormatIndentedParenOwnerKind::WithinGroup
                                                            | FormatIndentedParenOwnerKind::Keep
                                                            | FormatIndentedParenOwnerKind::Window
                                                            | FormatIndentedParenOwnerKind::AnalyticOver
                                                            | FormatIndentedParenOwnerKind::MatchRecognize
                                                            | FormatIndentedParenOwnerKind::Pivot
                                                            | FormatIndentedParenOwnerKind::Unpivot
                                                    )
                                                )
                                        });
                                    if let Some(list_indent) =
                                        query_like_select_list_indent.or(current_list_indent)
                                    {
                                        if !select_list_layout_state.is_multiline() {
                                            select_list_layout_state =
                                                SelectListLayoutState::Multiline {
                                                    indent: list_indent,
                                                    hanging_indent_spaces: None,
                                                };
                                        }
                                    }
                                    let comma_extra_indent = if mysql_handler_condition_separator
                                        || matches!(
                                            active_phase1_wrapped_owner_kind,
                                            Some(
                                                FormatIndentedParenOwnerKind::WithinGroup
                                                    | FormatIndentedParenOwnerKind::Keep
                                            )
                                        )
                                        || (matches!(current_clause.as_deref(), Some("SELECT"))
                                            && construct.cursor_sql_active.is_active())
                                    {
                                        0
                                    } else {
                                        1
                                    };
                                    let comma_follows_line_comment = matches!(
                                        tokens.get(idx.saturating_sub(1)),
                                        Some(SqlToken::Comment(comment))
                                            if comment.trim_start().starts_with("--")
                                    );
                                    let previous_non_comment_is_case_end = comment_prefix_cache
                                        .previous_non_comment_token_index(idx)
                                        .and_then(|token_idx| tokens.get(token_idx))
                                        .is_some_and(|token| {
                                            matches!(
                                                token,
                                                SqlToken::Word(word)
                                                    if word.eq_ignore_ascii_case("END")
                                            )
                                        });
                                    let case_end_sibling_indent = previous_non_comment_is_case_end
                                        .then_some(())
                                        .filter(|_| {
                                            paren_stack.last().is_some_and(|frame| {
                                                frame.suppresses_comma_breaks()
                                            })
                                        })
                                        .and_then(|_| {
                                            paren_stack.last().and_then(|frame| {
                                                (!frame.is_query_like() && !frame.is_column_list())
                                                    .then_some(
                                                        frame.open_line_indent.saturating_add(1),
                                                    )
                                            })
                                        });
                                    if matches!(current_clause.as_deref(), Some("SET"))
                                        && construct.merge_active.is_active()
                                    {
                                        let merge_set_continuation_extra =
                                            usize::from(!comma_follows_line_comment);
                                        newline_with(
                                            &mut out,
                                            base_indent(indent_level, open_cursor_state),
                                            merge_set_continuation_extra,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                    } else if let Some(case_end_sibling_indent) =
                                        case_end_sibling_indent
                                    {
                                        // CASE ... END, inside VALUES must snap the next
                                        // sibling argument back to the parent call frame.
                                        newline_with(
                                            &mut out,
                                            case_end_sibling_indent,
                                            0,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                    } else if current_query_has_apply
                                        && matches!(current_clause.as_deref(), Some("SELECT"))
                                    {
                                        // The select list is already multiline after the first comma.
                                        let select_list_indent =
                                            base_indent(indent_level, open_cursor_state) + 1;
                                        let hanging_indent_spaces = select_list_layout_state
                                            .hanging_indent_spaces(&out, select_list_indent);
                                        newline_with_spaces(
                                            &mut out,
                                            hanging_indent_spaces,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                        select_list_layout_state =
                                            SelectListLayoutState::Multiline {
                                                indent: select_list_indent,
                                                hanging_indent_spaces: Some(hanging_indent_spaces),
                                            };
                                    } else if matches!(
                                        current_clause.as_deref(),
                                        Some("SELECT" | "SET")
                                    ) && (current_token_paren_depth
                                        < line_start_token_paren_depth
                                        || follows_multiline_child_close)
                                    {
                                        // Mixed close-comma SELECT/SET siblings must snap to the
                                        // active list frame depth after the current line closes
                                        // one or more frames.
                                        let stable_root_list_indent =
                                            paren_stack.is_empty().then(|| {
                                                query_body_clause_base_depth
                                                    .unwrap_or_else(|| {
                                                        base_indent(
                                                            indent_level,
                                                            open_cursor_state,
                                                        )
                                                    })
                                                    .saturating_add(1)
                                            });
                                        let frame_based_sibling_indent =
                                            parent_frame_sibling_indent
                                                .or(stable_root_list_indent)
                                                .unwrap_or_else(|| {
                                                    select_list_layout_state.indentation_or(
                                                        active_list_indent(
                                                            indent_level,
                                                            open_cursor_state,
                                                            select_list_layout_state,
                                                            current_clause.as_deref(),
                                                            construct.merge_active.is_active(),
                                                            false,
                                                        ),
                                                    )
                                                });
                                        newline_with(
                                            &mut out,
                                            frame_based_sibling_indent,
                                            0,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                    } else if let Some(query_like_indent) =
                                        query_like_select_list_indent
                                    {
                                        let resolved_query_like_indent = query_like_indent;
                                        if !select_list_layout_state.is_multiline() {
                                            select_list_layout_state =
                                                SelectListLayoutState::Multiline {
                                                    indent: resolved_query_like_indent,
                                                    hanging_indent_spaces: None,
                                                };
                                        }
                                        newline_with(
                                            &mut out,
                                            resolved_query_like_indent,
                                            0,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                    } else if let Some(sibling_indent) =
                                        owner_relative_parent_sibling_indent
                                    {
                                        // Owner-relative wrapped frames keep comma siblings on
                                        // the frame body depth; they should not inherit
                                        // clause-local +1 continuation depth.
                                        newline_with(
                                            &mut out,
                                            sibling_indent,
                                            0,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                    } else if let Some(list_indent) = clause_list_indent {
                                        newline_with(
                                            &mut out,
                                            list_indent,
                                            0,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                    } else if top_level_select_item_context
                                        && matches!(
                                            current_clause.as_deref(),
                                            Some("SELECT" | "SET")
                                        )
                                        && select_list_layout_state.has_active_indent()
                                    {
                                        let structural_select_indent = select_list_layout_state
                                            .indentation_or(active_list_indent(
                                                indent_level,
                                                open_cursor_state,
                                                select_list_layout_state,
                                                current_clause.as_deref(),
                                                construct.merge_active.is_active(),
                                                false,
                                            ));
                                        newline_with(
                                            &mut out,
                                            structural_select_indent,
                                            0,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                    } else if let Some(sibling_indent) = parent_frame_sibling_indent
                                    {
                                        // Wrapped layout siblings must snap back to the parent
                                        // frame body depth instead of inheriting clause-local
                                        // comma indentation from the previous child.
                                        newline_with(
                                            &mut out,
                                            sibling_indent,
                                            0,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                    } else {
                                        newline_with(
                                            &mut out,
                                            base_indent(indent_level, open_cursor_state),
                                            comma_extra_indent,
                                            &mut at_line_start,
                                            &mut needs_space,
                                            &mut line_indent,
                                        );
                                    }
                                } else {
                                    if !next_is_newline_attached_comment {
                                        out.push(' ');
                                    }
                                    needs_space = false;
                                }
                            }
                        }
                        ";" => {
                            with_cte_state.on_separator();
                            let keep_tight_top_level_spacing =
                                with_cte_state.keeps_top_level_semicolon_inside_with_definitions();
                            trim_trailing_space(&mut out);
                            out.push(';');
                            current_clause = None;
                            pending_split_end_suffix_indent = None;
                            pending_split_end_suffix_kind = None;
                            join_on_condition_frames.clear();
                            on_duplicate_key_update_active = false;
                            mysql_handler_state.clear();
                            select_list_layout_state.clear();
                            open_cursor_state = OpenCursorFormatState::None;
                            open_for_select_stack.clear();
                            between_paren_depths.clear();
                            control_condition_header_stack.clear();
                            control_condition_header_parenthesized_stack.clear();
                            insert_all_branch_body_indent = None;
                            let active_exception_blocks = block_stack
                                .iter()
                                .filter(|block| block.as_str() == "EXCEPTION")
                                .count();
                            exception_branch_started.truncate(active_exception_blocks);
                            trigger_header_state.clear();
                            exit_condition_state.clear();
                            construct.execute_immediate_active.clear();
                            construct.cursor_decl_pending.clear();
                            construct.create_index_pending.clear();
                            construct.create_sequence_active.clear();
                            construct.create_synonym_active.clear();
                            construct.grant_revoke_active.clear();
                            construct.comment_on_active.clear();
                            construct.model_active.clear();
                            construct.model_reference_pending.clear();
                            construct.returning_active.clear();
                            construct.fetch_active.clear();
                            construct.bulk_collect_active.clear();
                            construct.insert_all_active.clear();
                            construct.referential_action_pending.clear();
                            construct.referential_on_active.clear();
                            if construct.merge_when_branch_active.is_active() {
                                indent_level = indent_level.saturating_sub(1);
                                construct.merge_when_branch_active.clear();
                            }
                            construct.merge_active.clear();
                            if construct.cursor_sql_active.is_active() {
                                indent_level = indent_level.saturating_sub(1);
                                construct.cursor_sql_active.clear();
                            }
                            if construct.forall_body_active.is_active() {
                                indent_level = indent_level.saturating_sub(1);
                                construct.forall_body_active.clear();
                            }
                            if pending_package_member_separator
                                && block_stack.last().is_some_and(|s| s == "PACKAGE_BODY")
                            {
                                indent_level = block_indent_stack
                                    .last()
                                    .map(|frame| frame.owner_depth.saturating_add(1))
                                    .unwrap_or(indent_level);
                            }
                            let package_initializer_next =
                                pending_package_member_separator && next_word_is("BEGIN");
                            if pending_package_member_separator
                                && (next_word_is("PROCEDURE") || next_word_is("FUNCTION"))
                            {
                                out.push_str("\n\n");
                            }
                            if !package_initializer_next {
                                pending_package_member_separator = false;
                            }
                            construct.routine_decl_pending.clear();
                            let dangling_paren_indent = paren_stack
                                .iter()
                                .map(|frame| frame.indent_level_delta())
                                .sum::<usize>();
                            if dangling_paren_indent > 0 {
                                indent_level = indent_level.saturating_sub(dangling_paren_indent);
                            }
                            suppress_comma_break_depth = 0;
                            paren_stack.clear();
                            query_body_clause_base_depth = None;
                            query_base_stack.truncate(1);
                            if let Some(base_depth) = query_base_stack.first_mut() {
                                *base_depth = None;
                            }
                            construct.pop_closed_paren_scopes(0);
                            paren_clause_restore_stack.clear();
                            phase1_wrapped_owner_frames.clear();
                            select_list_break_state.clear();
                            let should_reset_paren_tracking =
                                indent_level == 0 || block_stack.is_empty();
                            if should_reset_paren_tracking {
                                compound_trigger_state.clear();
                            }
                            let next_is_inline_line_comment = matches!(
                                tokens.get(idx + 1),
                                Some(SqlToken::Comment(comment))
                                    if !comment.starts_with('\n')
                                        && comment.trim_start().starts_with("--")
                            );
                            if !next_is_inline_line_comment {
                                newline_with(
                                    &mut out,
                                    indent_level,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                                if indent_level == 0 && !keep_tight_top_level_spacing {
                                    out.push('\n');
                                    at_line_start = true;
                                    needs_space = false;
                                }
                            }
                        }
                        "(" => {
                            with_cte_state.on_open_paren();
                            let is_query_paren = matches!(
                                next_non_comment,
                                Some(SqlToken::Word(word))
                                    if crate::sql_text::is_subquery_head_keyword(word)
                            ) && !matches!(
                                next_non_comment,
                                Some(SqlToken::Word(word))
                                    if mysql_compatible
                                        && on_duplicate_key_update_active
                                        && word.eq_ignore_ascii_case("VALUES")
                            );
                            let wraps_subquery_or_case_head =
                                Self::paren_starts_wrapped_layout_head(
                                    tokens,
                                    idx,
                                    Some(token_cache.meaningful_links()),
                                );
                            let paren_body_has_newline = Self::paren_body_contains_newline(
                                tokens,
                                token_spans.as_slice(),
                                statement,
                                idx,
                                Some(token_cache.matching_paren_close_indices()),
                            );
                            let is_analytic_over_paren = Self::paren_opens_analytic_layout(
                                current_clause.as_deref(),
                                prev_word_upper.as_deref(),
                            );
                            let multiline_clause_owner_kind =
                                Self::paren_multiline_clause_owner_kind(
                                    tokens,
                                    idx,
                                    Some(token_cache.statement_word_links()),
                                )
                                .or_else(|| {
                                    (matches!(current_clause.as_deref(), Some("WINDOW"))
                                        && matches!(prev_word_upper.as_deref(), Some("AS")))
                                    .then_some(FormatIndentedParenOwnerKind::Window)
                                });
                            let wrapped_owner_kind = multiline_clause_owner_kind.filter(|kind| {
                                Self::paren_owner_requires_wrapped_layout(
                                    tokens,
                                    idx,
                                    *kind,
                                    Some(token_cache.matching_paren_close_indices()),
                                    Some(
                                        token_cache.open_paren_multiline_child_head_prefix_counts(),
                                    ),
                                    Some(token_cache.meaningful_links()),
                                    Some(token_cache.statement_word_links()),
                                )
                            });
                            let recent_open_owner_words = Self::recent_statement_words_before(
                                tokens,
                                idx,
                                2,
                                Some(token_cache.statement_word_links()),
                            );
                            let body_contains_query_like_child = Self::matching_close_paren_index(
                                tokens,
                                idx,
                                Some(token_cache.matching_paren_close_indices()),
                            )
                            .is_some_and(|close_idx| {
                                tokens
                                    .iter()
                                    .enumerate()
                                    .take(close_idx)
                                    .skip(idx.saturating_add(1))
                                    .any(|(token_idx, token)| {
                                        matches!(
                                            token,
                                            SqlToken::Word(word)
                                                if crate::sql_text::is_subquery_head_keyword(word)
                                                    || word.eq_ignore_ascii_case("CASE")
                                        ) || (matches!(token, SqlToken::Symbol(sym) if sym == "(")
                                            && token_cache
                                                .meaningful_links()
                                                .next_index(token_idx)
                                                .and_then(|next_idx| tokens.get(next_idx))
                                                .is_some_and(|next_token| {
                                                    matches!(
                                                        next_token,
                                                        SqlToken::Word(word)
                                                            if crate::sql_text::is_subquery_head_keyword(word)
                                                                || word.eq_ignore_ascii_case("CASE")
                                                    )
                                                }))
                                    })
                            });
                            let force_within_group_wrapped_layout = recent_open_owner_words
                                .first()
                                .is_some_and(|word| word.eq_ignore_ascii_case("GROUP"))
                                && recent_open_owner_words
                                    .get(1)
                                    .is_some_and(|word| word.eq_ignore_ascii_case("WITHIN"))
                                && body_contains_query_like_child;
                            let forced_wrapped_owner_kind = force_within_group_wrapped_layout
                                .then_some(FormatIndentedParenOwnerKind::WithinGroup);
                            let is_keep_paren = matches!(prev_word_upper.as_deref(), Some("KEEP"));
                            let is_multiline_clause_paren = matches!(
                                multiline_clause_owner_kind,
                                Some(
                                    FormatIndentedParenOwnerKind::AnalyticOver
                                        | FormatIndentedParenOwnerKind::Window
                                        | FormatIndentedParenOwnerKind::MatchRecognize
                                        | FormatIndentedParenOwnerKind::Pivot
                                        | FormatIndentedParenOwnerKind::Unpivot
                                )
                            ) || is_analytic_over_paren;
                            let is_subquery = is_query_paren || is_multiline_clause_paren;
                            let is_column_list = Self::paren_opens_structured_column_list(
                                prev_word_upper.as_deref(),
                                construct.create_table_paren_expected.is_active(),
                            );
                            let preserves_mysql_on_duplicate_multiline_call = mysql_compatible
                                && on_duplicate_key_update_active
                                && !is_subquery
                                && !is_column_list
                                && multiline_clause_owner_kind.is_none()
                                && prev_word_upper.is_some()
                                && (paren_body_has_newline
                                    || Self::paren_body_has_top_level_comma(
                                        tokens,
                                        idx,
                                        Some(token_cache.matching_paren_close_indices()),
                                    ));
                            let is_multiline_routine_parameter_list = mysql_compatible
                                && Self::paren_opens_multiline_routine_parameter_list(
                                    tokens,
                                    token_spans.as_slice(),
                                    statement,
                                    idx,
                                    Some(token_cache.matching_paren_close_indices()),
                                    Some(token_cache.meaningful_links()),
                                );
                            let is_call_argument_list = Self::paren_opens_call_argument_list(
                                tokens,
                                idx,
                                Some(token_cache.statement_word_links()),
                            ) && (paren_body_has_newline
                                || Self::paren_body_contains_nested_multiline_child(
                                    tokens,
                                    idx,
                                    Some(token_cache.matching_paren_close_indices()),
                                    Some(
                                        token_cache.open_paren_multiline_child_head_prefix_counts(),
                                    ),
                                    Some(token_cache.meaningful_links()),
                                    Some(token_cache.statement_word_links()),
                                ));
                            let has_nested_analytic_clause_owner_child =
                                Self::paren_body_contains_nested_analytic_clause_owner(
                                    tokens,
                                    idx,
                                    Some(token_cache.matching_paren_close_indices()),
                                    Some(token_cache.statement_word_links()),
                                );
                            let wraps_function_call_child = wraps_subquery_or_case_head
                                && multiline_clause_owner_kind.is_none()
                                && wrapped_owner_kind.is_none()
                                && !force_within_group_wrapped_layout
                                && !is_analytic_over_paren
                                && !is_call_argument_list
                                && !preserves_mysql_on_duplicate_multiline_call
                                && !matches!(
                                    prev_word_upper.as_deref(),
                                    Some(
                                        "IF" | "THEN"
                                            | "ELSE"
                                            | "WHEN"
                                            | "EXISTS"
                                            | "IN"
                                            | "ANY"
                                            | "ALL"
                                            | "SOME"
                                            | "FROM"
                                            | "JOIN"
                                            | "APPLY"
                                            | "AS"
                                            | "SELECT"
                                    )
                                );
                            let paren_frame_kind = if multiline_clause_owner_kind
                                == Some(FormatIndentedParenOwnerKind::Window)
                                || is_analytic_over_paren
                                || is_call_argument_list
                                || preserves_mysql_on_duplicate_multiline_call
                            {
                                ParenFormatFrameKind::WrappedLayout
                            } else if is_subquery {
                                ParenFormatFrameKind::QueryLike
                            } else if is_column_list || is_multiline_routine_parameter_list {
                                ParenFormatFrameKind::ColumnList
                            } else if has_nested_analytic_clause_owner_child {
                                // Nested owner-relative multiline clauses inside ordinary
                                // call/expression parens (for example `... OVER (...)`) should
                                // still open an owner/body frame so sibling arguments can snap
                                // back to the parent call depth after the nested close.
                                ParenFormatFrameKind::WrappedLayout
                            } else if wrapped_owner_kind.is_some()
                                || forced_wrapped_owner_kind.is_some()
                                || (wraps_subquery_or_case_head && !wraps_function_call_child)
                            {
                                ParenFormatFrameKind::WrappedLayout
                            } else {
                                ParenFormatFrameKind::Compact
                            };
                            if Self::paren_starts_first_clause_list_item(
                                current_clause.as_deref(),
                                prev_word_upper.as_deref(),
                                is_query_paren,
                                paren_stack.len(),
                            ) {
                                newline_with(
                                    &mut out,
                                    base_indent(indent_level, open_cursor_state),
                                    1,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            } else if paren_frame_kind.opens_indented()
                                && !at_line_start
                                && out.trim_end().ends_with('(')
                            {
                                newline_with(
                                    &mut out,
                                    line_indent.saturating_add(1),
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                            }

                            let paren_started_at_line_start = at_line_start;
                            let function_like_wrapped_paren =
                                matches!(paren_frame_kind, ParenFormatFrameKind::WrappedLayout)
                                    && wraps_function_call_child;
                            let rendered_owner_line = current_rendered_line(&out);
                            let wrapped_query_owner_paren = !paren_started_at_line_start
                                && matches!(paren_frame_kind, ParenFormatFrameKind::WrappedLayout)
                                && {
                                    let mut owner_with_open = String::with_capacity(
                                        rendered_owner_line.len().saturating_add(2),
                                    );
                                    owner_with_open.push_str(rendered_owner_line.trim_end());
                                    if !owner_with_open.is_empty()
                                        && !owner_with_open.ends_with(' ')
                                    {
                                        owner_with_open.push(' ');
                                    }
                                    owner_with_open.push('(');
                                    sql_text::contextual_format_query_owner_kind(
                                        &owner_with_open,
                                        true,
                                    )
                                    .is_some()
                                };
                            let rendered_owner_depth = rendered_line_indent(rendered_owner_line);
                            let in_column_list = paren_stack
                                .last()
                                .is_some_and(|frame| frame.is_column_list());
                            let parent_frame_sibling_indent = paren_stack
                                .last()
                                .and_then(|frame| frame.sibling_body_indent());
                            let clause_family_body_indent = matches!(
                                current_clause.as_deref(),
                                Some(
                                    "SELECT"
                                        | "SET"
                                        | "ORDER"
                                        | "GROUP"
                                        | "HAVING"
                                        | "WINDOW"
                                        | "INTO"
                                        | "RETURNING"
                                )
                            )
                            .then(|| {
                                active_list_indent(
                                    indent_level,
                                    open_cursor_state,
                                    select_list_layout_state,
                                    current_clause.as_deref(),
                                    construct.merge_active.is_active(),
                                    in_column_list,
                                )
                            });
                            let previous_meaningful_is_open_paren = token_cache
                                .meaningful_links()
                                .prev_index(idx)
                                .and_then(|token_idx| tokens.get(token_idx))
                                .is_some_and(
                                    |token| matches!(token, SqlToken::Symbol(symbol) if symbol == "("),
                                );
                            let compact_function_wrapper =
                                matches!(paren_frame_kind, ParenFormatFrameKind::Compact)
                                    && (wraps_function_call_child
                                        || body_contains_query_like_child);
                            let inside_case_branch_condition =
                                block_stack.last().is_some_and(|block| block == "CASE");
                            let semantic_open_line_indent = if paren_started_at_line_start {
                                line_indent
                            } else if paren_frame_kind.opens_indented()
                                && !paren_frame_kind.is_query_like()
                                && !function_like_wrapped_paren
                            {
                                if multiline_clause_owner_kind.is_some() {
                                    rendered_owner_depth
                                } else if let Some(parent_sibling_indent) =
                                    parent_frame_sibling_indent
                                {
                                    if matches!(current_clause.as_deref(), Some("SELECT" | "SET"))
                                        && matches!(
                                            paren_frame_kind,
                                            ParenFormatFrameKind::WrappedLayout
                                        )
                                        && !previous_meaningful_is_open_paren
                                    {
                                        rendered_owner_depth
                                    } else {
                                        parent_sibling_indent.max(rendered_owner_depth)
                                    }
                                } else if previous_meaningful_is_open_paren {
                                    parent_frame_sibling_indent.unwrap_or(rendered_owner_depth)
                                } else {
                                    rendered_owner_depth
                                }
                            } else if matches!(current_clause.as_deref(), Some("VALUES" | "FROM"))
                                || matches!(
                                    prev_word_upper.as_deref(),
                                    Some("JSON_TABLE" | "XMLTABLE")
                                )
                                || wrapped_query_owner_paren
                            {
                                rendered_owner_depth
                            } else if matches!(paren_frame_kind, ParenFormatFrameKind::Compact)
                                || function_like_wrapped_paren
                            {
                                if compact_function_wrapper {
                                    if previous_meaningful_is_open_paren {
                                        parent_frame_sibling_indent.unwrap_or(rendered_owner_depth)
                                    } else if let Some(parent_sibling_indent) =
                                        parent_frame_sibling_indent
                                    {
                                        parent_sibling_indent.max(rendered_owner_depth)
                                    } else if inside_case_branch_condition
                                        && sql_text::line_starts_with_identifier_sequence_before_inline_comment(
                                            rendered_owner_line,
                                            &["WHEN"],
                                        )
                                    {
                                        rendered_owner_depth.saturating_add(1)
                                    } else {
                                        rendered_owner_depth
                                    }
                                } else if matches!(
                                    current_clause.as_deref(),
                                    Some(
                                        "SELECT"
                                            | "SET"
                                            | "ORDER"
                                            | "GROUP"
                                            | "HAVING"
                                            | "WINDOW"
                                            | "INTO"
                                            | "RETURNING"
                                    )
                                ) {
                                    base_indent(indent_level, open_cursor_state).saturating_add(1)
                                } else if previous_meaningful_is_open_paren {
                                    parent_frame_sibling_indent
                                        .unwrap_or_else(|| line_indent.saturating_add(1))
                                } else {
                                    line_indent
                                }
                            } else {
                                let parent_body_indent =
                                    (!matches!(paren_frame_kind, ParenFormatFrameKind::Compact))
                                        .then_some(parent_frame_sibling_indent)
                                        .flatten();
                                parent_body_indent
                                    .or(clause_family_body_indent)
                                    .unwrap_or(line_indent)
                            };
                            let query_like_owner_line =
                                paren_frame_kind.is_query_like().then(|| {
                                    active_query_owner_line(&out, paren_started_at_line_start)
                                        .to_string()
                                });
                            let standalone_owner_follows_opener = query_like_owner_line
                                .as_deref()
                                .is_some_and(|owner_line| owner_line.trim_end().ends_with('('));
                            let standalone_clause_list_query_item = paren_started_at_line_start
                                && paren_frame_kind.is_query_like()
                                && !standalone_owner_follows_opener
                                && ((matches!(current_clause.as_deref(), Some("SELECT" | "SET"))
                                    && select_list_layout_state.has_active_indent())
                                    || matches!(
                                        current_clause.as_deref(),
                                        Some("ORDER" | "GROUP" | "HAVING" | "WINDOW" | "INTO")
                                    ));
                            if standalone_clause_list_query_item {
                                line_indent = active_list_indent(
                                    indent_level,
                                    open_cursor_state,
                                    select_list_layout_state,
                                    current_clause.as_deref(),
                                    construct.merge_active.is_active(),
                                    false,
                                );
                            }
                            let query_like_owner_depth = query_like_owner_line
                                .as_deref()
                                .map(|owner_line| {
                                    let owner_line_open_depth =
                                        sql_text::significant_paren_depth_after_profile(
                                            0,
                                            &sql_text::significant_paren_profile(owner_line),
                                        );
                                    if standalone_clause_list_query_item {
                                        line_indent
                                    } else if paren_started_at_line_start {
                                        if owner_line.trim_end().ends_with('(') {
                                            paren_stack
                                                .last()
                                                .map(|frame| frame.open_line_indent)
                                                .unwrap_or(semantic_open_line_indent)
                                        } else {
                                            rendered_line_indent(owner_line)
                                        }
                                    } else if paren_frame_kind.is_query_like() {
                                        if sql_text::line_ends_with_identifier_sequence_before_inline_comment(
                                            owner_line,
                                            &["VALUE"],
                                        ) {
                                            paren_stack
                                                .last()
                                                .map(|frame| frame.open_line_indent)
                                                .unwrap_or(semantic_open_line_indent)
                                        } else {
                                            rendered_line_indent(owner_line)
                                                .saturating_add(owner_line_open_depth)
                                        }
                                    } else {
                                        semantic_open_line_indent
                                    }
                                })
                                .unwrap_or(line_indent);
                            let query_like_layout = query_like_owner_line.as_deref().map(|owner| {
                                Self::query_like_paren_layout(
                                    owner,
                                    query_like_owner_depth,
                                    query_base_stack.last().copied().flatten(),
                                    paren_started_at_line_start,
                                )
                            });
                            if paren_frame_kind.is_query_like()
                                && paren_started_at_line_start
                                && !standalone_clause_list_query_item
                            {
                                line_indent = query_like_layout
                                    .map(|layout| layout.close_depth)
                                    .unwrap_or(query_like_owner_depth);
                            }
                            ensure_indent(&mut out, &mut at_line_start, line_indent);
                            let keeps_aggregate_call_tight = statement_has_apply
                                && matches!(
                                    prev_word_upper.as_deref(),
                                    Some("AVG" | "COUNT" | "MAX" | "MIN")
                                );
                            let keeps_count_star_call_tight =
                                Self::count_star_call_should_stay_tight(
                                    tokens,
                                    idx,
                                    Some(token_cache.meaningful_links()),
                                    Some(token_cache.statement_word_links()),
                                );
                            let keeps_mysql_word_paren_tight = mysql_compatible
                                && Self::mysql_word_paren_should_stay_tight(
                                    tokens,
                                    idx,
                                    on_duplicate_key_update_active,
                                    Some(token_cache.meaningful_links()),
                                    Some(token_cache.statement_word_links()),
                                    Some(token_cache.matching_paren_close_indices()),
                                );
                            if needs_space
                                && !keeps_aggregate_call_tight
                                && !keeps_count_star_call_tight
                                && !keeps_mysql_word_paren_tight
                            {
                                out.push(' ');
                            }
                            out.push('(');
                            construct.create_table_paren_expected.deactivate();
                            let paren_indent_level_delta = query_like_layout
                                .map(|layout| layout.child_head_depth.saturating_sub(indent_level))
                                .unwrap_or_else(|| {
                                    if paren_frame_kind.opens_indented() {
                                        semantic_open_line_indent
                                            .saturating_add(1)
                                            .saturating_sub(indent_level)
                                    } else {
                                        paren_frame_kind.indent_level_delta()
                                    }
                                });
                            let branch_wrapper_close_indent = (paren_started_at_line_start
                                && block_stack.last().is_some_and(|block| block == "CASE")
                                && matches!(prev_word_upper.as_deref(), Some("THEN" | "ELSE")))
                            .then_some(semantic_open_line_indent.saturating_sub(1));
                            let paren_close_indent_override = query_like_layout
                                .map(|layout| layout.close_depth)
                                .or(branch_wrapper_close_indent);
                            paren_stack.push(ParenFormatFrame::new(
                                paren_frame_kind,
                                semantic_open_line_indent,
                                paren_started_at_line_start,
                                paren_indent_level_delta,
                                paren_close_indent_override,
                            ));
                            if multiline_clause_owner_kind
                                == Some(FormatIndentedParenOwnerKind::MatchRecognize)
                            {
                                construct
                                    .match_recognize_paren_depths
                                    .push(paren_stack.len());
                            }
                            if is_analytic_over_paren {
                                construct.analytic_over_paren_depths.push(paren_stack.len());
                            }
                            if multiline_clause_owner_kind
                                == Some(FormatIndentedParenOwnerKind::Window)
                            {
                                construct.window_clause_paren_depths.push(paren_stack.len());
                            }
                            if is_keep_paren {
                                construct.keep_paren_depths.push(paren_stack.len());
                            }
                            if let Some(kind) = wrapped_owner_kind.or(forced_wrapped_owner_kind) {
                                phase1_wrapped_owner_frames.push(Phase1WrappedOwnerFrame {
                                    kind,
                                    paren_depth: paren_stack.len(),
                                });
                            }
                            paren_clause_restore_stack.push(
                                if paren_frame_kind.is_query_like()
                                    || multiline_clause_owner_kind.is_some()
                                {
                                    Some(QueryLikeParenRestoreState {
                                        clause: current_clause.clone(),
                                        select_list_layout_state,
                                        statement_has_with_clause,
                                        query_body_clause_base_depth,
                                    })
                                } else {
                                    None
                                },
                            );
                            if paren_frame_kind.opens_indented() {
                                indent_level =
                                    indent_level.saturating_add(paren_indent_level_delta);
                                if let Some(layout) = query_like_layout {
                                    query_base_stack.push(Some(layout.child_head_depth));
                                }
                                let keeps_inline_comment_after_open_paren = matches!(
                                    tokens.get(idx + 1),
                                    Some(SqlToken::Comment(comment))
                                        if !comment.starts_with('\n') && comment.contains('\n')
                                );
                                if keeps_inline_comment_after_open_paren {
                                    line_indent = if matches!(
                                        paren_frame_kind,
                                        ParenFormatFrameKind::WrappedLayout
                                            | ParenFormatFrameKind::ColumnList
                                    ) {
                                        semantic_open_line_indent.saturating_add(1)
                                    } else {
                                        base_indent(indent_level, open_cursor_state)
                                    };
                                } else {
                                    let next_line_indent = query_like_layout
                                        .map(|layout| layout.child_head_depth)
                                        .unwrap_or_else(|| {
                                            if matches!(
                                                paren_frame_kind,
                                                ParenFormatFrameKind::WrappedLayout
                                                    | ParenFormatFrameKind::ColumnList
                                            ) {
                                                semantic_open_line_indent.saturating_add(1)
                                            } else {
                                                base_indent(indent_level, open_cursor_state)
                                            }
                                        });
                                    newline_with(
                                        &mut out,
                                        next_line_indent,
                                        0,
                                        &mut at_line_start,
                                        &mut needs_space,
                                        &mut line_indent,
                                    );
                                }
                            } else if paren_frame_kind.suppresses_comma_breaks() {
                                suppress_comma_break_depth += 1;
                            }
                            needs_space = false;
                        }
                        ")" => {
                            with_cte_state.on_close_paren();
                            trim_trailing_space(&mut out);
                            let paren_frame_kind =
                                paren_stack.pop().unwrap_or(ParenFormatFrame::new(
                                    ParenFormatFrameKind::Compact,
                                    0,
                                    false,
                                    0,
                                    None,
                                ));
                            if paren_frame_kind.is_query_like() && query_base_stack.len() > 1 {
                                let _ = query_base_stack.pop();
                            }
                            let restore_state = paren_clause_restore_stack.pop().unwrap_or(None);
                            let current_line =
                                active_query_owner_line(&out, at_line_start).trim_end();
                            let line_ends_with_end = current_line.ends_with("END")
                                || sql_text::line_ends_with_identifier_sequence_before_inline_comment(
                                    current_line,
                                    &["END"],
                                );
                            let line_ends_with_end_case =
                                sql_text::line_ends_with_identifier_sequence_before_inline_comment(
                                    current_line,
                                    &["END", "CASE"],
                                );
                            let close_case_paren_on_newline = !paren_frame_kind.closes_indented()
                                && (line_ends_with_end || line_ends_with_end_case)
                                && !(line_ends_with_end_case
                                    && matches!(
                                        next_non_comment,
                                        Some(SqlToken::Symbol(sym)) if sym == ";"
                                    ));
                            let close_compact_continuation_on_newline = !paren_frame_kind
                                .closes_indented()
                                && (paren_frame_kind.has_pending_multiline_child_continuation()
                                    || paren_frame_kind.has_simple_multiline_child_tail());
                            let close_compact_before_parent_close =
                                close_compact_continuation_on_newline
                                    && matches!(
                                        next_non_comment,
                                        Some(SqlToken::Symbol(sym)) if sym == ")"
                                    );
                            let close_follows_child_close_line =
                                current_rendered_line(&out).trim() == ")";
                            if paren_frame_kind.suppresses_comma_breaks() {
                                suppress_comma_break_depth =
                                    suppress_comma_break_depth.saturating_sub(1);
                            }
                            if paren_frame_kind.closes_indented() {
                                indent_level = indent_level
                                    .saturating_sub(paren_frame_kind.indent_level_delta());
                                let close_indent = if paren_frame_kind.close_indent() > 0 {
                                    paren_frame_kind.close_indent()
                                } else {
                                    base_indent(indent_level, open_cursor_state)
                                };
                                newline_with(
                                    &mut out,
                                    close_indent,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                                ensure_indent(&mut out, &mut at_line_start, line_indent);
                            } else if close_compact_continuation_on_newline
                                && !close_follows_child_close_line
                            {
                                let close_indent = if matches!(
                                    next_non_comment,
                                    Some(SqlToken::Symbol(sym)) if sym == ","
                                ) {
                                    paren_stack
                                        .last()
                                        .and_then(|frame| frame.sibling_body_indent())
                                        .unwrap_or(
                                            paren_frame_kind.compact_multiline_close_indent(),
                                        )
                                } else {
                                    paren_frame_kind.compact_multiline_close_indent()
                                };
                                newline_with(
                                    &mut out,
                                    close_indent,
                                    0,
                                    &mut at_line_start,
                                    &mut needs_space,
                                    &mut line_indent,
                                );
                                ensure_indent(&mut out, &mut at_line_start, line_indent);
                            }
                            if close_case_paren_on_newline {
                                let closes_plsql_condition_terminator =
                                    Self::tokens_continue_plsql_condition_terminator(tokens, idx);
                                let closes_control_branch_tail = (next_word_is("ELSE")
                                    || next_word_is("WHEN"))
                                    && block_stack.last().is_some_and(|block| {
                                        matches!(block.as_str(), "IF" | "WHILE")
                                    })
                                    && control_condition_header_stack.last().is_some();
                                if (in_plsql_block && closes_plsql_condition_terminator)
                                    || closes_control_branch_tail
                                {
                                    let close_case_indent_level = indent_level.saturating_sub(1);
                                    newline_with(
                                        &mut out,
                                        close_case_indent_level,
                                        0,
                                        &mut at_line_start,
                                        &mut needs_space,
                                        &mut line_indent,
                                    );
                                } else {
                                    newline_with(
                                        &mut out,
                                        paren_frame_kind.compact_multiline_close_indent(),
                                        0,
                                        &mut at_line_start,
                                        &mut needs_space,
                                        &mut line_indent,
                                    );
                                }
                                ensure_indent(&mut out, &mut at_line_start, line_indent);
                            }
                            if open_cursor_state
                                .select_depth()
                                .is_some_and(|depth| paren_stack.len() < depth)
                            {
                                open_cursor_state = open_for_select_stack
                                    .pop()
                                    .unwrap_or(OpenCursorFormatState::None);
                            }
                            if let Some(restore_state) = restore_state {
                                current_clause = restore_state.clause;
                                select_list_layout_state = restore_state.select_list_layout_state;
                                statement_has_with_clause = restore_state.statement_has_with_clause;
                                query_body_clause_base_depth =
                                    restore_state.query_body_clause_base_depth;
                            }
                            if paren_stack.is_empty()
                                && matches!(
                                    next_non_comment,
                                    Some(SqlToken::Symbol(sym)) if sym == ","
                                )
                                && select_list_layout_state.has_active_indent()
                            {
                                current_clause =
                                    Some(if matches!(current_clause.as_deref(), Some("SET")) {
                                        "SET".to_string()
                                    } else {
                                        "SELECT".to_string()
                                    });
                            }
                            construct.pop_closed_paren_scopes(paren_stack.len());
                            Self::pop_closed_phase1_wrapped_owner_frames(
                                &mut phase1_wrapped_owner_frames,
                                paren_stack.len(),
                            );
                            if at_line_start
                                && !paren_frame_kind.closes_indented()
                                && line_indent
                                    < (if matches!(
                                        next_non_comment,
                                        Some(SqlToken::Symbol(sym)) if sym == ","
                                    ) {
                                        paren_stack
                                            .last()
                                            .and_then(|frame| frame.sibling_body_indent())
                                            .unwrap_or(
                                                paren_frame_kind.compact_multiline_close_indent(),
                                            )
                                    } else {
                                        paren_frame_kind.compact_multiline_close_indent()
                                    })
                            {
                                line_indent = if matches!(
                                    next_non_comment,
                                    Some(SqlToken::Symbol(sym)) if sym == ","
                                ) {
                                    paren_stack
                                        .last()
                                        .and_then(|frame| frame.sibling_body_indent())
                                        .unwrap_or(
                                            paren_frame_kind.compact_multiline_close_indent(),
                                        )
                                } else {
                                    paren_frame_kind.compact_multiline_close_indent()
                                };
                            }
                            ensure_indent(&mut out, &mut at_line_start, line_indent);
                            out.push(')');
                            if let Some(parent_frame) = paren_stack.last_mut() {
                                if paren_frame_kind.contributes_multiline_close()
                                    && !close_compact_before_parent_close
                                {
                                    parent_frame.mark_multiline_child_closed();
                                }
                            }
                            needs_space = true;
                        }
                        "." => {
                            trim_trailing_space(&mut out);
                            out.push('.');
                            needs_space = false;
                        }
                        _ => {
                            ensure_indent(&mut out, &mut at_line_start, line_indent);
                            let is_mysql_block_label_colon =
                                Self::is_mysql_block_label_colon(tokens, idx, sym);
                            let is_plsql_attribute_prefix =
                                Self::is_plsql_attribute_prefix(sym, tokens.get(idx + 1));
                            // Don't add space between consecutive ampersands (&&var substitution)
                            let repeats_ampersand = sym == "&" && out.ends_with('&');
                            let repeats_at_sign = sym == "@" && out.ends_with('@');
                            let should_insert_space = needs_space
                                && !(repeats_ampersand
                                    || repeats_at_sign
                                    || is_mysql_block_label_colon
                                    || is_plsql_attribute_prefix);
                            if should_insert_space {
                                out.push(' ');
                            }
                            if is_mysql_block_label_colon {
                                trim_trailing_space(&mut out);
                            }
                            out.push_str(sym);
                            // For bind variables (:name) and assignment (:=), don't add space after colon
                            // Check if this is ":" and next token is a Word (bind variable)
                            let is_bind_var_colon = sym == ":"
                                && tokens
                                    .get(idx + 1)
                                    .is_some_and(|t| matches!(t, SqlToken::Word(_)));
                            // For substitution variables (&var, &&var), don't add space after &
                            let is_ampersand_prefix = sym == "&"
                                && tokens.get(idx + 1).is_some_and(|t| {
                                    matches!(t, SqlToken::Word(_))
                                        || matches!(t, SqlToken::Symbol(s) if s == "&")
                                });
                            let is_mysql_user_variable_prefix = sym == "@"
                                && tokens.get(idx + 1).is_some_and(|t| {
                                    matches!(t, SqlToken::Word(_))
                                        || matches!(t, SqlToken::Symbol(s) if s == "@")
                                });
                            needs_space = is_mysql_block_label_colon
                                || (!is_bind_var_colon
                                    && !is_ampersand_prefix
                                    && !is_mysql_user_variable_prefix
                                    && !is_plsql_attribute_prefix);
                        }
                    }
                }
            }

            idx += 1;
        }

        Self::split_inline_statement_separators(out.trim_end())
    }

    fn is_dml_clause_starter(trimmed_upper: &str) -> bool {
        crate::sql_text::starts_with_format_layout_clause(trimmed_upper)
    }

    fn fetch_into_has_multiple_targets(tokens: &[SqlToken], into_idx: usize) -> bool {
        let mut paren_depth = 0usize;
        let mut lookahead = into_idx.saturating_add(1);

        while lookahead < tokens.len() {
            match &tokens[lookahead] {
                SqlToken::Comment(comment) if comment.contains('\n') => {}
                SqlToken::Comment(_) => {}
                SqlToken::Symbol(sym) => {
                    for ch in sym.chars() {
                        match ch {
                            '(' => paren_depth = paren_depth.saturating_add(1),
                            ')' => paren_depth = paren_depth.saturating_sub(1),
                            ',' if paren_depth == 0 => return true,
                            ';' if paren_depth == 0 => return false,
                            _ => {}
                        }
                    }
                }
                SqlToken::Word(word) if paren_depth == 0 => {
                    if word.eq_ignore_ascii_case("LIMIT")
                        || word.eq_ignore_ascii_case("BULK")
                        || word.eq_ignore_ascii_case("FROM")
                        || word.eq_ignore_ascii_case("WHERE")
                    {
                        return false;
                    }
                }
                _ => {}
            }

            lookahead = lookahead.saturating_add(1);
        }

        false
    }

    #[cfg(test)]
    fn line_is_standalone_open_paren_before_inline_comment(line: &str) -> bool {
        crate::sql_text::line_is_standalone_open_paren_before_inline_comment(line)
    }

    #[cfg(test)]
    fn structural_line_upper(line: &str) -> String {
        crate::sql_text::auto_format_structural_tail(line).to_ascii_uppercase()
    }

    #[cfg(test)]
    fn line_starts_structural_operator_rhs_with_next_upper(
        line: &str,
        next_code_upper: Option<&str>,
    ) -> bool {
        if crate::sql_text::starts_with_auto_format_structural_continuation_boundary_without_expression_owner(line) {
            return true;
        }

        if !Self::line_is_standalone_open_paren_before_inline_comment(line) {
            return false;
        }

        next_code_upper.is_some_and(|next_upper| {
            crate::sql_text::SUBQUERY_HEAD_KEYWORDS
                .iter()
                .any(|keyword| crate::sql_text::starts_with_keyword_token(next_upper, keyword))
        })
    }

    #[cfg(test)]
    fn line_starts_structural_operator_rhs(line: &str, next_code_trimmed: Option<&str>) -> bool {
        let next_code_upper = next_code_trimmed.map(Self::structural_line_upper);
        Self::line_starts_structural_operator_rhs_with_next_upper(line, next_code_upper.as_deref())
    }

    /// Returns `true` when `line` contains a CASE keyword that is not closed
    /// by a matching END on the same line.  This detects mid-line CASE
    /// expressions such as `SELECT col, CASE` or `SET col = CASE` so that
    /// the formatter can open a [`DmlCaseLayoutFrame`] even when the CASE
    /// keyword does not start the line.
    #[cfg(test)]
    fn line_has_trailing_unclosed_case(line: &str) -> bool {
        let tokens = super::query_text::tokenize_sql(line);
        let mut open_cases = 0usize;
        let mut prev_was_end = false;

        for token in &tokens {
            if let SqlToken::Word(word) = token {
                if word.eq_ignore_ascii_case("CASE") {
                    if prev_was_end {
                        // `END CASE` — this closes a CASE, not opens one.
                        open_cases = open_cases.saturating_sub(1);
                        prev_was_end = false;
                    } else {
                        open_cases += 1;
                    }
                } else {
                    if word.eq_ignore_ascii_case("END") {
                        // Bare END (without CASE qualifier) also closes a CASE.
                        open_cases = open_cases.saturating_sub(1);
                    }
                    prev_was_end = word.eq_ignore_ascii_case("END");
                }
            } else {
                prev_was_end = false;
            }
        }

        open_cases > 0
    }

    fn paren_multiline_clause_owner_kind(
        tokens: &[SqlToken],
        open_idx: usize,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> Option<FormatIndentedParenOwnerKind> {
        const MAX_PRECEDING_WORDS: usize = 8;

        let mut preceding_words = Self::recent_statement_words_before(
            tokens,
            open_idx,
            MAX_PRECEDING_WORDS,
            statement_word_links,
        );

        if preceding_words.is_empty() {
            return None;
        }

        preceding_words.reverse();
        let mut candidate = preceding_words.join(" ");
        candidate.push_str(" (");
        crate::sql_text::format_indented_paren_owner_kind(&candidate)
    }

    fn matching_close_paren_index(
        tokens: &[SqlToken],
        open_idx: usize,
        matching_paren_close_indices: Option<&[Option<usize>]>,
    ) -> Option<usize> {
        if let Some(close_idx) = matching_paren_close_indices
            .and_then(|indices| indices.get(open_idx))
            .copied()
            .flatten()
        {
            return Some(close_idx);
        }

        let mut paren_depth = 0usize;

        for (idx, token) in tokens.iter().enumerate().skip(open_idx) {
            match token {
                SqlToken::Symbol(sym) if sym == "(" => {
                    paren_depth = paren_depth.saturating_add(1);
                }
                SqlToken::Symbol(sym) if sym == ")" => {
                    paren_depth = paren_depth.saturating_sub(1);
                    if paren_depth == 0 {
                        return Some(idx);
                    }
                }
                _ => {}
            }
        }

        None
    }

    fn paren_body_contains_nested_multiline_child(
        tokens: &[SqlToken],
        open_idx: usize,
        matching_paren_close_indices: Option<&[Option<usize>]>,
        open_paren_multiline_child_head_prefix_counts: Option<&[usize]>,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let Some(close_idx) =
            Self::matching_close_paren_index(tokens, open_idx, matching_paren_close_indices)
        else {
            return false;
        };

        if let Some(prefix_counts) = open_paren_multiline_child_head_prefix_counts {
            let start = open_idx.saturating_add(1).min(tokens.len());
            let end = close_idx.min(tokens.len());
            if end <= start {
                return false;
            }

            let start_count = prefix_counts.get(start).copied().unwrap_or(0);
            let end_count = prefix_counts.get(end).copied().unwrap_or(start_count);
            return end_count > start_count;
        }

        for idx in open_idx.saturating_add(1)..close_idx {
            if !matches!(tokens.get(idx), Some(SqlToken::Symbol(sym)) if sym == "(") {
                continue;
            }

            let next_non_comment_idx = meaningful_token_links
                .and_then(|links| links.next_index(idx))
                .or_else(|| {
                    tokens
                        .iter()
                        .enumerate()
                        .skip(idx.saturating_add(1))
                        .find(|(_, token)| !matches!(token, SqlToken::Comment(_)))
                        .map(|(token_idx, _)| token_idx)
                });
            let next_non_comment = next_non_comment_idx.and_then(|token_idx| tokens.get(token_idx));
            let opens_query_like_child = matches!(
                next_non_comment,
                Some(SqlToken::Word(word))
                    if crate::sql_text::is_subquery_head_keyword(word)
            );
            let opens_wrapped_layout_child =
                Self::paren_starts_wrapped_layout_head(tokens, idx, meaningful_token_links);
            let opens_owner_relative_child =
                Self::paren_multiline_clause_owner_kind(tokens, idx, statement_word_links)
                    .is_some();
            let prev_word_upper = statement_word_links
                .and_then(|links| links.prev_word_index(idx))
                .and_then(|token_idx| tokens.get(token_idx))
                .and_then(|token| match token {
                    SqlToken::Word(word) => Some(word.to_ascii_uppercase()),
                    _ => None,
                })
                .or_else(|| Self::previous_word_upper(tokens, idx).map(|(word, _)| word));
            let opens_column_list_child =
                Self::paren_opens_structured_column_list(prev_word_upper.as_deref(), false);

            if opens_query_like_child
                || opens_wrapped_layout_child
                || opens_owner_relative_child
                || opens_column_list_child
            {
                return true;
            }
        }

        false
    }

    fn paren_body_contains_nested_analytic_clause_owner(
        tokens: &[SqlToken],
        open_idx: usize,
        matching_paren_close_indices: Option<&[Option<usize>]>,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        let Some(close_idx) =
            Self::matching_close_paren_index(tokens, open_idx, matching_paren_close_indices)
        else {
            return false;
        };

        for idx in open_idx.saturating_add(1)..close_idx {
            if !matches!(tokens.get(idx), Some(SqlToken::Symbol(sym)) if sym == "(") {
                continue;
            }

            if let Some(owner_kind) =
                Self::paren_multiline_clause_owner_kind(tokens, idx, statement_word_links)
            {
                if matches!(
                    owner_kind,
                    FormatIndentedParenOwnerKind::AnalyticOver
                        | FormatIndentedParenOwnerKind::WithinGroup
                        | FormatIndentedParenOwnerKind::Keep
                ) {
                    return true;
                }
            }
        }

        false
    }

    fn paren_body_has_top_level_comma(
        tokens: &[SqlToken],
        open_idx: usize,
        matching_paren_close_indices: Option<&[Option<usize>]>,
    ) -> bool {
        let Some(close_idx) =
            Self::matching_close_paren_index(tokens, open_idx, matching_paren_close_indices)
        else {
            return false;
        };

        let mut nested_depth = 0usize;
        for token in tokens
            .iter()
            .skip(open_idx.saturating_add(1))
            .take(close_idx.saturating_sub(open_idx.saturating_add(1)))
        {
            match token {
                SqlToken::Symbol(sym) if sym == "(" => {
                    nested_depth = nested_depth.saturating_add(1);
                }
                SqlToken::Symbol(sym) if sym == ")" => {
                    nested_depth = nested_depth.saturating_sub(1);
                }
                SqlToken::Symbol(sym) if sym == "," && nested_depth == 0 => {
                    return true;
                }
                _ => {}
            }
        }

        false
    }

    fn paren_owner_requires_wrapped_layout(
        tokens: &[SqlToken],
        open_idx: usize,
        owner_kind: FormatIndentedParenOwnerKind,
        matching_paren_close_indices: Option<&[Option<usize>]>,
        open_paren_multiline_child_head_prefix_counts: Option<&[usize]>,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
        statement_word_links: Option<&StatementWordLinks>,
    ) -> bool {
        matches!(
            owner_kind,
            FormatIndentedParenOwnerKind::WithinGroup | FormatIndentedParenOwnerKind::Keep
        ) && Self::paren_body_contains_nested_multiline_child(
            tokens,
            open_idx,
            matching_paren_close_indices,
            open_paren_multiline_child_head_prefix_counts,
            meaningful_token_links,
            statement_word_links,
        )
    }

    fn active_phase1_wrapped_owner_kind_at_depth(
        frames: &[Phase1WrappedOwnerFrame],
        paren_depth: usize,
    ) -> Option<FormatIndentedParenOwnerKind> {
        frames
            .last()
            .filter(|frame| frame.paren_depth == paren_depth)
            .map(|frame| frame.kind)
    }

    fn pop_closed_phase1_wrapped_owner_frames(
        frames: &mut Vec<Phase1WrappedOwnerFrame>,
        paren_depth: usize,
    ) {
        while frames
            .last()
            .is_some_and(|frame| paren_depth < frame.paren_depth)
        {
            frames.pop();
        }
    }

    fn paren_starts_first_clause_list_item(
        current_clause: Option<&str>,
        prev_word_upper: Option<&str>,
        is_query_paren: bool,
        paren_depth: usize,
    ) -> bool {
        if paren_depth > 0 {
            return false;
        }

        matches!(
            (current_clause, prev_word_upper),
            (Some("SELECT"), Some("SELECT"))
        ) || (is_query_paren
            && matches!(
                (current_clause, prev_word_upper),
                (Some("GROUP" | "ORDER"), Some("BY"))
            ))
    }

    fn paren_extra_depth(paren_stack: &[ParenFormatFrame]) -> usize {
        paren_stack
            .iter()
            .copied()
            .filter(|frame| frame.counts_for_paren_extra())
            .count()
    }

    fn token_can_own_wrapped_layout(previous_non_comment: Option<&SqlToken>) -> bool {
        match previous_non_comment {
            None => true,
            Some(SqlToken::Symbol(symbol)) => matches!(
                symbol.as_str(),
                "(" | ","
                    | "="
                    | ":="
                    | "+"
                    | "-"
                    | "*"
                    | "/"
                    | "||"
                    | "|"
                    | "<"
                    | ">"
                    | "<="
                    | ">="
                    | "<>"
                    | "!="
                    | "=>"
            ),
            Some(SqlToken::Word(word)) => {
                sql_text::is_oracle_sql_keyword(&word.to_ascii_uppercase())
            }
            _ => false,
        }
    }

    fn paren_starts_wrapped_layout_head(
        tokens: &[SqlToken],
        open_idx: usize,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
    ) -> bool {
        let previous_non_comment = meaningful_token_links
            .and_then(|links| links.prev_index(open_idx))
            .and_then(|token_idx| tokens.get(token_idx))
            .or_else(|| {
                tokens[..open_idx]
                    .iter()
                    .rev()
                    .find(|token| !matches!(token, SqlToken::Comment(_)))
            });
        if !Self::token_can_own_wrapped_layout(previous_non_comment) {
            return false;
        }

        let mut saw_wrapper_paren = false;

        for token in tokens.iter().skip(open_idx.saturating_add(1)) {
            match token {
                SqlToken::Comment(_) => {}
                SqlToken::Symbol(symbol) if symbol == "(" => {
                    saw_wrapper_paren = true;
                }
                SqlToken::Word(word) => {
                    if word.eq_ignore_ascii_case("CASE") {
                        return true;
                    }

                    return saw_wrapper_paren && crate::sql_text::is_subquery_head_keyword(word);
                }
                _ => return false,
            }
        }

        false
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn non_comment_tokens_prefix_text(tokens: &[SqlToken], idx: usize) -> Option<String> {
        let mut prefix = String::new();

        for token in tokens[..idx]
            .iter()
            .filter(|token| !matches!(token, SqlToken::Comment(_)))
        {
            if !prefix.is_empty() {
                prefix.push(' ');
            }
            prefix.push_str(&Self::token_text(token));
        }

        (!prefix.is_empty()).then_some(prefix)
    }

    fn comment_keeps_next_line_continuation_for_prefix(
        structural_prefix: &str,
        previous_non_comment_token: Option<&SqlToken>,
        last_non_comment_token: Option<&SqlToken>,
        has_string_token_before: bool,
    ) -> bool {
        let previous_token = previous_non_comment_token
            .and_then(Self::format_trailing_meaningful_token_from_sql_token);
        let last_token =
            last_non_comment_token.and_then(Self::format_trailing_meaningful_token_from_sql_token);

        if last_token.is_some_and(|last| {
            crate::sql_text::format_trailing_continuation_operator_kind_from_token_pair(
                previous_token,
                last,
            )
            .is_some()
        }) {
            return true;
        }

        if let Some(SqlToken::Word(last_word)) = last_non_comment_token {
            let last_upper = last_word.to_ascii_uppercase();
            if crate::sql_text::is_format_comment_continuation_keyword(last_upper.as_str()) {
                return true;
            }
        }

        !has_string_token_before
            && !structural_prefix.is_empty()
            && crate::sql_text::format_inline_comment_structural_header_continuation_kind(
                structural_prefix,
            )
            .is_some()
    }

    fn format_trailing_meaningful_token_from_sql_token(
        token: &SqlToken,
    ) -> Option<crate::sql_text::FormatTrailingMeaningfulToken<'_>> {
        match token {
            SqlToken::Word(word) => Some(crate::sql_text::FormatTrailingMeaningfulToken::Word(
                word.as_str(),
            )),
            SqlToken::Symbol(symbol) => Some(
                crate::sql_text::FormatTrailingMeaningfulToken::Symbol(symbol.as_str()),
            ),
            SqlToken::String(_) | SqlToken::Comment(_) => {
                Some(crate::sql_text::FormatTrailingMeaningfulToken::Other)
            }
        }
    }

    #[cfg_attr(not(test), allow(dead_code))]
    fn comment_header_continuation_kind(
        tokens: &[SqlToken],
        idx: usize,
    ) -> Option<crate::sql_text::FormatInlineCommentHeaderContinuationKind> {
        Self::non_comment_tokens_prefix_text(tokens, idx)
            .and_then(|prefix| crate::sql_text::format_inline_comment_continuation_kind(&prefix))
    }

    fn comment_header_continuation_kind_for_prefix(
        structural_prefix: &str,
    ) -> Option<crate::sql_text::FormatInlineCommentHeaderContinuationKind> {
        (!structural_prefix.is_empty())
            .then_some(structural_prefix)
            .and_then(crate::sql_text::format_inline_comment_continuation_kind)
    }

    fn resolve_comment_header_continuation_indent(
        continuation_kind: Option<crate::sql_text::FormatInlineCommentHeaderContinuationKind>,
        same_depth_anchor: usize,
        query_base_anchor: usize,
        current_line_depth: usize,
        fallback_indent: usize,
    ) -> usize {
        continuation_kind
            .map(|kind| {
                crate::sql_text::resolve_format_header_continuation_depth_with_anchors(
                    kind,
                    same_depth_anchor,
                    current_line_depth,
                    Some(query_base_anchor),
                )
            })
            .unwrap_or(fallback_indent)
    }

    #[cfg(test)]
    fn is_plsql_like_tokens(statement: &str, tokens: &[SqlToken]) -> bool {
        let words: Vec<&str> = tokens
            .iter()
            .filter_map(|token| match token {
                SqlToken::Word(word) => Some(word.as_str()),
                _ => None,
            })
            .collect();

        if let Some(first) = words.first().copied() {
            if first.eq_ignore_ascii_case("SELECT")
                || first.eq_ignore_ascii_case("INSERT")
                || first.eq_ignore_ascii_case("UPDATE")
                || first.eq_ignore_ascii_case("DELETE")
                || first.eq_ignore_ascii_case("MERGE")
            {
                return false;
            }
            if first.eq_ignore_ascii_case("WITH") {
                let mut next_index = 1usize;
                if words
                    .get(next_index)
                    .is_some_and(|word| word.eq_ignore_ascii_case("RECURSIVE"))
                {
                    next_index += 1;
                }
                if words.get(next_index).is_some_and(|word| {
                    word.eq_ignore_ascii_case("FUNCTION") || word.eq_ignore_ascii_case("PROCEDURE")
                }) {
                    return true;
                }
                return false;
            }
        }

        for word in &words {
            if word.eq_ignore_ascii_case("BEGIN") || word.eq_ignore_ascii_case("DECLARE") {
                return true;
            }
            if word.eq_ignore_ascii_case("CREATE") {
                let object_type = Self::parse_ddl_object_type(statement);
                return matches!(
                    object_type,
                    "Procedure"
                        | "Function"
                        | "Package"
                        | "Package Body"
                        | "Type"
                        | "Type Body"
                        | "Trigger"
                );
            }
        }

        Self::is_plsql_control_fragment(&words)
    }

    #[cfg(test)]
    fn is_plsql_control_fragment(words: &[&str]) -> bool {
        if words.is_empty() {
            return false;
        }

        let first = words[0];
        if first.eq_ignore_ascii_case("IF")
            && words.iter().any(|word| word.eq_ignore_ascii_case("THEN"))
        {
            return true;
        }

        if first.eq_ignore_ascii_case("ELSIF") || first.eq_ignore_ascii_case("ELSEIF") {
            return true;
        }

        if first.eq_ignore_ascii_case("WHILE")
            && words.iter().any(|word| word.eq_ignore_ascii_case("LOOP"))
        {
            return true;
        }

        words.windows(2).any(|pair| {
            pair[0].eq_ignore_ascii_case("END")
                && (pair[1].eq_ignore_ascii_case("IF")
                    || pair[1].eq_ignore_ascii_case("LOOP")
                    || pair[1].eq_ignore_ascii_case("CASE"))
        })
    }

    #[cfg(test)]
    fn is_plsql_like_statement(statement: &str) -> bool {
        let tokens = Self::tokenize_sql(statement);
        Self::is_plsql_like_tokens(statement, &tokens)
    }

    fn paren_opens_structured_column_list(
        prev_word_upper: Option<&str>,
        create_table_paren_expected: bool,
    ) -> bool {
        // Oracle table functions expose nested column definitions through
        // `... COLUMNS (...)`; those parentheses should format like a column
        // list instead of a generic function-argument group.
        create_table_paren_expected || matches!(prev_word_upper, Some("COLUMNS"))
    }

    fn paren_opens_multiline_routine_parameter_list(
        tokens: &[SqlToken],
        token_spans: &[SqlTokenSpan],
        statement: &str,
        open_idx: usize,
        matching_paren_close_indices: Option<&[Option<usize>]>,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
    ) -> bool {
        Self::paren_opens_routine_parameter_list(tokens, open_idx, meaningful_token_links)
            && Self::paren_body_contains_newline(
                tokens,
                token_spans,
                statement,
                open_idx,
                matching_paren_close_indices,
            )
    }

    fn paren_opens_routine_parameter_list(
        tokens: &[SqlToken],
        open_idx: usize,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
    ) -> bool {
        const MAX_LOOKBACK_TOKENS: usize = 6;

        let mut lookback = 0usize;
        let mut saw_identifier = false;

        let mut lookback_idx = meaningful_token_links
            .and_then(|links| links.prev_index(open_idx))
            .or_else(|| Self::previous_meaningful_token_index(tokens, open_idx));
        while let Some(current_idx) = lookback_idx {
            let Some(token) = tokens.get(current_idx) else {
                break;
            };
            match token {
                SqlToken::Word(word) => {
                    lookback = lookback.saturating_add(1);
                    if lookback > MAX_LOOKBACK_TOKENS {
                        return false;
                    }

                    if word.eq_ignore_ascii_case("PROCEDURE")
                        || word.eq_ignore_ascii_case("FUNCTION")
                    {
                        return saw_identifier;
                    }

                    if word.eq_ignore_ascii_case("RETURN")
                        || word.eq_ignore_ascii_case("RETURNS")
                        || word.eq_ignore_ascii_case("IN")
                        || word.eq_ignore_ascii_case("OUT")
                        || word.eq_ignore_ascii_case("INOUT")
                        || word.eq_ignore_ascii_case("DEFAULT")
                    {
                        return false;
                    }

                    saw_identifier = true;
                }
                SqlToken::Symbol(symbol) if symbol == "." => {
                    lookback = lookback.saturating_add(1);
                    if lookback > MAX_LOOKBACK_TOKENS || !saw_identifier {
                        return false;
                    }
                }
                SqlToken::String(_) => return false,
                SqlToken::Symbol(_) => return false,
                SqlToken::Comment(_) => {}
            }
            lookback_idx = meaningful_token_links
                .and_then(|links| links.prev_index(current_idx))
                .or_else(|| Self::previous_meaningful_token_index(tokens, current_idx));
        }

        false
    }

    fn paren_body_contains_newline(
        tokens: &[SqlToken],
        token_spans: &[SqlTokenSpan],
        statement: &str,
        open_idx: usize,
        matching_paren_close_indices: Option<&[Option<usize>]>,
    ) -> bool {
        if tokens.len() != token_spans.len() {
            return false;
        }

        let Some(close_idx) =
            Self::matching_close_paren_index(tokens, open_idx, matching_paren_close_indices)
        else {
            return false;
        };
        let Some(open_span) = token_spans.get(open_idx) else {
            return false;
        };
        let Some(close_span) = token_spans.get(close_idx) else {
            return false;
        };

        if open_span.end > close_span.start {
            return false;
        }

        statement
            .get(open_span.end..close_span.start)
            .is_some_and(|body| body.contains('\n'))
    }

    #[cfg(test)]
    fn parse_ddl_object_type(statement: &str) -> &'static str {
        let upper = statement.to_uppercase();
        QueryExecutor::parse_ddl_object_type(&upper)
    }

    fn format_create_table(statement: &str, mysql_compatible: bool) -> Option<String> {
        let trimmed = statement.trim();
        if trimmed.is_empty() {
            return None;
        }

        let tokens = Self::tokenize_sql(trimmed);
        if tokens.is_empty() {
            return None;
        }

        // Guard: only apply CREATE TABLE formatting when TABLE is the actual
        // object keyword in the CREATE header. This avoids false matches like
        // CREATE PACKAGE BODY ... TYPE ... IS TABLE OF ...
        let mut word_positions: Vec<(usize, String)> = Vec::new();
        for (idx, token) in tokens.iter().enumerate() {
            if let SqlToken::Word(word) = token {
                word_positions.push((idx, word.to_uppercase()));
            }
        }

        let create_word_idx = word_positions
            .iter()
            .position(|(_, word)| word == "CREATE")?;

        let mut header_idx = create_word_idx + 1;
        while let Some((_, word)) = word_positions.get(header_idx) {
            if matches!(
                word.as_str(),
                "OR" | "REPLACE" | "EDITIONABLE" | "NONEDITIONABLE"
            ) {
                header_idx += 1;
                continue;
            }
            break;
        }

        if (word_positions
            .get(header_idx)
            .is_some_and(|(_, word)| word == "GLOBAL")
            || word_positions
                .get(header_idx)
                .is_some_and(|(_, word)| word == "PRIVATE"))
            && word_positions
                .get(header_idx + 1)
                .is_some_and(|(_, word)| word == "TEMPORARY")
        {
            header_idx += 2;
        }

        let (_, create_object) = word_positions.get(header_idx)?;
        if create_object != "TABLE" {
            return None;
        }

        let mut seen_table = false;
        let mut ctas = false;
        let mut open_idx: Option<usize> = None;
        let mut close_idx: Option<usize> = None;
        let token_depths = paren_depths(&tokens);
        let mut idx = 0usize;

        while idx < tokens.len() {
            let token = &tokens[idx];
            match token {
                SqlToken::Word(word) => {
                    let upper = word.to_uppercase();
                    if !seen_table && upper == "TABLE" {
                        seen_table = true;
                    } else if seen_table
                        && upper == "AS"
                        && tokens[idx + 1..]
                            .iter()
                            .find_map(|t| match t {
                                SqlToken::Word(w) => Some(w.to_uppercase()),
                                _ => None,
                            })
                            .is_some_and(|w| w == "SELECT" || w == "WITH")
                    {
                        ctas = true;
                    }
                }
                SqlToken::Symbol(sym) if sym == "(" => {
                    if is_top_level_depth(&token_depths, idx)
                        && seen_table
                        && !ctas
                        && open_idx.is_none()
                    {
                        open_idx = Some(idx);
                    }
                }
                SqlToken::Symbol(sym) if sym == ")" => {
                    if is_depth(&token_depths, idx, 1) && open_idx.is_some() && close_idx.is_none()
                    {
                        close_idx = Some(idx);
                        break;
                    }
                }
                _ => {}
            }
            idx += 1;
        }

        let (open_idx, close_idx) = match (open_idx, close_idx) {
            (Some(open_idx), Some(close_idx)) => (open_idx, close_idx),
            _ => return None,
        };

        let prefix_tokens = &tokens[..open_idx];
        let column_tokens = &tokens[open_idx + 1..close_idx];
        let suffix_tokens = &tokens[close_idx + 1..];

        let mut columns: Vec<Vec<SqlToken>> = Vec::new();
        for group in split_top_level_symbol_groups(column_tokens, ",") {
            columns.push(group.into_iter().cloned().collect());
        }

        if columns.is_empty() {
            return None;
        }

        // (is_constraint, name, type_str, rest_str, leading_comments, trailing_comments)
        let mut formatted_cols: Vec<(bool, String, String, String, Vec<String>, Vec<String>)> =
            Vec::new();
        let mut max_name = 0usize;
        let mut max_type = 0usize;

        for column in &columns {
            let mut iter = column.iter().filter(|t| !matches!(t, SqlToken::Comment(_)));
            let first = iter.next();
            let is_constraint = match first {
                Some(SqlToken::Word(word)) => {
                    matches!(
                        word.to_uppercase().as_str(),
                        "CONSTRAINT" | "PRIMARY" | "UNIQUE" | "FOREIGN" | "CHECK"
                    )
                }
                _ => false,
            };

            // Separate leading comments (before first non-comment token)
            // from trailing comments (after first non-comment token)
            let mut leading_comments: Vec<String> = Vec::new();
            let mut trailing_comments: Vec<String> = Vec::new();
            let mut seen_code = false;
            for token in column {
                match token {
                    SqlToken::Comment(comment) => {
                        let body = comment.strip_prefix('\n').unwrap_or(comment);
                        let trimmed = body.trim_end_matches('\n');
                        if !trimmed.is_empty() {
                            if seen_code {
                                trailing_comments.push(trimmed.to_string());
                            } else {
                                leading_comments.push(trimmed.to_string());
                            }
                        }
                    }
                    _ => {
                        seen_code = true;
                    }
                }
            }

            if is_constraint {
                let non_comment_tokens: Vec<SqlToken> = column
                    .iter()
                    .filter(|t| !matches!(t, SqlToken::Comment(_)))
                    .cloned()
                    .collect();
                let text = Self::join_tokens_spaced_for_create_table(
                    &non_comment_tokens,
                    0,
                    mysql_compatible,
                );
                formatted_cols.push((
                    true,
                    text,
                    String::new(),
                    String::new(),
                    leading_comments,
                    trailing_comments,
                ));
                continue;
            }

            let mut tokens_iter = column
                .iter()
                .filter(|t| !matches!(t, SqlToken::Comment(_)))
                .peekable();
            let name_token = tokens_iter.next();
            // Preserve the original case for column names: they are identifiers, not
            // keywords, even if the word happens to match a SQL keyword (e.g. `profile`).
            let name = name_token
                .map(|t| match t {
                    SqlToken::Word(w) => w.clone(),
                    _ => Self::token_text(t),
                })
                .unwrap_or_default();

            let mut type_tokens: Vec<SqlToken> = Vec::new();
            let mut rest_tokens: Vec<SqlToken> = Vec::new();
            let mut in_type = true;

            for token in tokens_iter {
                let is_constraint_token = match token {
                    SqlToken::Word(word) => {
                        sql_text::is_format_column_constraint_keyword(word.as_str())
                    }
                    _ => false,
                };
                if in_type && is_constraint_token {
                    in_type = false;
                }
                if in_type {
                    type_tokens.push(token.clone());
                } else {
                    rest_tokens.push(token.clone());
                }
            }

            let type_str =
                Self::join_tokens_compact_for_create_table(&type_tokens, mysql_compatible);
            let rest_str =
                Self::join_tokens_spaced_for_create_table(&rest_tokens, 0, mysql_compatible);

            max_name = max_name.max(name.len());
            max_type = max_type.max(type_str.len());
            formatted_cols.push((
                false,
                name,
                type_str,
                rest_str,
                leading_comments,
                trailing_comments,
            ));
        }

        let mut out = String::new();
        let prefix = Self::join_tokens_spaced_for_create_table(prefix_tokens, 0, mysql_compatible);
        out.push_str(prefix.trim_end());
        out.push_str(" (\n");

        let indent = " ".repeat(4);
        for (idx, (is_constraint, name, type_str, rest_str, leading_comments, trailing_comments)) in
            formatted_cols.into_iter().enumerate()
        {
            // Output leading comments (originally before the column)
            for comment in &leading_comments {
                out.push_str(&indent);
                out.push_str(comment);
                out.push('\n');
            }
            out.push_str(&indent);
            if is_constraint {
                out.push_str(&name);
            } else {
                let name_pad = max_name.saturating_sub(name.len());
                let type_pad = max_type.saturating_sub(type_str.len());
                out.push_str(&name);
                if !type_str.is_empty() {
                    out.push_str(&" ".repeat(name_pad + 1));
                    out.push_str(&type_str);
                    if !rest_str.is_empty() {
                        out.push_str(&" ".repeat(type_pad + 1));
                        out.push_str(&rest_str);
                    }
                }
            }
            if idx + 1 < columns.len() {
                out.push(',');
            }
            out.push('\n');
            // Output trailing comments (originally after the column definition)
            for comment in &trailing_comments {
                out.push_str(&indent);
                out.push_str(comment);
                out.push('\n');
            }
        }
        out.push(')');

        let suffix = Self::format_create_suffix_for_create_table(suffix_tokens, mysql_compatible);
        if !suffix.is_empty() {
            out.push('\n');
            out.push_str(&suffix);
        }

        Some(out.trim_end().to_string())
    }

    fn token_text(token: &SqlToken) -> String {
        match token {
            SqlToken::Word(word) => {
                let upper = word.to_uppercase();
                if sql_text::is_oracle_sql_keyword(upper.as_str()) {
                    upper
                } else {
                    word.clone()
                }
            }
            SqlToken::String(literal) => literal.clone(),
            SqlToken::Comment(comment) => comment.clone(),
            SqlToken::Symbol(sym) => sym.clone(),
        }
    }

    fn token_text_for_create_table(
        tokens: &[SqlToken],
        idx: usize,
        mysql_compatible: bool,
        meaningful_token_links: Option<&MeaningfulTokenLinks>,
    ) -> String {
        let Some(token) = tokens.get(idx) else {
            return String::new();
        };

        if mysql_compatible {
            match token {
                SqlToken::Word(word)
                    if Self::mysql_keyword_should_render_as_identifier(
                        tokens,
                        idx,
                        None,
                        false,
                        meaningful_token_links,
                    ) =>
                {
                    word.clone()
                }
                SqlToken::Word(word) => {
                    let upper = word.to_ascii_uppercase();
                    if sql_text::is_mysql_sql_keyword(upper.as_str()) {
                        upper
                    } else {
                        word.clone()
                    }
                }
                SqlToken::String(literal) => literal.clone(),
                SqlToken::Comment(comment) => comment.clone(),
                SqlToken::Symbol(sym) => sym.clone(),
            }
        } else {
            Self::token_text(token)
        }
    }

    fn token_is_word_like(token: &SqlToken) -> bool {
        matches!(token, SqlToken::Word(_))
    }

    fn is_plsql_attribute_prefix(sym: &str, next_token: Option<&SqlToken>) -> bool {
        sym == "%" && next_token.map(Self::token_is_word_like).unwrap_or(false)
    }

    fn join_tokens_compact_for_create_table(tokens: &[SqlToken], mysql_compatible: bool) -> String {
        let mut out = String::new();
        let mut needs_space = false;
        let meaningful_token_links = mysql_compatible.then(|| MeaningfulTokenLinks::build(tokens));
        let statement_word_links = mysql_compatible.then(|| StatementWordLinks::build(tokens));
        let matching_paren_close_indices = mysql_compatible
            .then(|| FormatterTokenCache::build_matching_paren_close_indices(tokens));
        for (idx, token) in tokens.iter().enumerate() {
            let text = Self::token_text_for_create_table(
                tokens,
                idx,
                mysql_compatible,
                meaningful_token_links.as_ref(),
            );
            match token {
                SqlToken::Symbol(sym) if sym == "(" => {
                    let keeps_mysql_word_paren_tight = mysql_compatible
                        && Self::mysql_word_paren_should_stay_tight(
                            tokens,
                            idx,
                            false,
                            meaningful_token_links.as_ref(),
                            statement_word_links.as_ref(),
                            matching_paren_close_indices.as_deref(),
                        );
                    if needs_space && !keeps_mysql_word_paren_tight {
                        out.push(' ');
                    }
                    out.push_str(&text);
                    needs_space = false;
                }
                SqlToken::Symbol(sym) if sym == ")" => {
                    out.push_str(&text);
                    needs_space = true;
                }
                SqlToken::Symbol(sym) if sym == "," => {
                    out.push_str(&text);
                    out.push(' ');
                    needs_space = false;
                }
                SqlToken::Symbol(sym)
                    if Self::is_plsql_attribute_prefix(sym, tokens.get(idx + 1)) =>
                {
                    out.push_str(&text);
                    needs_space = false;
                }
                _ => {
                    if needs_space {
                        out.push(' ');
                    }
                    out.push_str(&text);
                    needs_space = true;
                }
            }
        }
        out.trim().to_string()
    }

    fn join_tokens_spaced_for_create_table(
        tokens: &[SqlToken],
        indent_level: usize,
        mysql_compatible: bool,
    ) -> String {
        let mut out = String::new();
        let mut needs_space = false;
        let indent = " ".repeat(indent_level * 4);
        let mut at_line_start = true;
        let meaningful_token_links = mysql_compatible.then(|| MeaningfulTokenLinks::build(tokens));
        let statement_word_links = mysql_compatible.then(|| StatementWordLinks::build(tokens));
        let matching_paren_close_indices = mysql_compatible
            .then(|| FormatterTokenCache::build_matching_paren_close_indices(tokens));

        for (idx, token) in tokens.iter().enumerate() {
            let text = Self::token_text_for_create_table(
                tokens,
                idx,
                mysql_compatible,
                meaningful_token_links.as_ref(),
            );
            match token {
                SqlToken::Comment(comment) => {
                    if !at_line_start {
                        out.push(' ');
                    } else if !indent.is_empty() {
                        out.push_str(&indent);
                    }
                    out.push_str(comment);
                    if comment.ends_with('\n') {
                        at_line_start = true;
                        needs_space = false;
                    } else {
                        at_line_start = false;
                        needs_space = true;
                    }
                }
                SqlToken::Symbol(sym) if sym == "." => {
                    out.push('.');
                    needs_space = false;
                    at_line_start = false;
                }
                SqlToken::Symbol(sym) if sym == "(" => {
                    let keeps_mysql_word_paren_tight = mysql_compatible
                        && Self::mysql_word_paren_should_stay_tight(
                            tokens,
                            idx,
                            false,
                            meaningful_token_links.as_ref(),
                            statement_word_links.as_ref(),
                            matching_paren_close_indices.as_deref(),
                        );
                    if needs_space && !keeps_mysql_word_paren_tight {
                        out.push(' ');
                    }
                    out.push('(');
                    needs_space = false;
                    at_line_start = false;
                }
                SqlToken::Symbol(sym) if sym == ")" => {
                    out.push(')');
                    needs_space = true;
                    at_line_start = false;
                }
                SqlToken::Symbol(sym) if sym == "," => {
                    out.push(',');
                    out.push(' ');
                    needs_space = false;
                    at_line_start = false;
                }
                SqlToken::Symbol(sym)
                    if Self::is_plsql_attribute_prefix(sym, tokens.get(idx + 1)) =>
                {
                    out.push('%');
                    needs_space = false;
                    at_line_start = false;
                }
                SqlToken::Symbol(sym) => {
                    if needs_space {
                        out.push(' ');
                    }
                    out.push_str(sym);
                    needs_space = true;
                    at_line_start = false;
                }
                _ => {
                    if at_line_start && !indent.is_empty() {
                        out.push_str(&indent);
                    }
                    if needs_space {
                        out.push(' ');
                    }
                    out.push_str(&text);
                    needs_space = true;
                    at_line_start = false;
                }
            }
        }

        out.trim().to_string()
    }

    fn format_create_suffix_for_create_table(
        tokens: &[SqlToken],
        mysql_compatible: bool,
    ) -> String {
        if tokens.is_empty() {
            return String::new();
        }

        let break_keywords = FORMAT_CREATE_SUFFIX_BREAK_KEYWORDS;

        let mut parts: Vec<Vec<SqlToken>> = Vec::new();

        for part in split_top_level_keyword_groups(tokens, break_keywords) {
            parts.push(part.into_iter().cloned().collect());
        }

        let mut out = String::new();
        for (idx, part) in parts.iter().enumerate() {
            if idx > 0 {
                out.push('\n');
            }
            out.push_str(&Self::join_tokens_spaced_for_create_table(
                part,
                0,
                mysql_compatible,
            ));
        }
        out.trim().to_string()
    }

    /// 토크나이저는 공통 로직(`query_text`)로 위임합니다.
    pub(crate) fn tokenize_sql(sql: &str) -> Vec<SqlToken> {
        Self::tokenize_sql_with_mysql_compat(sql, sql_text::mysql_compatibility_for_sql(sql, None))
    }

    fn tokenize_sql_with_mysql_compat(sql: &str, mysql_compatible: bool) -> Vec<SqlToken> {
        super::query_text::tokenize_sql_with_mysql_compat(sql, mysql_compatible)
    }

    pub(super) fn escape_sql_literal(value: &str) -> String {
        value.replace('\'', "''")
    }
}

#[cfg(test)]
mod formatter_scope_state_tests {
    use super::{FormatScope, ScopedFlag, ScopedValue, SqlEditorWidget};

    #[test]
    fn scoped_flag_same_scope_activation_is_idempotent() {
        let mut flag = ScopedFlag::default();
        let scope = FormatScope::new(0, 0);

        flag.activate(scope);
        flag.activate(scope);
        flag.deactivate();

        assert!(
            !flag.is_active(),
            "same-scope activation should not require multiple deactivations"
        );
    }

    #[test]
    fn scoped_value_restores_outer_scope_after_inner_scope_exits() {
        let mut value = ScopedValue::default();
        let outer_scope = FormatScope::new(0, 0);
        let inner_scope = FormatScope::new(1, 0);

        value.replace(outer_scope, "OUTER".to_string());
        value.replace(inner_scope, "INNER".to_string());
        assert_eq!(value.as_deref(), Some("INNER"));

        value.sync_scope(outer_scope);

        assert_eq!(
            value.as_deref(),
            Some("OUTER"),
            "scoped values should restore the outer frame after the inner scope closes"
        );
    }

    #[test]
    fn format_sql_search_cycle_scope_does_not_leak_into_following_update_set_clause() {
        let source = "WITH r (id, parent_id) AS (SELECT 1, 0 FROM dual UNION ALL SELECT id + 1, parent_id FROM r WHERE id < 2) SEARCH DEPTH FIRST BY id SET ord CYCLE id SET is_cycle TO 'Y' DEFAULT 'N' UPDATE demo SET status = 'DONE' WHERE id IN (SELECT id FROM r);";
        let formatted = SqlEditorWidget::format_sql_basic(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let leading_spaces = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let update_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("UPDATE demo"))
            .unwrap_or_else(|| panic!("UPDATE line, got:\n{}", formatted));
        let set_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("SET status = 'DONE'"))
            .unwrap_or_else(|| panic!("SET line, got:\n{}", formatted));
        let where_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("WHERE id IN ("))
            .unwrap_or_else(|| panic!("WHERE line, got:\n{}", formatted));

        assert_eq!(
            leading_spaces(lines[update_idx]),
            0,
            "UPDATE after SEARCH/CYCLE should return to top-level depth, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[set_idx]),
            0,
            "SET after SEARCH/CYCLE should open a real UPDATE SET clause instead of inheriting recursive CTE SET suppression, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[where_idx]),
            0,
            "WHERE after UPDATE SET should stay aligned with the UPDATE clause, got:\n{}",
            formatted
        );
        assert!(
            formatted.contains("SEARCH DEPTH FIRST BY id SET ord"),
            "SEARCH clause should keep its inline SET payload, got:\n{}",
            formatted
        );
        assert!(
            formatted.contains("CYCLE id SET is_cycle TO 'Y' DEFAULT 'N'"),
            "CYCLE clause should keep its inline SET payload, got:\n{}",
            formatted
        );
    }

    #[test]
    fn normalized_indent_tab_width_never_returns_zero() {
        assert!(
            SqlEditorWidget::normalized_indent_tab_width() > 0,
            "indent tab width must never be zero to avoid division/modulo panics"
        );
    }
}

