    #[test]
    fn package_body_initializer_begin_stays_at_top_level_after_case_declaration() {
        let sql = r#"CREATE OR REPLACE PACKAGE BODY fmt_pkg_extreme AS
g_last_mode VARCHAR2 (30) := 'BOOT';
FUNCTION calc_mode RETURN VARCHAR2 IS
BEGIN
  RETURN
  CASE
    WHEN 1 = 1 THEN
      'WEEKDAY_BOOT'
    ELSE
      'WEEKEND_BOOT'
  END;
END calc_mode;

BEGIN
    g_last_mode :=
    CASE
        WHEN TO_CHAR (SYSDATE, 'DY', 'NLS_DATE_LANGUAGE=ENGLISH') IN ('SAT', 'SUN') THEN
            'WEEKEND_BOOT'
        ELSE
            'WEEKDAY_BOOT'
    END;
    AUDIT ('INIT', 'package initialized. mode=' || g_last_mode);
END fmt_pkg_extreme;"#;

        let formatted = SqlEditorWidget::format_sql_basic(sql);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let assignment_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("g_last_mode :="))
            .expect("assignment line");
        let case_idx = lines
            .iter()
            .enumerate()
            .skip(assignment_idx + 1)
            .find(|(_, line)| line.trim_start() == "CASE")
            .map(|(idx, _)| idx)
            .expect("CASE line");

        assert!(
            formatted.contains("END calc_mode;\nBEGIN\n    g_last_mode :="),
            "package body initializer BEGIN should not remain indented under declarations, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[case_idx]),
            indent(lines[assignment_idx]).saturating_add(4),
            "initializer CASE should indent one level deeper than the := owner, got:\n{}",
            formatted
        );
        assert!(
            !formatted.contains("END calc_mode;\n\n    BEGIN\n        g_last_mode :="),
            "initializer BEGIN/body should not be shifted one extra level, got:\n{}",
            formatted
        );
    }

    #[test]
    fn package_body_header_detection_ignores_literals_and_comments() {
        let package_header_sql = r#"/* lead */ CREATE OR REPLACE PACKAGE BODY pkg_demo AS
BEGIN
  NULL;
END pkg_demo;"#;
        let package_tokens = SqlEditorWidget::tokenize_sql(package_header_sql);
        assert!(
            SqlEditorWidget::statement_starts_with_package_body_header(&package_tokens),
            "real package body header should be detected from meaningful tokens"
        );

        let literal_sql = "SELECT 'CREATE OR REPLACE PACKAGE BODY pkg_demo' AS txt FROM dual;";
        let literal_tokens = SqlEditorWidget::tokenize_sql(literal_sql);
        assert!(
            !SqlEditorWidget::statement_starts_with_package_body_header(&literal_tokens),
            "package-body phrase inside a string literal must not be treated as a structural header"
        );

        let comment_sql = "-- CREATE OR REPLACE PACKAGE BODY pkg_demo\nSELECT 1 FROM dual;";
        let comment_tokens = SqlEditorWidget::tokenize_sql(comment_sql);
        assert!(
            !SqlEditorWidget::statement_starts_with_package_body_header(&comment_tokens),
            "package-body phrase inside comments must not be treated as a structural header"
        );
    }

    #[test]
    fn apply_keyword_detection_uses_meaningful_tokens_only() {
        let apply_sql = "SELECT * FROM src CROSS APPLY (SELECT 1 AS v FROM dual) d;";
        let apply_tokens = SqlEditorWidget::tokenize_sql(apply_sql);
        assert!(
            SqlEditorWidget::statement_contains_keyword(&apply_tokens, "APPLY"),
            "real APPLY keyword should be detected"
        );

        let literal_sql = "SELECT ' APPLY' AS hint_txt, AVG (sal) AS avg_sal FROM emp;";
        let literal_tokens = SqlEditorWidget::tokenize_sql(literal_sql);
        assert!(
            !SqlEditorWidget::statement_contains_keyword(&literal_tokens, "APPLY"),
            "APPLY inside a string literal must not be treated as a statement keyword"
        );

        let comment_sql = "SELECT AVG (sal) AS avg_sal FROM emp -- APPLY marker";
        let comment_tokens = SqlEditorWidget::tokenize_sql(comment_sql);
        assert!(
            !SqlEditorWidget::statement_contains_keyword(&comment_tokens, "APPLY"),
            "APPLY inside comments must not be treated as a statement keyword"
        );
    }

    #[test]
    fn aggregate_call_spacing_is_not_tightened_by_apply_text_inside_literal() {
        let sql = "SELECT ' APPLY' AS hint_txt, AVG (sal) AS avg_sal FROM emp;";
        let formatted = SqlEditorWidget::format_sql_basic(sql);

        assert!(
            formatted.contains("AVG (sal) AS avg_sal"),
            "literal text containing APPLY should not trigger APPLY-specific aggregate spacing, got:\n{}",
            formatted
        );
        assert!(
            !formatted.contains("AVG(sal) AS avg_sal"),
            "formatter should not remove the call gap due to non-structural APPLY text, got:\n{}",
            formatted
        );
    }

    #[test]
    fn package_procedure_if_then_nested_begin_aligns_under_then() {
        let sql = r#"CREATE PACKAGE a AS
    PROCEDURE b (c IN VARCHAR2) IS
    BEGIN
        IF (1 = 1) THEN
        BEGIN
                SELECT * FROM d;
            END;
        END IF;
    END b;
END a;"#;
        let formatted = SqlEditorWidget::format_sql_basic(sql);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let if_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("IF (1 = 1) THEN"))
            .unwrap_or(0);
        let begin_idx = lines
            .iter()
            .enumerate()
            .find(|(idx, line)| *idx > if_idx && line.trim_start() == "BEGIN")
            .map(|(idx, _)| idx)
            .unwrap_or(0);
        let select_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("SELECT *"))
            .unwrap_or(0);
        let inner_end_idx = lines
            .iter()
            .enumerate()
            .find(|(idx, line)| *idx > select_idx && line.trim_start() == "END;")
            .map(|(idx, _)| idx)
            .unwrap_or(0);
        let end_if_idx = lines
            .iter()
            .position(|line| line.trim_start() == "END IF;")
            .unwrap_or(0);

        assert!(
            indent(lines[begin_idx]) > indent(lines[if_idx]),
            "BEGIN inside IF THEN should indent deeper than IF, got:\n{}",
            formatted
        );
        assert!(
            indent(lines[select_idx]) > indent(lines[begin_idx]),
            "SELECT inside nested BEGIN should indent deeper than BEGIN, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[inner_end_idx]),
            indent(lines[begin_idx]),
            "END; for nested BEGIN should align with BEGIN, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[end_if_idx]),
            indent(lines[if_idx]),
            "END IF should align with IF, got:\n{}",
            formatted
        );
    }

