    #[test]
    fn format_sql_basic_keeps_sum_case_indented_inside_with_plsql_cte() {
        let source = r#"WITH
    FUNCTION fmt_mask (p_txt IN VARCHAR2) RETURN VARCHAR2 IS
    BEGIN
        RETURN REGEXP_REPLACE (NVL (p_txt, 'NULL'), '([[:alnum:]])', '*');
    END fmt_mask,
    PROCEDURE noop (p_msg IN VARCHAR2) IS
    BEGIN
        NULL;
    END noop,
    dept_stat AS (
        SELECT
            f.deptno,
            COUNT (*) AS cnt_emp,
            SUM (
            CASE
                WHEN f.band = 'TOP' THEN 1
                ELSE 0
            END
            ) AS cnt_top,
            LISTAGG (f.ename, ', ') WITHIN GROUP (ORDER BY f.sal DESC, f.empno) AS emp_list
        FROM filtered_emp f
        GROUP BY f.deptno
    )
SELECT
    *
FROM dept_stat;"#;
        let formatted = SqlEditorWidget::format_sql_basic(source);
        let lines: Vec<&str> = formatted.lines().collect();

        let leading_spaces = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let sum_idx = lines
            .iter()
            .position(|line| line.trim_start() == "SUM (")
            .unwrap_or(0);
        let case_idx = lines
            .iter()
            .enumerate()
            .skip(sum_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "CASE")
            .map(|(idx, _)| idx)
            .unwrap_or(0);
        let when_idx = lines
            .iter()
            .enumerate()
            .skip(case_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start().starts_with("WHEN f.band = 'TOP' THEN 1"))
            .map(|(idx, _)| idx)
            .unwrap_or(0);
        let else_idx = lines
            .iter()
            .enumerate()
            .skip(when_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "ELSE 0")
            .map(|(idx, _)| idx)
            .unwrap_or(0);
        let end_idx = lines
            .iter()
            .enumerate()
            .skip(else_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "END")
            .map(|(idx, _)| idx)
            .unwrap_or(0);
        let close_idx = lines
            .iter()
            .enumerate()
            .skip(end_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start().starts_with(") AS cnt_top"))
            .map(|(idx, _)| idx)
            .unwrap_or(0);

        assert!(
            leading_spaces(lines[case_idx]) > leading_spaces(lines[sum_idx]),
            "CASE inside SUM should indent deeper than SUM header, got:\n{}",
            formatted
        );
        assert!(
            leading_spaces(lines[when_idx]) > leading_spaces(lines[case_idx]),
            "WHEN inside aggregate CASE should indent deeper than CASE, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[else_idx]),
            leading_spaces(lines[when_idx]),
            "ELSE inside aggregate CASE should align with WHEN, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[end_idx]),
            leading_spaces(lines[case_idx]),
            "END inside aggregate CASE should align with CASE, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[close_idx]),
            leading_spaces(lines[sum_idx]),
            "closing SUM parenthesis should align with SUM header, got:\n{}",
            formatted
        );
    }

    #[test]
    fn format_sql_basic_does_not_insert_blank_line_after_with_function_terminator_before_cte() {
        let source = r#"WITH
    FUNCTION calc_depth (p_id NUMBER) RETURN NUMBER IS
        v_depth NUMBER;
    BEGIN
            SELECT MAX (LEVEL)
            INTO v_depth
            FROM org_tree
            START WITH parent_id IS NULL
            CONNECT BY PRIOR node_id = parent_id;
    RETURN v_depth;
END calc_depth;

recursive_tree (node_id, parent_id, node_name, DEPTH, PATH) AS (
    SELECT
        node_id,
        parent_id,
        node_name,
        1 AS DEPTH,
        CAST (node_name AS VARCHAR2 (4000)) AS PATH
    FROM org_tree
    WHERE parent_id IS NULL
    UNION ALL
    SELECT
        t.node_id,
        t.parent_id,
        t.node_name,
        rt.DEPTH + 1,
        rt.PATH || ' > ' || t.node_name
    FROM org_tree t
    JOIN recursive_tree rt
        ON t.parent_id = rt.node_id
    WHERE rt.DEPTH < calc_depth (t.node_id)
),
aggregated AS (
    SELECT
        parent_id,
        COUNT (*) AS child_count,
        MAX (DEPTH) AS max_depth,
        LISTAGG (node_name, ', ') WITHIN GROUP (ORDER BY node_name) AS children
    FROM recursive_tree
    WHERE DEPTH > 1
    GROUP BY parent_id
)
SELECT
    rt.*,
    a.child_count,
    a.max_depth,
    a.children
FROM recursive_tree rt
LEFT JOIN aggregated a
    ON rt.node_id = a.parent_id
ORDER BY rt.PATH;"#;

        let formatted = SqlEditorWidget::format_sql_basic(source);

        assert!(
            !formatted.contains("END calc_depth;\n\nrecursive_tree"),
            "WITH FUNCTION terminator should stay attached to the following CTE, got:\n{}",
            formatted
        );
    }

    #[test]
    fn format_sql_basic_keeps_following_cte_siblings_aligned_after_with_function_body() {
        let source = r#"WITH
    FUNCTION calc_depth (p_id NUMBER) RETURN NUMBER IS
        v_depth NUMBER;
    BEGIN
        SELECT MAX (LEVEL)
        INTO v_depth
        FROM org_tree
        START WITH parent_id IS NULL
        CONNECT BY PRIOR node_id = parent_id;
    RETURN v_depth;
END calc_depth;
recursive_tree (node_id, parent_id, node_name, DEPTH, PATH) AS (
    SELECT
        node_id,
        parent_id,
        node_name,
        1 AS DEPTH,
        CAST (node_name AS VARCHAR2 (4000)) AS PATH
    FROM org_tree
    WHERE parent_id IS NULL
    UNION ALL
    SELECT
        t.node_id,
        t.parent_id,
        t.node_name,
        rt.DEPTH + 1,
        rt.PATH || ' > ' || t.node_name
    FROM org_tree t
    JOIN recursive_tree rt
        ON t.parent_id = rt.node_id
    WHERE rt.DEPTH < calc_depth (t.node_id)
),
aggregated AS (
    SELECT
        parent_id,
        COUNT (*) AS child_count,
        MAX (DEPTH) AS max_depth,
        LISTAGG (node_name, ', ') WITHIN GROUP (ORDER BY node_name) AS children
    FROM recursive_tree
    WHERE DEPTH > 1
    GROUP BY parent_id
)
SELECT
    rt.*,
    a.child_count,
    a.max_depth,
    a.children
FROM recursive_tree rt
LEFT JOIN aggregated a
    ON rt.node_id = a.parent_id
ORDER BY rt.PATH;"#;

        let formatted = SqlEditorWidget::format_sql_basic(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let recursive_cte_idx = find_line_starting_with(
            &lines,
            "recursive_tree (node_id, parent_id, node_name, DEPTH, PATH) AS (",
        )
        .expect("recursive CTE line");
        let aggregated_cte_idx =
            find_line_starting_with(&lines, "aggregated AS (").expect("aggregated CTE line");
        let aggregated_select_idx = lines
            .iter()
            .enumerate()
            .skip(aggregated_cte_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "SELECT")
            .map(|(idx, _)| idx)
            .expect("aggregated SELECT line");

        assert_eq!(
            leading_spaces(lines[aggregated_cte_idx]),
            leading_spaces(lines[recursive_cte_idx]),
            "sibling CTE after WITH FUNCTION body should realign with the same WITH owner depth, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[aggregated_select_idx]),
            leading_spaces(lines[aggregated_cte_idx]).saturating_add(4),
            "aggregated CTE body SELECT should stay exactly one level deeper than its CTE header, got:\n{}",
            formatted
        );
    }

