    #[test]
    fn format_for_auto_formatting_keeps_outer_match_recognize_subclauses_after_nested_match_recognize(
    ) {
        let source = "select * from sales match_recognize (partition by cust_id order by sale_date measures (select count(*) from (select * from sales match_recognize (partition by cust_id order by sale_date measures match_number() as inner_no one row per match pattern (a) define a as amount > 0)) nested_rows) as inner_cnt all rows per match pattern (a b+) define a as amount < 50, b as amount >= 50);";
        let formatted = SqlEditorWidget::format_for_auto_formatting(source, false);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let outer_all_idx = lines
            .iter()
            .rposition(|line| line.trim_start().starts_with("ALL ROWS PER MATCH"))
            .expect("outer ALL ROWS PER MATCH line");
        let outer_pattern_idx = lines
            .iter()
            .rposition(|line| line.trim_start().starts_with("PATTERN ("))
            .expect("outer PATTERN line");
        let outer_define_idx = lines
            .iter()
            .rposition(|line| line.trim_start().starts_with("DEFINE "))
            .expect("outer DEFINE line");
        let inner_one_row_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("ONE ROW PER MATCH"))
            .expect("inner ONE ROW PER MATCH line");

        assert_eq!(
            indent(lines[outer_pattern_idx]),
            indent(lines[outer_all_idx]),
            "outer PATTERN should realign to the outer MATCH_RECOGNIZE owner depth after nested MATCH_RECOGNIZE closes, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[outer_define_idx]),
            indent(lines[outer_all_idx]),
            "outer DEFINE should realign to the outer MATCH_RECOGNIZE owner depth after nested MATCH_RECOGNIZE closes, got:\n{}",
            formatted
        );
        assert!(
            indent(lines[inner_one_row_idx]) > indent(lines[outer_all_idx]),
            "nested MATCH_RECOGNIZE subclauses should stay deeper than the outer MATCH_RECOGNIZE subclauses, got:\n{}",
            formatted
        );
        assert_eq!(
            SqlEditorWidget::format_for_auto_formatting(&formatted, false),
            formatted,
            "nested MATCH_RECOGNIZE auto-formatting should remain stable"
        );
    }

    #[test]
    fn format_for_auto_formatting_keeps_cte_close_depth_after_pivot_and_unpivot_blocks() {
        let source = r#"WITH src AS (
    SELECT
        10 AS dept_id,
        'ALICE' AS emp_name,
        'Q1' AS qtr,
        100 AS amt
    FROM DUAL
    UNION ALL
        SELECT
            10,
            'ALICE',
            'Q2',
            120
        FROM DUAL
        UNION ALL
        SELECT
            10,
            'BOB',
            'Q1',
            90
        FROM DUAL
        UNION ALL
        SELECT
            10,
            'BOB',
            'Q2',
            150
        FROM DUAL
        UNION ALL
        SELECT
            20,
            'DAVE',
            'Q1',
            80
        FROM DUAL
        UNION ALL
        SELECT
            20,
            'DAVE',
            'Q2',
            110
        FROM DUAL
        UNION ALL
        SELECT
            20,
            'ERIN',
            'Q1',
            140
        FROM DUAL
        UNION ALL
        SELECT
            20,
            'ERIN',
            'Q2',
            130
        FROM DUAL
),
p AS (
    SELECT *
    FROM src PIVOT (
        SUM (amt)
        FOR qtr IN ('Q1' AS q1, 'Q2' AS q2)
    )
        ),
u AS (
            SELECT *
            FROM p UNPIVOT (
                amt
                FOR qtr IN (q1 AS 'Q1', q2 AS 'Q2')
            )
                )
SELECT
    u.dept_id,
    u.emp_name,
    MAX (
        CASE
            WHEN u.qtr = 'Q1' THEN u.amt
        END
                ) AS q1_amt,
                MAX (
                    CASE
                        WHEN u.qtr = 'Q2' THEN u.amt
                    END
                ) AS q2_amt,
                CASE
                    WHEN MAX (
                        CASE
                            WHEN u.qtr = 'Q2' THEN u.amt
                        END
                    ) > MAX (
                        CASE
                            WHEN u.qtr = 'Q1' THEN u.amt
                        END
                    ) THEN 'UP'
                    WHEN MAX (
                        CASE
                            WHEN u.qtr = 'Q2' THEN u.amt
                        END
                    ) < MAX (
                        CASE
                            WHEN u.qtr = 'Q1' THEN u.amt
                        END
                    ) THEN 'DOWN'
                    ELSE 'SAME'
                END AS trend_flag
FROM u
GROUP BY u.dept_id,
    u.emp_name
ORDER BY u.dept_id,
    u.emp_name;"#;

        let formatted = SqlEditorWidget::format_for_auto_formatting(source, false);
        let expected = r#"WITH src AS (
    SELECT
        10 AS dept_id,
        'ALICE' AS emp_name,
        'Q1' AS qtr,
        100 AS amt
    FROM DUAL
    UNION ALL
    SELECT
        10,
        'ALICE',
        'Q2',
        120
    FROM DUAL
    UNION ALL
    SELECT
        10,
        'BOB',
        'Q1',
        90
    FROM DUAL
    UNION ALL
    SELECT
        10,
        'BOB',
        'Q2',
        150
    FROM DUAL
    UNION ALL
    SELECT
        20,
        'DAVE',
        'Q1',
        80
    FROM DUAL
    UNION ALL
    SELECT
        20,
        'DAVE',
        'Q2',
        110
    FROM DUAL
    UNION ALL
    SELECT
        20,
        'ERIN',
        'Q1',
        140
    FROM DUAL
    UNION ALL
    SELECT
        20,
        'ERIN',
        'Q2',
        130
    FROM DUAL
),
p AS (
    SELECT *
    FROM src
    PIVOT (
        SUM (amt)
        FOR qtr IN ('Q1' AS q1, 'Q2' AS q2)
    )
),
u AS (
    SELECT *
    FROM p
    UNPIVOT (
        amt
        FOR qtr IN (q1 AS 'Q1', q2 AS 'Q2')
    )
)
SELECT
    u.dept_id,
    u.emp_name,
    MAX (
        CASE
            WHEN u.qtr = 'Q1' THEN u.amt
        END
    ) AS q1_amt,
    MAX (
        CASE
            WHEN u.qtr = 'Q2' THEN u.amt
        END
    ) AS q2_amt,
    CASE
        WHEN MAX (
                CASE
                    WHEN u.qtr = 'Q2' THEN u.amt
                END
            ) > MAX (
                CASE
                    WHEN u.qtr = 'Q1' THEN u.amt
                END
            ) THEN 'UP'
        WHEN MAX (
                CASE
                    WHEN u.qtr = 'Q2' THEN u.amt
                END
            ) < MAX (
                CASE
                    WHEN u.qtr = 'Q1' THEN u.amt
                END
            ) THEN 'DOWN'
        ELSE 'SAME'
    END AS trend_flag
FROM u
GROUP BY u.dept_id,
    u.emp_name
ORDER BY u.dept_id,
    u.emp_name;"#;

        assert_eq!(
            formatted, expected,
            "CTE close parens after PIVOT/UNPIVOT blocks should return to the CTE owner depth instead of inheriting inner block depth"
        );
        assert_eq!(
            SqlEditorWidget::format_for_auto_formatting(expected, false),
            expected,
            "Auto formatting should stay stable for CTE close-paren depth after PIVOT/UNPIVOT blocks"
        );
    }

