    #[test]
    fn format_sql_analytic_and_window_exclude_breaks_to_owner_relative_lines() {
        let analytic_source =
            "SELECT SUM(sal) OVER (PARTITION BY deptno EXCLUDE CURRENT ROW) AS running_sal FROM emp;";
        let analytic_formatted = SqlEditorWidget::format_sql_basic(analytic_source);
        assert!(
            analytic_formatted.contains(
                "OVER (\n    PARTITION BY deptno\n    EXCLUDE CURRENT ROW\n) AS running_sal"
            ),
            "EXCLUDE inside OVER should break onto the shared owner-relative depth, got:\n{}",
            analytic_formatted
        );

        let window_source = "SELECT SUM(e.sal) OVER w_dept AS dept_sum FROM emp e WINDOW w_dept AS (PARTITION BY e.deptno EXCLUDE CURRENT ROW) QUALIFY ROW_NUMBER() OVER w_dept = 1;";
        let window_formatted = SqlEditorWidget::format_sql_basic(window_source);
        let lines: Vec<&str> = window_formatted.lines().collect();
        let window_idx = find_line_starting_with(&lines, "WINDOW").expect("WINDOW clause line");
        let named_idx = find_line_starting_with(&lines, "w_dept AS (").expect("named WINDOW line");
        let partition_idx =
            find_line_starting_with(&lines, "PARTITION BY e.deptno").expect("WINDOW PARTITION BY");
        let exclude_idx = find_line_starting_with(&lines, "EXCLUDE CURRENT ROW")
            .expect("WINDOW EXCLUDE clause line");

        assert_eq!(
            leading_spaces(lines[exclude_idx]),
            leading_spaces(lines[partition_idx]),
            "WINDOW EXCLUDE should share the WINDOW body depth after line breaking, got:\n{}",
            window_formatted
        );
        assert_eq!(
            leading_spaces(lines[named_idx]),
            leading_spaces(lines[window_idx]).saturating_add(4),
            "named WINDOW definition should stay one clause-body level deeper than bare WINDOW, got:\n{}",
            window_formatted
        );
        assert!(
            leading_spaces(lines[exclude_idx]) > leading_spaces(lines[named_idx]),
            "WINDOW EXCLUDE should stay indented under WINDOW, got:\n{}",
            window_formatted
        );
        assert_eq!(
            SqlEditorWidget::format_sql_basic(&window_formatted),
            window_formatted,
            "WINDOW EXCLUDE formatting should be idempotent"
        );
    }

    #[test]
    fn format_sql_analytic_over_restores_outer_window_depth_after_nested_over() {
        let source = "SELECT SUM(sal) OVER (PARTITION BY deptno ORDER BY (SELECT MAX(inner_val) OVER (PARTITION BY grp ORDER BY inner_val) FROM dual) ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS running_sal FROM emp;";
        let formatted = SqlEditorWidget::format_sql_basic(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let outer_partition_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("PARTITION BY deptno"))
            .expect("outer PARTITION BY line");
        let inner_partition_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("PARTITION BY grp"))
            .expect("inner PARTITION BY line");
        let outer_rows_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("ROWS BETWEEN"))
            .expect("outer ROWS BETWEEN line");

        assert_eq!(
            indent(lines[outer_rows_idx]),
            indent(lines[outer_partition_idx]),
            "Outer ROWS BETWEEN should stay aligned with the outer OVER subclauses after nested OVER closes, got:\n{}",
            formatted
        );
        assert!(
            indent(lines[inner_partition_idx]) > indent(lines[outer_partition_idx]),
            "Nested OVER subclauses should stay deeper than the outer OVER subclauses, got:\n{}",
            formatted
        );
    }

    #[test]
    fn format_sql_window_clause_and_qualify_keep_clause_depths_stable() {
        let source = "SELECT e.deptno, e.empno, SUM(e.sal) OVER w_dept AS dept_sum FROM emp e WINDOW w_dept AS (PARTITION BY e.deptno ORDER BY e.sal DESC, e.empno) QUALIFY ROW_NUMBER() OVER w_dept = 1;";
        let formatted = SqlEditorWidget::format_sql_basic(source);
        let lines: Vec<&str> = formatted.lines().collect();

        let window_idx = find_line_starting_with(&lines, "WINDOW").expect("WINDOW clause line");
        let named_idx = find_line_starting_with(&lines, "w_dept AS (").expect("named WINDOW line");
        let partition_idx =
            find_line_starting_with(&lines, "PARTITION BY e.deptno").expect("WINDOW PARTITION BY");
        let order_idx =
            find_line_starting_with(&lines, "ORDER BY e.sal DESC").expect("WINDOW ORDER BY");
        let qualify_idx =
            find_line_starting_with(&lines, "QUALIFY ROW_NUMBER").expect("QUALIFY clause line");
        let close_idx = lines
            .iter()
            .enumerate()
            .skip(order_idx.saturating_add(1))
            .find(|(idx, line)| *idx < qualify_idx && line.trim() == ")")
            .map(|(idx, _)| idx)
            .expect("WINDOW closing parenthesis");

        assert!(
            formatted.contains("\nWINDOW\n    w_dept AS ("),
            "WINDOW clause should start on its own clause line, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[named_idx]),
            leading_spaces(lines[window_idx]).saturating_add(4),
            "named WINDOW definition should stay one level deeper than bare WINDOW, got:\n{}",
            formatted
        );
        assert!(
            leading_spaces(lines[partition_idx]) > leading_spaces(lines[named_idx]),
            "WINDOW PARTITION BY should be indented under WINDOW, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[partition_idx]),
            leading_spaces(lines[order_idx]),
            "WINDOW PARTITION BY / ORDER BY should share the same continuation depth, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[close_idx]),
            leading_spaces(lines[named_idx]),
            "WINDOW closing parenthesis should realign with the named WINDOW definition, got:\n{}",
            formatted
        );
        assert_eq!(
            leading_spaces(lines[qualify_idx]),
            leading_spaces(lines[window_idx]),
            "QUALIFY should align with top-level clause anchors, got:\n{}",
            formatted
        );

        let formatted_again = SqlEditorWidget::format_sql_basic(&formatted);
        assert_eq!(
            formatted, formatted_again,
            "WINDOW / QUALIFY formatting should be idempotent"
        );
    }

    #[test]
    fn format_sql_window_clause_indents_named_window_siblings_under_bare_window_header() {
        let source = "SELECT ob.*, ROW_NUMBER() OVER w_emp AS rn_in_emp, DENSE_RANK() OVER w_global AS global_rank, SUM(ob.total_usd) OVER w_emp_running AS running_emp_total FROM order_base AS ob WINDOW w_emp AS (PARTITION BY ob.emp_id ORDER BY ob.created_at, ob.order_id), w_emp_running AS (PARTITION BY ob.emp_id ORDER BY ob.created_at, ob.order_id ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW), w_global AS (ORDER BY ob.total_usd DESC);";
        let formatted = SqlEditorWidget::format_sql_basic(source);
        let window_fragment = r#"WINDOW
    w_emp AS (
        PARTITION BY ob.emp_id
        ORDER BY ob.created_at,
        ob.order_id
    ),
    w_emp_running AS (
        PARTITION BY ob.emp_id
        ORDER BY ob.created_at,
        ob.order_id
        ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
    ),
    w_global AS (
        ORDER BY ob.total_usd DESC
    );"#;

        assert!(
            formatted.contains(window_fragment),
            "named WINDOW siblings should format as clause-body items under a bare WINDOW header, got:\n{}",
            formatted
        );
        assert_eq!(SqlEditorWidget::format_sql_basic(&formatted), formatted);
    }

    #[test]
    fn format_sql_nested_window_clause_restores_outer_query_depth() {
        let source = "SELECT * FROM (SELECT e.deptno, SUM(e.sal) OVER w_dept AS dept_sum FROM emp e WINDOW w_dept AS (PARTITION BY e.deptno ORDER BY e.sal DESC, e.empno) QUALIFY ROW_NUMBER() OVER w_dept = 1) ranked WHERE ranked.dept_sum > 0;";
        let formatted = SqlEditorWidget::format_sql_basic(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let from_paren_idx =
            find_line_starting_with(&lines, "FROM (").expect("nested query owner line");
        let inner_select_idx =
            find_line_starting_with(&lines, "SELECT e.deptno").expect("nested SELECT line");
        let window_idx = find_line_starting_with(&lines, "WINDOW").expect("nested WINDOW line");
        let named_idx =
            find_line_starting_with(&lines, "w_dept AS (").expect("nested named WINDOW line");
        let partition_idx =
            find_line_starting_with(&lines, "PARTITION BY e.deptno").expect("nested PARTITION BY");
        let order_idx =
            find_line_starting_with(&lines, "ORDER BY e.sal DESC").expect("nested ORDER BY");
        let qualify_idx =
            find_line_starting_with(&lines, "QUALIFY ROW_NUMBER").expect("nested QUALIFY line");
        let close_idx = lines
            .iter()
            .enumerate()
            .find(|(_, line)| line.trim_start() == ") ranked")
            .map(|(idx, _)| idx)
            .expect("nested query closing line");
        let outer_where_idx = lines
            .iter()
            .rposition(|line| line.trim_start().starts_with("WHERE ranked.dept_sum"))
            .expect("outer WHERE line");

        assert!(
            indent(lines[inner_select_idx]) > indent(lines[from_paren_idx]),
            "nested SELECT should stay deeper than the FROM ( owner, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[window_idx]),
            indent(lines[inner_select_idx]),
            "nested WINDOW should stay aligned with the nested query clause depth, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[named_idx]),
            indent(lines[window_idx]).saturating_add(4),
            "nested named WINDOW definition should stay one level deeper than bare WINDOW, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[partition_idx]),
            indent(lines[named_idx]).saturating_add(4),
            "nested WINDOW body should be one indentation level deeper than its named owner, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[partition_idx]),
            indent(lines[order_idx]),
            "nested WINDOW PARTITION BY / ORDER BY should share the same continuation depth, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[qualify_idx]),
            indent(lines[window_idx]),
            "nested QUALIFY should realign with the nested WINDOW owner depth after the body closes, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[close_idx]),
            indent(lines[inner_select_idx]).saturating_sub(4),
            "nested query closing line should step out of the inner query body by one level, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[outer_where_idx]),
            0,
            "outer WHERE should return to the outer query base after the nested WINDOW query closes, got:\n{}",
            formatted
        );
        assert_eq!(
            SqlEditorWidget::format_sql_basic(&formatted),
            formatted,
            "nested WINDOW formatting should remain idempotent"
        );
    }

