    #[test]
    fn comment_header_continuation_kind_reuses_exact_bare_structural_taxonomy_and_skips_named_owners(
    ) {
        let continuation_kind =
            |line: &str| -> Option<crate::sql_text::FormatInlineCommentHeaderContinuationKind> {
                let tokens = SqlEditorWidget::tokenize_sql(line);
                let comment_idx = tokens
                    .iter()
                    .position(|token| matches!(token, SqlToken::Comment(_)))
                    .unwrap_or(0);
                SqlEditorWidget::comment_header_continuation_kind(&tokens, comment_idx)
            };

        for line in [
            "WITHIN GROUP -- analytic owner",
            "KEEP -- analytic owner",
            "MATCH_RECOGNIZE -- row pattern",
            "PIVOT -- rotated rows",
            "UNPIVOT -- rotated rows",
            "FROM TABLE -- collection rows",
            "USING TABLE -- collection rows",
            "JOIN TABLE -- collection rows",
            "LEFT JOIN TABLE -- collection rows",
            "LEFT OUTER JOIN TABLE -- collection rows",
            "RIGHT JOIN TABLE -- collection rows",
            "RIGHT OUTER JOIN TABLE -- collection rows",
            "FULL JOIN TABLE -- collection rows",
            "FULL OUTER JOIN TABLE -- collection rows",
            "INNER JOIN TABLE -- collection rows",
            "CROSS JOIN TABLE -- collection rows",
            "NATURAL JOIN TABLE -- collection rows",
            "NATURAL LEFT JOIN TABLE -- collection rows",
            "NATURAL LEFT OUTER JOIN TABLE -- collection rows",
            "NATURAL RIGHT JOIN TABLE -- collection rows",
            "NATURAL RIGHT OUTER JOIN TABLE -- collection rows",
            "NATURAL FULL JOIN TABLE -- collection rows",
            "NATURAL FULL OUTER JOIN TABLE -- collection rows",
        ] {
            assert_eq!(
                continuation_kind(line),
                Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth),
                "expected `{line}` to reuse exact bare owner/header continuation depth"
            );
        }

        assert_eq!(
            continuation_kind("JOIN -- joined rows"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanCurrentLine)
        );
        assert_eq!(
            continuation_kind("CALL -- invoke routine"),
            Some(
                crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanCurrentLine
            )
        );
        assert_eq!(
            continuation_kind("INNER JOIN -- joined rows"),
            Some(
                crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanQueryBase
            )
        );
        assert_eq!(
            continuation_kind("NATURAL LEFT JOIN -- joined rows"),
            Some(
                crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanQueryBase
            )
        );
        assert_eq!(
            continuation_kind("REFERENCE -- model ref"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("WINDOW -- named window"),
            Some(
                crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanCurrentLine
            )
        );
        assert_eq!(
            continuation_kind("MATCH_RECOGNIZE -- row pattern"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("PIVOT -- rotated rows"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("UNPIVOT -- rotated rows"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("FROM TABLE -- collection rows"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("LEFT JOIN TABLE -- collection rows"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("EXISTS -- deferred wrapper"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("NOT EXISTS -- deferred wrapper"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("IN -- deferred wrapper"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("NOT IN -- deferred wrapper"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("ANY -- deferred wrapper"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("SOME -- deferred wrapper"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
        assert_eq!(
            continuation_kind("ALL -- deferred wrapper"),
            Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth)
        );
    }

    #[test]
    fn comment_header_continuation_kind_keeps_rhs_operator_precedence_for_non_owner_lines() {
        let continuation_kind =
            |line: &str| -> Option<crate::sql_text::FormatInlineCommentHeaderContinuationKind> {
                let tokens = SqlEditorWidget::tokenize_sql(line);
                let comment_idx = tokens
                    .iter()
                    .position(|token| matches!(token, SqlToken::Comment(_)))
                    .unwrap_or(0);
                SqlEditorWidget::comment_header_continuation_kind(&tokens, comment_idx)
            };

        for line in [
            "AND e.member_col MEMBER OF -- type filter",
            "AND e.num_nt SUBMULTISET OF -- subset filter",
            "AND e.ename LIKE4 -- pattern",
            "AND e.ename LIKE 'A%' ESCAPE -- esc",
            "v_total := -- assign",
            "pkg_lock.request => -- named arg",
        ] {
            assert_eq!(
                continuation_kind(line),
                Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanCurrentLine),
                "expected `{line}` to keep RHS operator continuation depth"
            );
        }
    }

    #[test]
    fn resolve_comment_header_continuation_indent_reuses_shared_anchor_resolver() {
        assert_eq!(
            SqlEditorWidget::resolve_comment_header_continuation_indent(
                Some(crate::sql_text::FormatInlineCommentHeaderContinuationKind::SameDepth),
                5,
                2,
                5,
                9,
            ),
            5
        );
        assert_eq!(
            SqlEditorWidget::resolve_comment_header_continuation_indent(
                Some(
                    crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanQueryBase,
                ),
                5,
                2,
                5,
                9,
            ),
            3
        );
        assert_eq!(
            SqlEditorWidget::resolve_comment_header_continuation_indent(
                Some(
                    crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanCurrentLine,
                ),
                5,
                2,
                5,
                9,
            ),
            6
        );
        assert_eq!(
            SqlEditorWidget::resolve_comment_header_continuation_indent(None, 5, 2, 5, 9),
            9
        );
    }

    #[test]
    fn comment_header_continuation_kind_prioritizes_structural_header_family_over_trailing_operator_for_header_lines(
    ) {
        let continuation_kind =
            |line: &str| -> Option<crate::sql_text::FormatInlineCommentHeaderContinuationKind> {
                let tokens = SqlEditorWidget::tokenize_sql(line);
                let comment_idx = tokens
                    .iter()
                    .position(|token| matches!(token, SqlToken::Comment(_)))
                    .unwrap_or(0);
                SqlEditorWidget::comment_header_continuation_kind(&tokens, comment_idx)
            };

        for (line, expected) in [
            (
                "WHERE e.emp_id = -- keep",
                Some(
                    crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanQueryBase,
                ),
            ),
            (
                "WHERE e.member_col MEMBER OF -- keep",
                Some(
                    crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanQueryBase,
                ),
            ),
            (
                "ON e.emp_id = -- keep",
                Some(
                    crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanQueryBase,
                ),
            ),
            (
                "AND e.status_cd = -- keep",
                Some(
                    crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanCurrentLine,
                ),
            ),
            (
                "v_total := -- keep",
                Some(
                    crate::sql_text::FormatInlineCommentHeaderContinuationKind::OneDeeperThanCurrentLine,
                ),
            ),
        ] {
            assert_eq!(
                continuation_kind(line),
                expected,
                "expected `{line}` to prefer structural header carry before pure RHS fallback",
            );
        }
    }

    #[test]
    fn format_sql_basic_keeps_inline_comment_split_not_exists_owner_depth_across_standalone_open_paren(
    ) {
        let source = r#"SELECT d.deptno
FROM dept d
WHERE
NOT EXISTS -- owner
(
    SELECT 1
    FROM emp e
    WHERE e.deptno = d.deptno
)
AND d.active = 'Y';"#;
        let formatted = SqlEditorWidget::format_sql_basic(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let owner_idx = lines
            .iter()
            .position(|line| line.trim_start() == "NOT EXISTS -- owner")
            .unwrap_or(0);
        let open_idx = lines
            .iter()
            .position(|line| line.trim() == "(")
            .unwrap_or(0);
        let select_idx = lines
            .iter()
            .position(|line| line.trim_start() == "SELECT 1")
            .unwrap_or(0);
        let close_idx = lines
            .iter()
            .position(|line| line.trim() == ")")
            .unwrap_or(0);

        assert_eq!(
            indent(lines[open_idx]),
            indent(lines[owner_idx]),
            "standalone open paren after inline-comment split NOT EXISTS should stay on owner depth, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[select_idx]),
            indent(lines[owner_idx]).saturating_add(4),
            "child SELECT under inline-comment split NOT EXISTS should stay one level deeper than owner, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[close_idx]),
            indent(lines[owner_idx]),
            "inline-comment split NOT EXISTS closing paren should realign with owner depth, got:\n{}",
            formatted
        );
    }

