    #[test]
    fn line_starts_structural_operator_rhs_uses_shared_owner_boundary_taxonomy() {
        assert!(SqlEditorWidget::line_starts_structural_operator_rhs(
            "CURSOR c_emp",
            None,
        ));
        assert!(SqlEditorWidget::line_starts_structural_operator_rhs(
            "WINDOW w_dept AS",
            None,
        ));
        assert!(SqlEditorWidget::line_starts_structural_operator_rhs(
            "SEARCH DEPTH FIRST BY deptno SET ord",
            None,
        ));
        assert!(SqlEditorWidget::line_starts_structural_operator_rhs(
            "(",
            Some("SELECT empno"),
        ));
        assert!(!SqlEditorWidget::line_starts_structural_operator_rhs(
            "MULTISET",
            Some("SELECT bonus"),
        ));
    }

