    #[test]
    fn format_sql_basic_for_mysql_db_type_keeps_on_duplicate_multiline_call_siblings_on_parent_frame_depth(
    ) {
        let source = r#"INSERT INTO dept (dept_id, parent_dept_id, dept_code, dept_name, sort_no)
VALUES (20, 10, 'SALES', 'Sales-upsert-check', 2)
ON DUPLICATE KEY UPDATE dept_name = CONCAT(
VALUES(dept_name),
' / touched'
),
sort_no = VALUES(sort_no);"#;

        let formatted = SqlEditorWidget::format_sql_basic_for_db_type(
            source,
            crate::db::connection::DatabaseType::MySQL,
        );
        let lines: Vec<&str> = formatted.lines().collect();
        let on_duplicate_idx =
            find_line_starting_with(&lines, "ON DUPLICATE KEY UPDATE dept_name = CONCAT(")
                .expect("ON DUPLICATE KEY UPDATE owner");
        let values_idx =
            find_line_starting_with(&lines, "VALUES(dept_name),").expect("VALUES() sibling");
        let literal_idx = find_line_starting_with(&lines, "' / touched'").expect("literal sibling");
        let close_idx = lines
            .iter()
            .enumerate()
            .skip(literal_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "),")
            .map(|(idx, _)| idx)
            .expect("CONCAT close");

        assert!(
            leading_spaces(lines[values_idx]) > leading_spaces(lines[on_duplicate_idx]),
            "VALUES() argument should stay nested under the ON DUPLICATE call owner, got:\n{formatted}"
        );
        assert_eq!(
            leading_spaces(lines[literal_idx]),
            leading_spaces(lines[values_idx]),
            "wrapped call siblings inside ON DUPLICATE KEY UPDATE should reuse the parent frame body depth, got:\n{formatted}"
        );
        assert_eq!(
            leading_spaces(lines[close_idx]),
            leading_spaces(lines[on_duplicate_idx]),
            "wrapped call close should realign with the ON DUPLICATE owner depth, got:\n{formatted}"
        );
        assert_eq!(
            SqlEditorWidget::format_sql_basic_for_db_type(
                &formatted,
                crate::db::connection::DatabaseType::MySQL,
            ),
            formatted
        );
    }

    #[test]
    fn format_sql_basic_for_mysql_db_type_reapplies_frame_depth_after_nested_subquery_close_comma()
    {
        let source = r#"SELECT ROUND(
(
SELECT AVG (s2.score)
FROM emp_score s2
WHERE s2.empno = s.empno
),
2
),
s.ename
FROM emp_score s;"#;

        let formatted = SqlEditorWidget::format_sql_basic_for_db_type(
            source,
            crate::db::connection::DatabaseType::MySQL,
        );
        let lines: Vec<&str> = formatted.lines().collect();
        let round_idx = find_line_starting_with(&lines, "SELECT ROUND(").expect("ROUND owner");
        let mixed_close_precision_idx =
            find_line_starting_with(&lines, "), 2").expect("mixed close + precision");
        let outer_close_idx = lines
            .iter()
            .enumerate()
            .skip(mixed_close_precision_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "),")
            .map(|(idx, _)| idx)
            .expect("ROUND close-comma");
        let sibling_idx = find_line_starting_with(&lines, "s.ename").expect("SELECT sibling");
        let from_idx = find_line_starting_with(&lines, "FROM emp_score s;").expect("FROM line");

        assert_eq!(
            leading_spaces(lines[outer_close_idx]),
            leading_spaces(lines[round_idx]),
            "ROUND close-comma should return to the owner depth, got:\n{formatted}"
        );
        assert_eq!(
            leading_spaces(lines[sibling_idx]),
            leading_spaces(lines[round_idx]).saturating_add(4),
            "SELECT sibling after a nested close-comma must realign to the SELECT list frame depth instead of the previous line shape, got:\n{formatted}"
        );
        assert!(
            leading_spaces(lines[from_idx]) < leading_spaces(lines[sibling_idx]),
            "FROM should clear the carried SELECT list depth after the nested ROUND item closes, got:\n{formatted}"
        );
        assert_eq!(
            SqlEditorWidget::format_sql_basic_for_db_type(
                &formatted,
                crate::db::connection::DatabaseType::MySQL,
            ),
            formatted,
            "MySQL nested close-comma realignment should stay idempotent once frame-based depth wins"
        );
    }

    #[test]
    fn mysql_formatter_keeps_sibling_depth_after_nested_close_comma() {
        let source = r#"SELECT ROUND(
(
SELECT AVG (s2.score)
FROM emp_score s2
WHERE s2.empno = s.empno
),
2
),
            s.ename
FROM emp_score s;"#;

        let normalized = SqlEditorWidget::format_sql_basic_for_db_type(
            source,
            crate::db::connection::DatabaseType::MySQL,
        );
        let lines: Vec<&str> = normalized.lines().collect();
        let round_idx = find_line_starting_with(&lines, "SELECT ROUND(").expect("ROUND owner");
        let sibling_idx = find_line_starting_with(&lines, "s.ename").expect("SELECT sibling");

        assert_eq!(
            leading_spaces(lines[sibling_idx]),
            leading_spaces(lines[round_idx]).saturating_add(4),
            "MySQL formatter should keep sibling depth after nested close-comma, got:\n{normalized}"
        );
    }

    #[test]
    fn mysql_formatter_keeps_select_list_sibling_depth_after_nested_subquery_close() {
        let source = r#"SELECT JSON_OBJECT(
'avg_score',
(
SELECT AVG (s2.score)
FROM emp_score s2
WHERE s2.empno = s.empno
),
'employee_name',
        s.ename
)
FROM emp_score s;"#;

        let normalized = SqlEditorWidget::format_sql_basic_for_db_type(
            source,
            crate::db::connection::DatabaseType::MySQL,
        );
        let lines: Vec<&str> = normalized.lines().collect();
        let key_idx = find_line_starting_with(&lines, "'employee_name',");
        let value_idx = find_line_starting_with(&lines, "s.ename");

        if let (Some(key_idx), Some(value_idx)) = (key_idx, value_idx) {
            assert_eq!(
                leading_spaces(lines[value_idx]),
                leading_spaces(lines[key_idx]),
                "MySQL formatter should keep select-list sibling depth after nested subquery close, got:\n{normalized}"
            );
        } else {
            assert!(
                normalized.contains("'employee_name', s.ename"),
                "MySQL formatter should keep the select-list sibling pair adjacent even when rendered inline, got:\n{normalized}"
            );
        }
    }

